# ---------- SKU suffix helpers ----------
_GR_SUFFIXES = ("-NEW", "-GRA", "-GRB", "-GRC")
_IC_SUFFIXES = ("-ICB", "-ICC")
_ALL_SUFFIXES = _GR_SUFFIXES + _IC_SUFFIXES


def _extract_base_sku(sku: str) -> str:
    """Devuelve el SKU base sin sufijo de variante."""
    upper = sku.upper()
    for sfx in _ALL_SUFFIXES:
        if upper.endswith(sfx):
            return sku[:-len(sfx)]
    return sku


def _bm_conditions_for_sku(sku: str) -> str:
    """Retorna condiciones BM según formato del SELLER_SKU y categoría.

    Reglas:
    - SNTV* → GRA,GRB,GRC,ICB,ICC,NEW
      (televisiones pueden tener stock en condición In-Carton B/C en cualquier SKU base;
       el "/" de bundles se elimina al normalizar el SKU antes de llamar esta función,
       por lo que no se puede depender del sufijo para detectar si hay ICB/ICC)
    - Todo lo demás → GRA,GRB,GRC,NEW
      (simple, -NEW, -GRA, -GRB, -GRC, -ICB/-ICC fuera de SNTV, otras categorías)
    """
    upper = sku.upper()
    if upper.startswith("SNTV"):
        return "GRA,GRB,GRC,ICB,ICC,NEW"
    return "GRA,GRB,GRC,NEW"


import re as _re


def normalize_to_bm_sku(sku: str) -> str:
    """Proxy a sku_utils.base_sku — fuente canónica en app/services/sku_utils.py."""
    return _normalize_sku_imported(sku)


def _extract_key_attributes(body: dict) -> list:
    """Extract up to 20 key spec attributes from an ML item body for AI context."""
    raw = body.get("attributes", []) or []
    result = []
    _skip = {"SELLER_SKU", "GTIN", "EAN", "ITEM_CONDITION", "ALPHANUMERIC_MODEL", "BRAND"}
    for attr in raw:
        if len(result) >= 20:
            break
        aid = (attr.get("id") or "").upper()
        if aid in _skip:
            continue
        name = attr.get("name") or attr.get("id") or ""
        vs = attr.get("value_struct") or {}
        value = attr.get("value_name") or (str(vs.get("number", "")) if vs.get("number") is not None else "")
        unit = vs.get("unit") or ""
        if name and value:
            result.append({"name": name, "value": f"{value}{(' ' + unit) if unit else ''}"})
    return result


def _clean_sku_for_bm(sku: str) -> str:
    """Limpia SKU de MeLi para consultar BinManager.
    Quita: (N), / segunda_parte, + segunda_parte, espacios extra, etc."""
    if not sku:
        return ""
    # Tomar primera parte antes de " / " o " + " (MeLi concatena SKUs en packs)
    s = _re.split(r'\s*[/+]\s*', sku)[0].strip()
    # Quitar cualquier sufijo entre paréntesis: (2), (cantidad:2), (18), etc.
    s = _re.sub(r'\s*\([^)]*\)', '', s).strip()
    return s


_manual_fx_rate: float = 0.0   # 0 = usar tasa MeLi API; >0 = override manual
_last_fx_rate:   float = 17.0  # última tasa conocida (actualizada en prewarm c/15 min)


async def _get_usd_to_mxn(client) -> float:
    """Obtiene tipo de cambio USD->MXN. Prefiere override manual si está configurado."""
    if _manual_fx_rate > 0:
        return _manual_fx_rate
    try:
        fx_data = await client.get("/currency_conversions/search", params={"from": "USD", "to": "MXN"})
        return fx_data.get("ratio", 20.0)
    except Exception:
        return 20.0


def _ml_fee(price: float) -> float:
    """Tarifa ML escalonada por precio (más precisa que flat 17%)."""
    if price >= 5000:
        return 0.12
    if price >= 1500:
        return 0.14
    if price >= 500:
        return 0.16
    return 0.18


def _calc_margins(products: list, usd_to_mxn: float, deal_buffer_pct: float = 0.15, retail_target_pct: float = 1.0):
    """Calcula costos, márgenes y comparativas vs RetailPrice PH para cada producto."""
    for p in products:
        avg_cost = p.get("_bm_avg_cost", 0) or 0
        retail = p.get("_bm_retail_price", 0) or 0
        retail_ph = p.get("_bm_retail_ph", 0) or 0

        # Flag: BM tiene registro aunque costos sean sentinel (0 o 9999)
        p["_bm_has_data"] = bool(p.get("_bm_brand") or avg_cost > 0 or retail > 0)

        # Costo efectivo: AvgCost tiene prioridad; RetailPrice de BM = precio de adquisición (fallback)
        _eff_cost = avg_cost if (0 < avg_cost < 9999) else retail
        p["_bm_eff_cost_usd"] = round(_eff_cost, 2) if (0 < _eff_cost < 9999) else 0
        p["_cost_source"] = "avg" if (0 < avg_cost < 9999) else ("retail" if (0 < retail < 9999) else None)

        # Conversiones USD → MXN
        p["_costo_mxn"] = round(_eff_cost * usd_to_mxn, 2) if (0 < _eff_cost < 9999) else 0
        p["_retail_mxn"] = round(retail * usd_to_mxn, 2) if (0 < retail < 9999) else 0
        p["_retail_ph_mxn"] = round(retail_ph * usd_to_mxn, 2) if (0 < retail_ph < 9999) else 0

        price = p.get("price", 0)

        # ── Ganancia/margen vs precio de venta actual ──────────────────────
        if price > 0 and p["_costo_mxn"] > 0:
            comision = price * _ml_fee(price)
            iva_comision = comision * 0.16
            envio = 150
            ganancia = price - p["_costo_mxn"] - comision - iva_comision - envio
            p["_ganancia_est"] = round(ganancia, 2)
            p["_margen_pct"] = round((ganancia / price) * 100, 1)
        else:
            p["_ganancia_est"] = None
            p["_margen_pct"] = None

        # ── Neto ML y % Recuperación Retail ─────────────────────────────────
        # Precio real de venta: promo_deal_price → price → original_price (fallback catalogo)
        _sale_price = p.get("_promo_deal_price") or price or p.get("original_price") or 0
        _retail_mxn = p["_retail_mxn"]
        if _sale_price > 0:
            _item_id = p.get("id", "")
            _hist_ratio = _item_net_ratio_map.get(_item_id)
            if _hist_ratio:
                # Ratio real de ventas históricas: ya incluye fee ML + retenciones + 7% socio
                _neto = _sale_price * _hist_ratio
            else:
                # Fee real por tramo + retenciones fiscales ML Mexico ~9.05% (IVA 6.9% + ISR 2.15%)
                # Envío estimado: producto mayor retail = más grande/pesado
                _fee_pct = _ml_fee(_sale_price)
                if _retail_mxn >= 5000:
                    _ship_est = 400
                elif _retail_mxn >= 2500:
                    _ship_est = 250
                elif _retail_mxn >= 1000:
                    _ship_est = 150
                else:
                    _ship_est = 100
                _net_ml = _sale_price * (1 - _fee_pct - 0.0905) - _ship_est
                _neto = _net_ml * (1 - _PARTNER_COMMISSION_PCT)
            p["_neto_ml"] = round(_neto, 2)
            p["_recup_retail_pct"] = round((_neto / _retail_mxn) * 100, 1) if _retail_mxn > 0 else None
        else:
            p["_neto_ml"] = None
            p["_recup_retail_pct"] = None

        # ── Aportación MeLi (PRE_NEGOTIATED) — ML subsidia parte del descuento ──
        _meli_pct = p.get("_meli_promo_pct", 0) or 0
        _orig_p = p.get("original_price", 0) or 0
        p["_meli_contribution_mxn"] = round(_orig_p * _meli_pct / 100, 2) if (_meli_pct > 0 and _orig_p > 0) else 0
        # Ganancia real = ganancia_est + lo que ML aporta (gratis para el vendedor)
        if p["_ganancia_est"] is not None:
            p["_ganancia_real"] = round(p["_ganancia_est"] + p["_meli_contribution_mxn"], 2)
            _eff_price = price + p["_meli_contribution_mxn"]
            p["_margen_real_pct"] = round((p["_ganancia_real"] / _eff_price) * 100, 1) if _eff_price > 0 else None
        else:
            p["_ganancia_real"] = None
            p["_margen_real_pct"] = None

        # ── Comparativa vs RetailPrice PH ──────────────────────────────────
        rph = p["_retail_ph_mxn"]
        if rph > 0:
            # % diferencia entre precio actual de venta y Retail PH
            # > 0 → vendiendo sobre PH (bueno), < 0 → bajo PH (riesgo)
            p["_vs_retail_ph_pct"] = round((price / rph - 1) * 100, 1) if price > 0 else None

            # Precio sugerido: RetailPrice PH + 15% mínimo de margen sobre PH
            p["_precio_sugerido_ph"] = round(rph * 1.15, 2)

            # ROI potencial: (PH - costo) / costo × 100
            costo = p["_costo_mxn"]
            p["_roi_pct"] = round((rph - costo) / costo * 100, 1) if costo > 0 else None

            # Margen neto si se vendiera al precio PH
            if p["_costo_mxn"] > 0:
                comision_ph = rph * _ml_fee(rph)
                iva_ph = comision_ph * 0.16
                ganancia_ph = rph - p["_costo_mxn"] - comision_ph - iva_ph - 150
                p["_margen_ph_pct"] = round((ganancia_ph / rph) * 100, 1)
            else:
                p["_margen_ph_pct"] = None
        else:
            p["_vs_retail_ph_pct"] = None
            p["_precio_sugerido_ph"] = None
            p["_roi_pct"] = None
            p["_margen_ph_pct"] = None

        # Precios sugeridos: para recuperar retail BM (sin/con deal)
        _retail = p["_retail_mxn"]
        if _retail > 0:
            # Sin deal: (retail + 150) / (1 - fee * 1.16), con una iteración de refinamiento
            _fee0 = _ml_fee(_retail) * 1.16
            _sp0 = (_retail + 150) / (1 - _fee0) if _fee0 < 1 else None
            if _sp0:
                _fee1 = _ml_fee(_sp0) * 1.16
                p["_precio_sug_retail"] = round((_retail + 150) / (1 - _fee1)) if _fee1 < 1 else None
            else:
                p["_precio_sug_retail"] = None
            # Con deal: original_price para que (1 - buffer) * (1 - fee*1.16) * orig - 150 = target * retail
            if deal_buffer_pct < 1 and p["_precio_sug_retail"]:
                _eff = p["_precio_sug_retail"] * (1 - deal_buffer_pct)  # approx final sale price
                _fee_d = _ml_fee(_eff) * 1.16
                _denom = (1 - deal_buffer_pct) * (1 - _fee_d)
                p["_precio_sug_deal"] = round((retail_target_pct * _retail + 150) / _denom) if _denom > 0 else None
            else:
                p["_precio_sug_deal"] = None
        else:
            p["_precio_sug_retail"] = None
            p["_precio_sug_deal"] = None
        p["_deal_buffer_pct"] = deal_buffer_pct
        p["_retail_target_pct"] = retail_target_pct

        # Precio piso: mínimo para lograr 15% de margen después de comisión MeLi
        costo = p["_costo_mxn"]
        if costo > 0:
            # precio_piso = costo / (1 - fee*1.16 - margen_obj); fee dinámico según bracket
            # Estimación inicial → refinar una vez
            _fee0 = _ml_fee(costo * 1.6)
            _f0 = 1 - _fee0 * 1.16 - 0.15
            _piso0 = costo / _f0 if _f0 > 0 else costo * 3
            _fee1 = _ml_fee(_piso0)
            _f1 = 1 - _fee1 * 1.16 - 0.15
            p["_precio_piso"] = round(costo / _f1, 0) if _f1 > 0 else None
        else:
            p["_precio_piso"] = None


def _apply_bundle_stock_override(products: list, bundles: dict):
    """Para productos cuyo SKU coincide EXACTO con un bundle definido,
    sobreescribe _bm_avail/_bm_avail_raw con el mínimo real de sus
    componentes (stock_componente // qty_por_bundle) — reemplaza el atajo
    de 'tomar solo el primer componente'. Requiere que _bm_stock_cache ya
    tenga cada componente cacheado (se agregan como candidatos extra en
    _do_prewarm antes del bulk BM)."""
    if not bundles:
        return
    for p in products:
        raw_sku = (p.get("sku") or "").strip()
        bundle = bundles.get(raw_sku)
        if not bundle or not bundle["components"]:
            continue
        avails = []
        mty = cdmx = tj = reserved = 0
        for comp in bundle["components"]:
            bk = normalize_to_bm_sku(comp["sku"])
            entry = _bm_stock_cache.get(bk)
            data = entry[1] if entry else {}
            qty = max(1, int(comp.get("qty", 1) or 1))
            avails.append((data.get("avail_total", 0) or 0) // qty)
            mty += (data.get("mty", 0) or 0)
            cdmx += (data.get("cdmx", 0) or 0)
            tj += (data.get("tj", 0) or 0)
            reserved += (data.get("reserved_total", 0) or 0)
        bundle_avail = min(avails) if avails else 0
        p["_bm_avail"] = bundle_avail
        p["_bm_avail_raw"] = bundle_avail
        p["_bm_mty"] = mty
        p["_bm_cdmx"] = cdmx
        p["_bm_tj"] = tj
        p["_bm_total"] = mty + cdmx + tj
        p["_bm_reserved"] = reserved
        p["_is_bundle"] = True
        p["_bundle_components"] = bundle["components"]


def _apply_bundle_margin_override(products: list, bundles: dict):
    """Para productos-bundle, recalcula costo/margen como la SUMA de sus
    componentes (vía _sku_cost_map/_sku_retail_map, ya poblados por
    prewarm) contra own_price_mxn (o el precio ML actual si no se definió)
    — reemplaza el margen calculado hoy con el costo de un solo componente."""
    if not bundles:
        return
    for p in products:
        raw_sku = (p.get("sku") or "").strip()
        bundle = bundles.get(raw_sku)
        if not bundle or not bundle["components"]:
            continue
        cost_mxn = 0.0
        retail_mxn = 0.0
        for comp in bundle["components"]:
            bk = normalize_to_bm_sku(comp["sku"])
            qty = max(1, int(comp.get("qty", 1) or 1))
            cost_mxn += (_sku_cost_map.get(bk, 0) or 0) * qty
            retail_mxn += (_sku_retail_map.get(bk, 0) or 0) * qty
        sale_price = bundle.get("own_price_mxn") or p.get("price", 0) or 0
        p["_costo_mxn"] = round(cost_mxn, 2)
        p["_retail_mxn"] = round(retail_mxn, 2)
        p["_is_bundle"] = True
        p["_bundle_own_price"] = bundle.get("own_price_mxn")
        if sale_price > 0 and cost_mxn > 0:
            comision = sale_price * _ml_fee(sale_price)
            iva_comision = comision * 0.16
            ganancia = sale_price - cost_mxn - comision - iva_comision - 150
            p["_ganancia_est"] = round(ganancia, 2)
            p["_margen_pct"] = round((ganancia / sale_price) * 100, 1)
        else:
            p["_ganancia_est"] = None
            p["_margen_pct"] = None


# Nicknames conocidos de cuentas propias — fallback cuando ML API rate-limita en startup
_KNOWN_ML_NICKNAMES: dict = {
    "523916436": "APANTALLATEMX",
    "292395685": "AUTOBOT MEXICO",
    "391393176": "BLOWTECHNOLOGIES",
    "515061615": "LUTEMAMEXICO",
}


async def _seed_one(user_id: str, refresh_token: str, label: str, nickname_hint: str = ""):
    """Intenta recuperar tokens para una cuenta via refresh_token.
    También obtiene el nickname desde la API de MeLi para mostrarlo en el dropdown.
    nickname_hint: fallback desde env var MELI_NICKNAME_N — se usa cuando ML API rate-limita."""
    import httpx
    from app.config import MELI_TOKEN_URL, MELI_CLIENT_ID, MELI_CLIENT_SECRET, MELI_API_URL
    try:
        async with httpx.AsyncClient() as client:
            resp = await client.post(MELI_TOKEN_URL, data={
                "grant_type": "refresh_token",
                "client_id": MELI_CLIENT_ID,
                "client_secret": MELI_CLIENT_SECRET,
                "refresh_token": refresh_token,
            })
            if resp.status_code == 200:
                data = resp.json()
                access_token = data["access_token"]
                # Obtener nickname desde MeLi API
                nickname = ""
                try:
                    me_resp = await client.get(
                        f"{MELI_API_URL}/users/{user_id}",
                        headers={"Authorization": f"Bearer {access_token}"}
                    )
                    if me_resp.status_code == 200:
                        nickname = me_resp.json().get("nickname", "")
                except Exception:
                    pass
                # Fallback 1: env var MELI_NICKNAME_N
                if not nickname and nickname_hint:
                    nickname = nickname_hint
                # Fallback 2: dict estático de cuentas conocidas
                if not nickname:
                    nickname = _KNOWN_ML_NICKNAMES.get(str(user_id), "")
                await token_store.save_tokens(
                    user_id,
                    access_token,
                    data["refresh_token"],
                    data.get("expires_in", 21600),
                    nickname=nickname,
                )
                print(f"[SEED] Tokens recovered for {label} (user {user_id}, nickname={nickname or '(sin nickname)'})")
            else:
                print(f"[SEED] Token refresh failed for {label}: {resp.status_code} {resp.text[:200]}")
    except Exception as e:
        print(f"[SEED] Error recovering tokens for {label}: {e}")


async def _backfill_nickname(user_id: str, access_token: str):
    """Rellena el nickname de una cuenta existente en DB que no lo tiene."""
    import httpx
    from app.config import MELI_API_URL
    try:
        nickname = ""
        async with httpx.AsyncClient() as client:
            resp = await client.get(
                f"{MELI_API_URL}/users/{user_id}",
                headers={"Authorization": f"Bearer {access_token}"}
            )
            if resp.status_code == 200:
                nickname = resp.json().get("nickname", "")
        # Fallback: dict estático de cuentas conocidas
        if not nickname:
            nickname = _KNOWN_ML_NICKNAMES.get(str(user_id), "")
        if nickname:
            await token_store.update_nickname(user_id, nickname)
            print(f"[SEED] Nickname actualizado: {user_id} → {nickname}")
    except Exception as e:
        print(f"[SEED] Error obteniendo nickname para {user_id}: {e}")


def _parse_env_slots(env_vars: dict) -> list:
    """Devuelve lista de (uid, rt, label, nick) para todos los slots en env_vars.
    Slot 1: MELI_USER_ID / MELI_REFRESH_TOKEN / MELI_NICKNAME
    Slot N: MELI_USER_ID_N / MELI_REFRESH_TOKEN_N / MELI_NICKNAME_N (sin límite)"""
    accounts = []
    uid = env_vars.get("MELI_USER_ID", "") or MELI_USER_ID
    rt = env_vars.get("MELI_REFRESH_TOKEN", "") or MELI_REFRESH_TOKEN
    nick = env_vars.get("MELI_NICKNAME", "")
    if uid and rt:
        accounts.append((uid, rt, "cuenta1", nick))
    n = 2
    while True:
        uid = env_vars.get(f"MELI_USER_ID_{n}", "")
        rt = env_vars.get(f"MELI_REFRESH_TOKEN_{n}", "")
        nick = env_vars.get(f"MELI_NICKNAME_{n}", "")
        if not uid or not rt:
            break
        accounts.append((uid, rt, f"cuenta{n}", nick))
        n += 1
    return accounts


async def _seed_tokens():
    """Auto-recover MeLi tokens. Lee Railway env vars primero, luego .env.production
    como fallback. Soporta N cuentas dinámicamente (cuenta1, cuenta2, cuenta3, ...)."""
    import os as _os
    from pathlib import Path as _Path

    # Leer .env.production como fallback (puede no existir en Railway)
    file_vars = {}
    env_file = _Path(__file__).resolve().parent.parent / ".env.production"
    if env_file.exists():
        for line in env_file.read_text(encoding='utf-8').splitlines():
            line = line.strip()
            if '=' in line and not line.startswith('#'):
                k, _, v = line.partition('=')
                file_vars[k.strip()] = v.strip()

    # Railway env vars tienen prioridad sobre el archivo (incluye MELI_NICKNAME_N)
    env_vars = {**file_vars}
    for key in ("MELI_USER_ID", "MELI_REFRESH_TOKEN", "MELI_NICKNAME",
                "MELI_USER_ID_2", "MELI_REFRESH_TOKEN_2", "MELI_NICKNAME_2",
                "MELI_USER_ID_3", "MELI_REFRESH_TOKEN_3", "MELI_NICKNAME_3",
                "MELI_USER_ID_4", "MELI_REFRESH_TOKEN_4", "MELI_NICKNAME_4",
                "MELI_USER_ID_5", "MELI_REFRESH_TOKEN_5", "MELI_NICKNAME_5"):
        val = _os.getenv(key)
        if val:
            env_vars[key] = val

    for uid, rt, label, nick_hint in _parse_env_slots(env_vars):
        existing = await token_store.get_tokens(uid)
        if not existing:
            await _seed_one(uid, rt, label, nickname_hint=nick_hint)
        else:
            is_expired = await token_store.is_token_expired(uid)
            if is_expired:
                # DB RT es más actual que env (ML rota el RT en cada uso)
                refresh_rt = existing.get("refresh_token") or rt
                print(f"[SEED] Token expirado para {label} — refrescando con RT {'db' if existing.get('refresh_token') else 'env'}...")
                await _seed_one(uid, refresh_rt, label, nickname_hint=nick_hint)
            elif not existing.get("nickname"):
                await _backfill_nickname(uid, existing.get("access_token", ""))
                # Fallback: si la API falla y tenemos hint de env var, usarlo directamente
                if nick_hint:
                    refetched = await token_store.get_tokens(uid)
                    if not (refetched or {}).get("nickname"):
                        await token_store.update_nickname(uid, nick_hint)
                        print(f"[SEED] Nickname desde env var: {uid} → {nick_hint}")

    # Backfill nickname para TODAS las cuentas en DB que aún no lo tienen
    # (incluye cuentas agregadas via OAuth que no están en env vars)
    try:
        import aiosqlite as _aio_seed
        from app.services.token_store import DATABASE_PATH as _DB_PATH_SEED
        async with _aio_seed.connect(_DB_PATH_SEED) as _db_seed:
            _db_seed.row_factory = _aio_seed.Row
            _cur = await _db_seed.execute(
                "SELECT user_id, access_token FROM tokens WHERE nickname IS NULL OR nickname = ''"
            )
            _missing = await _cur.fetchall()
        for _row in _missing:
            await _backfill_nickname(_row["user_id"], _row["access_token"] or "")
    except Exception as _e:
        print(f"[SEED] Backfill nicknames error: {_e}")


@asynccontextmanager
async def lifespan(app: FastAPI):
    """
    Inicializa la base de datos y siembra credenciales al arrancar el servidor.

    Orden de inicialización:
    1. init_db()           → Crea tablas si no existen (tokens, amazon_accounts, etc.)
    2. _seed_tokens()      → Siembra cuentas MeLi desde .env.production
    3. _seed_amazon_accounts() → Siembra cuentas Amazon desde .env.production
    """
    # ── Esenciales síncronos — deben completar antes de aceptar requests ──────
    # Envueltos en try/except: si el disco/volumen se llena, un solo INSERT que
    # falla (sqlite3.OperationalError: database or disk is full) NO debe tumbar
    # el arranque completo — eso deja el servicio 502 sin forma de entrar ni
    # siquiera a los endpoints de diagnóstico para liberar espacio (incidente
    # 2026-07-15, ver DEVLOG). Mejor bootear en modo degradado y poder actuar.
    try:
        await token_store.init_db()
    except Exception as _e_init:
        logger.error(f"[STARTUP] init_db() falló (¿disco lleno?): {_e_init}")
    try:
        await user_store.init_user_db()
    except Exception as _e_uinit:
        logger.error(f"[STARTUP] init_user_db() falló: {_e_uinit}")
    # Cargar cache de stock desde DB inmediatamente — operadores ven datos del
    # deploy anterior desde el primer request, sin esperar el prewarm (90s).
    try:
        await _load_bm_cache_from_db()
        await _load_stock_issues_from_db()
        # Cargar catálogo de productos BM (retail_ph, brand, model) desde DB
        # Para que VS REF% en planeación funcione desde el primer request.
        await _load_catalog_from_db()
    except Exception as _e_load:
        logger.error(f"[STARTUP] Carga de caché desde DB falló: {_e_load}")

    # Seed product type templates (TELEVISION, VACUUM_CLEANER validated)
    try:
        await token_store.seed_product_type_templates()
    except Exception as _e_seed:
        logger.error(f"[STARTUP] seed_product_type_templates() falló (¿disco lleno?): {_e_seed}")

    # ── Todo lo demás en background — yield inmediato para Coolify/Railway ───
    # Así uvicorn emite "Application startup complete" en <2s y el contenedor
    # no recibe SIGKILL por timeout (exit 137).
    import asyncio as _asyncio_lifespan
    from app.services.amazon_client import _seed_amazon_accounts

    import os as _os_bm
    _BM_DISABLED = _os_bm.getenv("DISABLE_BM_MONITOR", "true").lower() in ("1", "true", "yes")
    if _BM_DISABLED:
        logger.info("[BM] DISABLE_BM_MONITOR=true — polling BM deshabilitado en este ambiente")

    async def _seed_tokens_with_retry():
        """Intenta _seed_tokens() cada 30s hasta que TODAS las cuentas esperadas estén activas.
        Necesario cuando ML rate-limita el token endpoint al arrancar."""
        import os as _os_r
        # Contar cuentas esperadas según env vars
        n_expected = 1 if (_os_r.getenv("MELI_USER_ID") and _os_r.getenv("MELI_REFRESH_TOKEN")) else 0
        for _n in range(2, 10):
            if _os_r.getenv(f"MELI_USER_ID_{_n}") and _os_r.getenv(f"MELI_REFRESH_TOKEN_{_n}"):
                n_expected += 1
            else:
                break
        n_expected = max(n_expected, 1)

        for attempt in range(1, 25):  # max 12 min
            await _seed_tokens()
            accounts = await token_store.get_all_tokens()
            if len(accounts) >= n_expected:
                print(f"[SEED-RETRY] Tokens OK en intento #{attempt}: {len(accounts)}/{n_expected} cuentas")
                return
            print(f"[SEED-RETRY] Intento #{attempt}: {len(accounts)}/{n_expected} cuentas. Reintentando en 30s...")
            import asyncio as _aio_retry
            await _aio_retry.sleep(30)
        print(f"[SEED-RETRY] Máx intentos alcanzado. Cuentas activas: {len(await token_store.get_all_tokens())}/{n_expected}")

    async def _deferred_init():
        """Inicialización diferida — corre después de que uvicorn ya acepta requests."""
        # 0. One-time migration: si distribution_settings nunca fue configurado
        #    manualmente (updated_at==0), aplicar umbrales más sensatos que los
        #    defaults originales (threshold=10, buffer=2 → threshold=3, buffer=1).
        try:
            _dist_stg = await token_store.get_distribution_settings()
            if (_dist_stg.get("updated_at") or 0) == 0:
                await token_store.upsert_distribution_settings(
                    scarce_threshold_units=3, scarce_threshold_days=7, safety_buffer_units=1
                )
                logger.info("[MIGRATION] distribution_settings: threshold 10→3, buffer 2→1")
        except Exception as _e_dm:
            logger.warning(f"[MIGRATION] distribution_settings failed: {_e_dm}")

        # 1. Refrescar tokens ML + Amazon (con retry si ML rate-limita)
        await _seed_tokens_with_retry()
        await _seed_amazon_accounts()
        # 2. Monitor de precios BM (skip si DISABLE_BM_MONITOR=true)
        # Conectar caché local al monitor para que nunca golpee BM directamente
        if _bm_retail_ph_cache:
            price_monitor.set_cache(_bm_retail_ph_cache)
        if not _BM_DISABLED:
            await price_monitor.start()
        # 3. Cachés ya cargados en startup síncrono — solo refrescar BM global
        await _load_bm_cache_from_db()
        # 4. Recalcular precios sugeridos en bm_sku_gaps
        try:
            import aiosqlite as _aio_init
            from app.config import DATABASE_PATH as _DB_INIT
            updated = 0
            async with _aio_init.connect(_DB_INIT) as _db:
                _rows = await (await _db.execute(
                    "SELECT rowid, retail_price_usd FROM bm_sku_gaps"
                )).fetchall()
                for _row in _rows:
                    _rowid, _retail = _row[0], float(_row[1] or 0)
                    _new_sug  = round(_retail * 18 * 1.20, 0) if _retail > 0 else 0
                    _new_cost = round(_retail * 18, 0) if _retail > 0 else 0
                    await _db.execute(
                        "UPDATE bm_sku_gaps SET suggested_price_mxn=?, cost_price_mxn=?, cost_usd=? WHERE rowid=?",
                        (_new_sug, _new_cost, _retail, _rowid)
                    )
                    updated += 1
                await _db.commit()
            logger.info(f"Startup: recalculated prices for {updated} gap records")
        except Exception as _e:
            logger.warning(f"Startup price recalc failed: {_e}")

    _asyncio_lifespan.create_task(_deferred_init())

    # Loops periódicos (no bloquean — solo registran tareas de fondo)
    from app.api.amazon_products import start_onsite_background_sync
    start_onsite_background_sync()
    start_stock_sync()
    from app.services.stock_sync_multi import start_multi_stock_sync
    start_multi_stock_sync()
    start_token_refresh()
    start_supplier_debt_sync()
    start_realtime_alerts_reconcile()
    from app.api.system_health import start_health_check_loop
    start_health_check_loop()
    from app.services import buyer_messages_client as _bmc
    asyncio.create_task(_bmc.poll_loop())
    # Pre-warm caches en background (90s delay — espera a que ml_listing_sync llene la DB primero)
    # Loop periódico: refresca cada 10 min para que el Stock tab nunca espere en frío.
    # Con la DB local de listings el prewarm tarda <10s en lugar de 130s+.
    async def _startup_prewarm():
        await asyncio.sleep(90)  # ml_listing_sync necesita ~60s para full sync inicial
        _auto_fail_streak = 0   # fallos consecutivos del loop automático
        while True:
            _prewarm_ok = False
            # Precalentar todas las cuentas — la deduplicación por normalize_to_bm_sku
            # garantiza que SKUs repetidos entre cuentas usen el cache existente.
            try:
                accounts = await token_store.get_all_tokens()
                for acc in accounts:
                    uid = acc.get("user_id", "")
                    if uid:
                        await _prewarm_caches(user_id=uid)
                        await asyncio.sleep(1)
                _prewarm_ok = True
                _auto_fail_streak = 0
            except Exception:
                _auto_fail_streak += 1
                logger.warning(f"[AUTO-PREWARM] Fallo #{_auto_fail_streak} en loop automático")
            # Refrescar alertas de sobreventa con datos BM actualizados
            if _prewarm_ok:
                try:
                    accounts = await token_store.get_all_tokens()
                    for acc in accounts:
                        uid = acc.get("user_id", "")
                        if uid:
                            await _run_stock_sync_for_user(uid)
                            _backfill_order_zones_bg(uid)  # gradual, no bloquea (fire-and-forget)
                            _check_ml_winner_status_bg(uid)  # idem, Vigilancia (Helium10 Alerts)
                            await asyncio.sleep(2)
                except Exception:
                    pass
                # Sincronizar stock de gaps con caché BM fresco
                try:
                    await _sync_gap_stock_from_cache()
                except Exception:
                    pass
                # Vigilancia Amazon (Buy Box) — mismo ciclo, cuentas Amazon
                try:
                    _amz_accounts = await token_store.get_all_amazon_accounts()
                    for _amz_acc in _amz_accounts:
                        _seller_id = _amz_acc.get("seller_id", "")
                        if _seller_id:
                            _check_amazon_buy_box_status_bg(_seller_id)
                            await asyncio.sleep(2)
                except Exception:
                    pass
            # Limpieza de caches en memoria al final de cada ciclo completo
            try:
                _cleanup_memory_caches()
            except Exception:
                pass
            # Retry rápido en fallo (2 min); ciclo normal 15 min (requests BM son secuenciales)
            _sleep = 120 if _auto_fail_streak > 0 else 900
            await asyncio.sleep(_sleep)
    if not _BM_DISABLED:
        asyncio.create_task(_startup_prewarm())
    # Monitor de salud BinManager — chequea cada 2 min, fast-fail en prewarm si está caído
    if not _BM_DISABLED:
        asyncio.create_task(_bm_health_loop())

    # ── Sync diario de catálogo BM (3am Monterrey CDT = 09:00 UTC) ──
    # Descarga retail_ph, brand, model, title para todos los SKUs del bulk cache.
    # Corre cada noche — catálogo es fuente de verdad para alert "SKU desconocido en BM".
    async def _weekly_catalog_sync():
        from datetime import datetime as _dt, timezone as _tz, timedelta as _td
        while True:
            _now = _dt.now(_tz.utc)
            # 3am Monterrey CDT (UTC-6) = 09:00 UTC
            _next = _now.replace(hour=9, minute=0, second=0, microsecond=0)
            if _next <= _now:
                _next += _td(days=1)
            _secs = (_next - _now).total_seconds()
            logger.info(f"[CATALOG-SYNC] Próximo sync diario en {_secs/3600:.1f}h (3am MTY = 09:00 UTC)")
            await asyncio.sleep(_secs)
            logger.info("[CATALOG-SYNC] Iniciando sync diario de catálogo BM...")
            try:
                synced = await _sync_bm_product_catalog(source="auto")
                logger.info(f"[CATALOG-SYNC] Sync diario completado: {synced} SKUs")
            except Exception as _e:
                logger.warning(f"[CATALOG-SYNC] Error en sync diario: {_e}")
    if not _BM_DISABLED:
        asyncio.create_task(_weekly_catalog_sync())
    # Lanzador Inteligente — scan nocturno BM vs MeLi (3am Mexico = 9am UTC)
    start_gap_scan_loop()
    # Sync incremental de listings ML → DB local (elimina spinner en Stock tab)
    from app.services.ml_listing_sync import start_ml_listing_sync, register_listings_updated_callback

    def _invalidate_products_on_sync(uid: str, updates=None):
        """Limpia _products_cache cuando ml_listing_sync actualiza la DB.
        Si updates contiene items cuya qty pasó a >0, los evicta quirúrgicamente de
        _stock_issues_cache (restock/activate) sin borrar el resto del cache — sin spinner."""
        uid_prefix = f"{uid}:"
        for k in [k for k in _products_cache if k.startswith(uid_prefix)]:
            del _products_cache[k]
        logger.debug(f"[ML-SYNC-CB] products_cache invalidado para uid={uid} post-sync")
        # Evicción quirúrgica: items que recuperaron stock en ML → sacar de alertas Reabastecer
        if updates:
            newly_stocked = {iid for (iid, qty) in updates if qty > 0}
            if newly_stocked:
                si_prefix = f"stock_issues:{uid}:"
                for cache_key in [k for k in _stock_issues_cache if k.startswith(si_prefix)]:
                    cached = _stock_issues_cache.get(cache_key)
                    if not isinstance(cached, tuple) or len(cached) < 2:
                        continue
                    ts, data = cached
                    if not isinstance(data, dict):
                        continue
                    changed_cache = False
                    for section in ("restock", "activate"):
                        old_list = data.get(section, [])
                        if not old_list:
                            continue
                        new_list = [p for p in old_list if p.get("id") not in newly_stocked]
                        if len(new_list) != len(old_list):
                            evicted = len(old_list) - len(new_list)
                            data[section] = new_list
                            if section == "restock":
                                data["restock_count"] = data.get("restock_count", len(old_list)) - evicted
                            changed_cache = True
                            logger.info(f"[ML-QTY-CB] {section}: evictados {evicted} items uid={uid} (qty recuperó >0)")
                    if changed_cache:
                        _stock_issues_cache[cache_key] = (ts, data)

    register_listings_updated_callback(_invalidate_products_on_sync)
    start_ml_listing_sync()
    # Sync de listings Amazon → DB local (descarga solo, sin modificar Amazon)
    from app.services.amazon_listing_sync import start_amazon_listing_sync
    start_amazon_listing_sync()
    # Callback post stock-sync: invalida _products_cache + _stock_issues_cache
    # para que el prewarm recalcule alertas con qty ML correctas (no stale)
    from app.services.stock_sync_multi import register_sync_complete_callback

    async def _invalidate_caches_post_sync():
        _products_cache.clear()
        # NO limpiar _stock_issues_cache: el prewarm post-sync la reconstruye con datos nuevos.
        # Limpiarla aquí causaba spinner en el tab Stock durante/después de un sync.
        logger.info("[SYNC-CB] products_cache invalidado post stock-sync")

    register_sync_complete_callback(_invalidate_caches_post_sync)
    yield
    await price_monitor.stop()


app = FastAPI(title="Mercado Libre Dashboard", lifespan=lifespan)

