def _tab_url(platform: str, tab: str) -> str:
    if platform == "ml":
        return _ML_TAB_URL.get(tab, "/facturacion")
    if platform == "amz":
        return _AMZ_TAB_URL.get(tab, "/facturacion")
    return "/facturacion"


def _require_subtab(request: Request, platform: str, tab: str, subtab: str):
    """Gate de una sub-vista específica (ej. Salud→Mensajes). Se llama al
    inicio de partials/endpoints de subtabs individuales — el gating de
    AuthMiddleware solo cubre el tab completo, no cada subtab."""
    du = getattr(request.state, "dashboard_user", None)
    if not du or du.get("role") == "admin":
        return
    sections = du.get("allowed_sections") or []
    if not sections:
        return
    if not user_store.has_subtab_access(sections, platform, tab, subtab):
        raise HTTPException(status_code=403, detail="No tienes acceso a esta sección")


def _derive_audit_section(path: str) -> str:
    """Mapea un URL path a sección legible para auditoría y last_seen."""
    p = path.lower()
    if any(x in p for x in ("/items", "/products", "/lanzar", "/sin-lanzar")):
        return "Productos"
    if any(x in p for x in ("/orders", "orders-table")):
        return "Órdenes"
    if "/ads" in p:
        return "Ads"
    if any(x in p for x in ("/health", "/claims")):
        return "Reclamos"
    if "/returns" in p:
        return "Devoluciones"
    if any(x in p for x in ("/stock", "/inventory", "/distribucion")):
        return "Stock"
    if "/amazon" in p:
        return "Amazon"
    if any(x in p for x in ("/users", "/auditoria")):
        return "Admin"
    if any(x in p for x in ("/billing", "/facturacion")):
        return "Facturación"
    if any(x in p for x in ("/login", "/logout", "/set-password", "/auth")):
        return "Sistema"
    return "Dashboard"


class AuthMiddleware(BaseHTTPMiddleware):
    async def dispatch(self, request: Request, call_next):
        path = request.url.path
        if any(path.startswith(ex) for ex in _AUTH_EXEMPT):
            return await call_next(request)
        token = request.cookies.get("dash_session")
        du = await user_store.get_session(token) if token else None
        if not du:
            from urllib.parse import quote
            next_url = quote(str(request.url.path), safe="")
            return RedirectResponse(f"/login?next={next_url}", status_code=302)
        # Si debe cambiar contraseña, redirigir a set-password (excepto si ya está allí)
        if du.get("must_change_pw") and path != "/set-password":
            return RedirectResponse("/set-password", status_code=302)
        # Control de acceso por sección (solo para usuarios no-admin con secciones restringidas)
        allowed_sections = du.get("allowed_sections") or []
        if allowed_sections and du.get("role") != "admin":
            # Solo aplicar a rutas de página HTML (no API, no static)
            if not path.startswith("/api/") and not path.startswith("/static/"):
                denied = False
                if path == "/deuda-empresa":
                    denied = "deuda" not in allowed_sections
                elif path == "/amazon":
                    amz_tab = request.query_params.get("tab", "dashboard")
                    denied = not user_store.has_tab_access(allowed_sections, "amz", amz_tab)
                else:
                    tab_info = _PATH_TO_TAB.get(path)
                    if tab_info:
                        plat, tab = tab_info
                        denied = not user_store.has_tab_access(allowed_sections, plat, tab)
                if denied:
                    # Redirigir al primer tab/subtab permitido
                    dplat, dtab, _dsub = user_store.first_allowed_location(allowed_sections)
                    first_url = _tab_url(dplat, dtab) if dplat else "/facturacion"
                    return RedirectResponse(first_url, status_code=302)
        request.state.dashboard_user = du
        # Registrar presencia activa (fire-and-forget — no bloquea la respuesta)
        if not path.startswith("/static/") and path not in ("/favicon.ico",):
            _ip = request.headers.get("X-Forwarded-For", request.client.host if request.client else "")
            _is_page = not path.startswith("/api/") and not path.startswith("/partials/")
            _section = _PATH_TO_SECTION.get(path, _derive_audit_section(path)) if _is_page else ""
            # Cuenta activa = last_platform cookie determina ML vs Amazon (no depende de la URL)
            _last_platform = request.cookies.get("last_platform", "ml")
            async def _record_presence(username=du["username"], display=du.get("display_name") or du["username"],
                                       url=path, section=_section, ip=_ip,
                                       is_page=_is_page, last_platform=_last_platform,
                                       cookies=dict(request.cookies)):
                account_name = ""
                if is_page:
                    try:
                        if last_platform == "amz":
                            seller_id = cookies.get("active_amazon_id", "")
                            if seller_id:
                                acct = await token_store.get_amazon_account(seller_id)
                                account_name = acct.get("nickname") or seller_id if acct else seller_id
                        else:
                            uid = cookies.get("active_account_id", "")
                            all_ml = await token_store.get_all_tokens()
                            # Buscar por uid exacto; si vacío, usar la primera cuenta
                            match = next((a for a in all_ml if str(a["user_id"]) == str(uid)), None)
                            if not match and all_ml:
                                match = all_ml[0]
                            account_name = match["nickname"] if match else uid
                    except Exception:
                        pass
                await user_store.update_last_seen(
                    username=username, display_name=display,
                    url=url, section=section, ml_account=account_name, ip=ip,
                    is_page=is_page,
                )
            asyncio.create_task(_record_presence())
        return await call_next(request)


class AccountMiddleware(BaseHTTPMiddleware):
    """Setea el ContextVar de cuenta activa basado en la cookie active_account_id.
    Todos los roles pueden cambiar de cuenta — el rol controla qué pueden hacer en ella."""
    async def dispatch(self, request: Request, call_next):
        cookie_uid = request.cookies.get("active_account_id")
        if cookie_uid:
            tokens = await token_store.get_tokens(cookie_uid)
            if tokens:
                token = _meli_user_id_ctx.set(cookie_uid)
                try:
                    return await call_next(request)
                finally:
                    _meli_user_id_ctx.reset(token)
        return await call_next(request)


app.add_middleware(AuthMiddleware)
app.add_middleware(AccountMiddleware)


