@app.get("/partials/products-stock-issues", response_class=HTMLResponse)
async def products_stock_issues_partial(request: Request, threshold: int = 10):
    """Stock tab: Reabastecer + Riesgo + Activar. Resultado cacheado 5 min."""
    client = await get_meli_client()
    if not client:
        return HTMLResponse("<p>Error: No autenticado</p>")
    try:
        # Cache de resultado completo (evita re-computar cada vez)
        key = f"stock_issues:{client.user_id}:t{threshold}"
        entry = _stock_issues_cache.get(key)
        # Helper: añade orphan_count y active_user_id al ctx (siempre fresco, fuera del cache)
        async def _add_orphan_ctx(c: dict) -> dict:
            c["active_user_id"] = client.user_id
            try:
                from app.services import token_store as _ts
                _orows = await _ts.get_orphan_listings(platform="ml", account_id=client.user_id)
                c["orphan_count"] = len(_orows)
            except Exception:
                c["orphan_count"] = 0
            return c

        _du_stock = getattr(request.state, "dashboard_user", None) or {}
        _is_admin_stock = _du_stock.get("role") == "admin"

        if entry:
            _data_age_s = _time.time() - entry[0]
            ctx = await _add_orphan_ctx(entry[1].copy())
            # Stale banner solo si datos tienen más de 10 min — si no, todo perfecto
            ctx["stale"]        = _data_age_s > 600
            ctx["data_age_min"] = int(_data_age_s // 60)
            # Trigger prewarm en background solo si admin y datos > TTL (30 min)
            if _is_admin_stock and _data_age_s > _STOCK_ISSUES_TTL:
                asyncio.create_task(_prewarm_caches())
            return templates.TemplateResponse(request, "partials/products_stock_issues.html", ctx)
        # Sin cache en absoluto — operador y admin ven spinner (espera el prewarm).
        # Admin además dispara el prewarm si no está corriendo.
        if _is_admin_stock and not _prewarm_running:
            asyncio.create_task(_prewarm_caches())
        return HTMLResponse("""
<div id="stock-loading" class="text-center py-16 text-gray-500">
  <svg id="stock-spinner" class="animate-spin h-8 w-8 text-yellow-400 mx-auto mb-3" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
    <circle class="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" stroke-width="4"></circle>
    <path class="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"></path>
  </svg>
  <p id="stock-status-msg" class="text-sm font-medium text-gray-600">Calculando stock en background...</p>
  <p id="stock-status-sub" class="text-xs text-gray-400 mt-1">Revisando cada 5 segundos...</p>
  <p id="stock-error-msg" class="text-xs text-red-500 mt-2 hidden"></p>
</div>
<script>
(function() {
  var attempts = 0;
  var maxAttempts = 140;  // 140 x 5s = 700s (mas que el timeout de 600s del prewarm)
  function reload() {
    if (window.switchProductTab) window.switchProductTab('stock', '/partials/products-stock-issues');
    else location.reload();
  }
  function poll() {
    attempts++;
    fetch('/api/stock/prewarm-status')
      .then(function(r){ return r.json(); })
      .then(function(s) {
        var sub = document.getElementById('stock-status-sub');
        var err = document.getElementById('stock-error-msg');
        var msg = document.getElementById('stock-status-msg');
        if (s.ready) {
          if (msg) msg.textContent = 'Listo — cargando datos...';
          if (sub) sub.textContent = '';
          reload();
          return;
        }
        if (s.error) {
          // Error — mostrar mensaje y botón manual, NO auto-reload (evita loop infinito)
          var spinner = document.getElementById('stock-spinner');
          if (spinner) spinner.classList.add('hidden');
          if (err) { err.textContent = s.error; err.classList.remove('hidden'); }
          if (msg) msg.textContent = 'Error al calcular stock';
          if (sub) sub.innerHTML = '<button onclick="location.reload()" style="margin-top:8px;padding:4px 12px;background:#facc15;border-radius:6px;font-size:11px;font-weight:600;cursor:pointer;">Reintentar</button>';
          return;
        }
        // Si hay datos en cache (aunque sean viejos) cargarlos de inmediato
        if (s.stale_available) {
          if (msg) msg.textContent = 'Cargando datos del último ciclo...';
          if (sub) sub.textContent = '';
          reload();
          return;
        }
        // Sin datos y prewarm no corriendo — iniciarlo automáticamente
        if (!s.running) {
          fetch('/api/stock/force-prewarm', {method:'POST'}).catch(function(){});
          if (msg) msg.textContent = 'Iniciando actualización de stock...';
          if (sub) sub.textContent = 'Esto puede tardar unos minutos la primera vez.';
          setTimeout(poll, 5000);
          return;
        }
        var secs = attempts * 5;
        if (sub) sub.textContent = s.running ? ('Calculando... ' + secs + 's') : ('En espera... ' + secs + 's');
        if (attempts < maxAttempts) {
          setTimeout(poll, 5000);
        } else {
          // Tiempo agotado — mostrar botón manual, NO auto-reload
          var spinner2 = document.getElementById('stock-spinner');
          if (spinner2) spinner2.classList.add('hidden');
          if (msg) msg.textContent = 'El cálculo está tardando más de lo esperado';
          if (sub) sub.innerHTML = '<button onclick="location.reload()" style="margin-top:8px;padding:4px 12px;background:#facc15;border-radius:6px;font-size:11px;font-weight:600;cursor:pointer;">Reintentar</button>';
        }
      })
      .catch(function() {
        if (attempts < maxAttempts) setTimeout(poll, 5000);
      });
  }
  setTimeout(poll, 5000);
})();
</script>
""")

    finally:
        await client.close()


# ---------- Product Intelligence: shared cache ----------

import time as _time

# Cache compartido: items details + BM stock (evita re-fetch entre tabs)
_products_cache: dict[str, tuple[float, list]] = {}
_bm_stock_cache: dict[str, tuple[float, dict]] = {}
_sku_cost_map: dict[str, float] = {}    # sku -> costo MXN (del último prewarm)
_sku_retail_map: dict[str, float] = {} # sku -> retail_ph MXN (LastRetailPricePurchaseHistory × FX)
_item_net_ratio_map: dict[str, float] = {}  # item_id -> net_final/total_amount real (del tab ventas)
_PARTNER_COMMISSION_PCT = 0.07         # 7% comisión socio (aplicado sobre net_received ML)
_category_cache: dict[str, str] = {}  # category_id -> name
_PRODUCTS_CACHE_TTL = 900   # 15 min
_BM_CACHE_TTL = 420         # 7 min (era 15 — más frecuente para reflejar cambios de stock)
_orders_cache: dict[str, tuple[float, list]] = {}
_ORDERS_CACHE_TTL = 900     # 15 min
# Cache RetailPrice PH por SKU base — TTL 30 min (cambia lentamente)
_bm_retail_ph_cache: dict[str, tuple[float, float]] = {}  # sku -> (ts, price_usd)
_BM_RETAIL_PH_TTL = 7 * 24 * 3600  # 7 días — fuente real es DB (sync semanal)
# Cache AvgCostQTY por SKU base — mismo TTL/fuente que retail (sync semanal completo)
_bm_cost_cache: dict[str, tuple[float, float]] = {}  # sku -> (ts, cost_usd)


async def _sync_bm_product_catalog(source: str = "auto") -> int:
    """Descarga LastRetailPricePurchaseHistory para todos los SKUs de BM via
    ConfColumns_Conditions_Excel. 1 sola llamada, ~8,786 SKUs, 97% cobertura LRPPH.
    Corre 1x/semana (domingo 9pm Monterrey). Guarda en DB + actualiza _bm_retail_ph_cache.
    Retorna cantidad de SKUs guardados en DB.
    """
    global _bm_retail_ph_cache, _catalog_sync_running, _catalog_sync_history, _catalog_sync_task
    if _catalog_sync_running:
        return 0
    _catalog_sync_running = True
    _catalog_sync_task = asyncio.current_task()
    _t0 = _time.time()
    _total_rows = 0

    logger.info("[CATALOG-SYNC] Iniciando sync via ConfColumns_Conditions_Excel (1 sola llamada)")
    from app.services.binmanager_client import _BM_BASE, _AJAX_HEADERS, get_shared_bm as _get_bm_cat
    bm_cat = await _get_bm_cat()
    if not bm_cat._logged_in:
        await bm_cat.login()

    try:
        r = await bm_cat._post(
            f"{_BM_BASE}/InventoryReport/InventoryReport/ConfColumns_Conditions_Excel",
            json={
                "COMPANYID": 1,
                "NEEDRETAILPRICEPH": True,
                "NEEDRETAILPRICE": True,
                "NEEDAVGCOST": True,
                "NEEDSALES": True,
            },
            headers=_AJAX_HEADERS,
            timeout=120,
        )
        if r.status_code != 200:
            raise Exception(f"HTTP {r.status_code} de ConfColumns_Conditions_Excel")
        data = r.json()
        if not isinstance(data, list):
            raise Exception(f"Respuesta inesperada (no lista): {str(data)[:200]}")

        _total_rows = len(data)
        logger.info(f"[CATALOG-SYNC] ConfColumns retornó {_total_rows} filas")

        # Parsear — campo clave: LastRetailPricePurchaseHistory (97% cobertura)
        rows = []
        for _row in data:
            _sku = normalize_to_bm_sku((_row.get("SKU") or "").upper().strip())
            if not _sku:
                continue
            _rph = float(_row.get("LastRetailPricePurchaseHistory") or 0)
            _cost = float(_row.get("AvgCostQTY") or 0)
            _size = int(_row.get("Size") or 0)
            rows.append({
                "sku":       _sku,
                "retail_ph": _rph if 0 < _rph < 9000 else 0,
                "cost_usd":  _cost if 0 < _cost < 9000 else 0,
                "brand":     _row.get("Brand") or "",
                "model":     _row.get("Model") or "",
                "title":     _row.get("Title") or "",
                "size":      _size if 0 < _size <= 200 else 0,
            })

        # Guardar en DB
        saved = await token_store.upsert_bm_catalog_batch(rows)
        logger.info(f"[CATALOG-SYNC] {saved}/{_total_rows} SKUs guardados en DB")

        # Actualizar _bm_retail_ph_cache / _bm_cost_cache en memoria
        _now = _time.time()
        for _row in rows:
            if _row["retail_ph"] > 0:
                _bm_retail_ph_cache[_row["sku"]] = (_now, _row["retail_ph"])
            if _row["cost_usd"] > 0:
                _bm_cost_cache[_row["sku"]] = (_now, _row["cost_usd"])

        with_price = sum(1 for _r in rows if _r.get("retail_ph", 0) > 0)
        elapsed = round(_time.time() - _t0, 1)
        logger.info(f"[CATALOG-SYNC] Completado: {with_price}/{_total_rows} con LRPPH. "
                    f"Cache: {len(_bm_retail_ph_cache)} SKUs. Elapsed: {elapsed}s")
        _catalog_sync_history.append({
            "ts": _time.time(), "skus_total": _total_rows,
            "skus_saved": saved, "with_price": with_price,
            "elapsed_s": elapsed, "source": source, "ok": True, "error": "",
        })
        if len(_catalog_sync_history) > 10: _catalog_sync_history.pop(0)
        return saved

    except asyncio.CancelledError:
        elapsed = round(_time.time() - _t0, 1)
        _catalog_sync_history.append({
            "ts": _time.time(), "skus_total": _total_rows,
            "skus_saved": 0, "with_price": 0,
            "elapsed_s": elapsed, "source": source, "ok": False, "error": "Cancelado por usuario",
        })
        if len(_catalog_sync_history) > 10: _catalog_sync_history.pop(0)
        logger.info(f"[CATALOG-SYNC] Cancelado por usuario tras {elapsed}s")
        return 0
    except Exception as _err:
        elapsed = round(_time.time() - _t0, 1)
        _catalog_sync_history.append({
            "ts": _time.time(), "skus_total": _total_rows,
            "skus_saved": 0, "with_price": 0,
            "elapsed_s": elapsed, "source": source, "ok": False, "error": str(_err)[:200],
        })
        if len(_catalog_sync_history) > 10: _catalog_sync_history.pop(0)
        logger.error(f"[CATALOG-SYNC] Error: {_err}")
        return 0
    finally:
        _catalog_sync_running = False
        _catalog_sync_task = None


async def _load_catalog_from_db() -> int:
    """Al arrancar: carga bm_product_catalog de DB a _bm_retail_ph_cache/_bm_cost_cache
    en memoria. Así VS REF% funciona desde el primer request sin esperar el prewarm semanal.
    """
    global _bm_retail_ph_cache, _bm_cost_cache
    try:
        rows = await token_store.get_bm_catalog_all()
        now = _time.time()
        loaded = 0
        for row in rows:
            if row.get("retail_ph") and row["retail_ph"] > 0:
                _bm_retail_ph_cache[row["sku"]] = (now, float(row["retail_ph"]))
                loaded += 1
            if row.get("cost_usd") and row["cost_usd"] > 0:
                _bm_cost_cache[row["sku"]] = (now, float(row["cost_usd"]))
        logger.info(f"[CATALOG-LOAD] {loaded} SKUs con RetailPH cargados de DB al arrancar")
        return loaded
    except Exception as _e:
        logger.warning(f"[CATALOG-LOAD] Error cargando catálogo de DB: {_e}")
        return 0


# Cache para órdenes de Amazon — TTL corto porque es el dashboard del día
# Key: "{seller_id}:{date}" para invalidar automáticamente al cambiar de día
_amazon_daily_cache: dict[str, tuple[float, dict]] = {}
_AMAZON_DAILY_CACHE_TTL = 180  # 3 min — más fresco que MeLi porque Amazon tiene rate limits estrictos
_sale_price_cache: dict[str, tuple[float, dict | None]] = {}
_SALE_PRICE_CACHE_TTL = 300  # 5 min
_stock_issues_cache: dict[str, tuple[float, dict]] = {}
# Cache cross-account para dashboard general (independiente de cuenta activa)
_multi_account_cache: dict[str, tuple[float, dict]] = {}
_MULTI_ACCOUNT_CACHE_TTL = 300  # 5 minutos
_STOCK_ISSUES_TTL = 900      # 15 min (era 30 — más responsivo; BM down = servir stale)
_products_fetch_lock = asyncio.Lock()  # prevenir doble fetch concurrente
_synced_alert_items: dict[str, float] = {}  # item_id → timestamp de sync; TTL 10 min — excluidos de alertas hasta qty-sync ML


_ALL_MELI_STATUSES = ["active", "paused", "closed", "inactive", "under_review"]

_DB_PRODUCTS_MAX_AGE = 3600  # 1h — usar DB si el sync tiene < 1h de antigüedad

async def _get_all_products_cached(client, include_paused=False, include_all=False) -> list[dict]:
    """Devuelve todos los items, cacheado 15 min.
    OPTIMIZACIÓN: lee primero de ml_listings DB (sincronizado en background por ml_listing_sync).
    Si la DB tiene datos frescos (< 1h), los usa sin llamar ML API — carga instantánea.
    include_all=True trae TODOS los statuses (no usa DB — solo llamada directa a ML).
    Lock previene doble fetch cuando multiples requests concurrentes."""
    if include_all:
        suffix = ":all_statuses"
    elif include_paused:
        suffix = ":with_paused"
    else:
        suffix = ""
    key = f"products:{client.user_id}{suffix}"
    entry = _products_cache.get(key)
    if entry and (_time.time() - entry[0]) < _PRODUCTS_CACHE_TTL:
        return entry[1]

    async with _products_fetch_lock:
        entry = _products_cache.get(key)
        if entry and (_time.time() - entry[0]) < _PRODUCTS_CACHE_TTL:
            return entry[1]

        # --- Intentar leer de DB local (rápido, < 100ms) ---
        # Solo para active/paused — include_all siempre va a ML API (incluye cerrados)
        if not include_all:
            try:
                import json as _json
                max_synced = await token_store.get_ml_listings_max_synced_at(client.user_id)
                db_age = _time.time() - max_synced
                if max_synced > 0 and db_age < _DB_PRODUCTS_MAX_AGE:
                    # "inactive" = "Inactiva sin stock" en UI de ML — auto-desactivado por stock=0.
                    # Se incluye para poder detectar alertas de restock y re-activación.
                    statuses = ["active", "paused", "inactive"] if include_paused else ["active"]
                    db_rows = await token_store.get_ml_listings(client.user_id, statuses=statuses)
                    products_from_db = []
                    for r in db_rows:
                        dj = r.get("data_json") or ""
                        if dj:
                            try:
                                body = _json.loads(dj)
                                if body.get("id"):
                                    products_from_db.append(body)
                            except Exception:
                                pass
                    if products_from_db:
                        import logging as _log
                        _log.getLogger(__name__).info(
                            f"[PRODUCTS-CACHE] DB hit: {len(products_from_db)} items "
                            f"para uid={client.user_id} (edad DB: {db_age:.0f}s)"
                        )
                        _products_cache[key] = (_time.time(), products_from_db)
                        return products_from_db
            except Exception as _db_err:
                import logging as _log
                _log.getLogger(__name__).warning(f"[PRODUCTS-CACHE] DB fallback error: {_db_err}")
                # Continúa con fetch de ML API

        # --- Fallback: ML API (lento, solo si DB vacía o muy antigua) ---
        if include_all:
            all_ids = await client.get_all_item_ids_by_statuses(_ALL_MELI_STATUSES)
        elif include_paused:
            # "inactive" = "Inactiva sin stock" — ML auto-desactivó por qty=0; incluir para alertas.
            all_ids = await client.get_all_item_ids_by_statuses(["active", "paused", "inactive"])
        else:
            all_ids = await client.get_all_active_item_ids()
        all_details = []
        sem = asyncio.Semaphore(10)  # aumentado de 5 → 10 para reducir tiempo de fetch

        async def _batch(ids):
            async with sem:
                try:
                    return await client.get_items_details(ids)
                except Exception:
                    return []

        batches = [all_ids[i:i+20] for i in range(0, len(all_ids), 20)]
        results = await asyncio.gather(*[_batch(b) for b in batches])
        for batch_result in results:
            all_details.extend(batch_result)

        products = []
        for d in all_details:
            body = d.get("body", d)
            if body and body.get("id"):
                products.append(body)

        _products_cache[key] = (_time.time(), products)
        return products


async def _get_orders_cached(client, date_from: str, date_to: str) -> list:
    """Ordenes de 30 dias con cache."""
    key = f"orders:{client.user_id}:{date_from}"
    entry = _orders_cache.get(key)
    if entry and (_time.time() - entry[0]) < _ORDERS_CACHE_TTL:
        return entry[1]
    orders = await client.fetch_all_orders(date_from=date_from, date_to=date_to)
    _orders_cache[key] = (_time.time(), orders)
    return orders


async def _load_bm_cache_from_db():
    """Carga el caché BM desde DB al arrancar — warm-start que evita spinner tras restart.
    Timestamp se pone a 0 para que el prewarm re-fetche todo inmediatamente con la config
    actual (LOCATIONID, conditions). Así cualquier cambio de config se aplica en el primer
    bulk post-restart (~1-2 min) sin mostrar datos incorrectos por hasta 15 min."""
    import json as _json, logging as _log
    logger = _log.getLogger(__name__)
    try:
        rows = await token_store.load_bm_stock_cache(max_age_s=7200.0)  # 2h — solo hay >0 en DB
        loaded = 0
        for row in rows:
            sku = row["sku"].upper()
            data = _json.loads(row["data_json"])
            # Solo cargar entradas con stock > 0 (DB solo debería tener >0, pero doble guarda)
            if sku not in _bm_stock_cache and data.get("avail_total", 0) > 0:
                # Timestamp 0 → _cache_is_valid() lo declara expirado → prewarm re-fetcha
                # con el LOCATIONID y condiciones actuales del código. El dato de DB sigue
                # disponible como warm-start para la primer renderización antes del re-fetch.
                _bm_stock_cache[sku] = (0.0, data)
                loaded += 1
        logger.info(f"[BM-DB] Warm-start: {loaded} SKUs cargados (timestamp=0 → re-fetch en primer prewarm)")
    except Exception as _e:
        import logging as _log2
        _log2.getLogger(__name__).warning(f"[BM-DB] Error cargando desde DB: {_e}")


async def _load_stock_issues_from_db():
    """Carga stock_issues_cache desde SQLite al arrancar.
    El Stock tab muestra datos inmediatamente post-deploy en vez de 'Calculando...'
    El prewarm sigue corriendo en background y sobreescribe con datos frescos al terminar.
    NOTA: activate siempre empieza vacío — al arrancar no hay forma de verificar si
    el stock BM del snapshot sigue siendo real sin llamar a BM. El prewarm llena
    activate en <5 min. Mejor vacío que datos stale (ej: SKU con 0 stock real mostrando 549).
    """
    try:
        snapshots = await token_store.load_all_stock_issues_snapshots()
        loaded = 0
        for key, (ts, data) in snapshots.items():
            if key not in _stock_issues_cache:
                _fdata = dict(data)
                _fdata["activate"] = []
                _fdata["activate_count"] = 0
                _stock_issues_cache[key] = (ts, _fdata)
                loaded += 1
        if loaded:
            logger.info(f"[STOCK-DB] {loaded} snapshots cargados (activate vaciado — prewarm lo llenará)")
        else:
            logger.info("[STOCK-DB] Sin snapshots en DB — esperando primer prewarm")
    except Exception as _e:
        logger.warning(f"[STOCK-DB] Error cargando snapshots: {_e}")


async def _get_sale_prices_cached(client, item_ids: list[str]) -> dict[str, dict]:
    """Fetch /items/{id}/sale_price para detectar deals activos. Cache 5min.
    Retorna {item_id: {amount, regular_amount, ...}} solo para items CON descuento."""
    now = _time.time()
    result = {}
    to_fetch = []
    for iid in item_ids:
        entry = _sale_price_cache.get(iid)
        if entry and (now - entry[0]) < _SALE_PRICE_CACHE_TTL:
            if entry[1]:
                result[iid] = entry[1]
        else:
            to_fetch.append(iid)

    if not to_fetch:
        return result

    sem = asyncio.Semaphore(10)

    async def _fetch_one(iid):
        async with sem:
            try:
                data = await client.get_item_sale_price(iid)
                if data and data.get("regular_amount") and data.get("amount"):
                    if data["regular_amount"] > data["amount"]:
                        _sale_price_cache[iid] = (now, data)
                        return iid, data
                _sale_price_cache[iid] = (now, None)
                return iid, None
            except Exception:
                _sale_price_cache[iid] = (now, None)
                return iid, None

    results = await asyncio.gather(*[_fetch_one(iid) for iid in to_fetch])
    for iid, data in results:
        if data:
            result[iid] = data
    return result


# --- Seller catalog cache (for cross-sell in questions AI) ---
# Keyed by str(client.user_id). Populated lazily from questions page + background refresh.
_seller_catalog: dict = {}     # {uid: {item_id: {title, permalink, price}}}
_seller_catalog_ts: dict = {}  # {uid: float (last refresh timestamp)}
_CATALOG_CACHE_TTL = 900       # 15 min before background refresh
_seller_catalog_refresh_tasks: set = set()  # active background tasks
_price_comp_cache: dict = {}   # {uid: {"ts": float, "data": dict}} — caché 30 min

async def _refresh_seller_catalog(uid: str, access_token: str, refresh_token: str = ""):
    """Background: fetch all active items for seller uid and populate _seller_catalog."""
    try:
        from app.services.meli_client import MeliClient
        cat_client = MeliClient(access_token=access_token, refresh_token=refresh_token, user_id=uid)
        try:
            # Fetch up to 200 active item IDs
            all_ids = []
            for offset in (0, 100):
                resp = await cat_client.get(
                    f"/users/{uid}/items/search",
                    params={"status": "active", "offset": offset, "limit": 100},
                )
                batch_ids = resp.get("results", [])
                all_ids.extend(batch_ids)
                if len(batch_ids) < 100:
                    break
            if not all_ids:
                return
            # Fetch details in batches of 20
            catalog = dict(_seller_catalog.get(uid, {}))
            for i in range(0, len(all_ids), 20):
                batch = all_ids[i:i+20]
                details = await cat_client.get_items_details(batch)
                for d in details:
                    body = d.get("body", d) if isinstance(d, dict) else {}
                    iid = str(body.get("id", ""))
                    if iid and body.get("permalink"):
                        catalog[iid] = {
                            "title": body.get("title", ""),
                            "permalink": body.get("permalink", ""),
                            "price": body.get("price", 0),
                        }
            _seller_catalog[uid] = catalog
            _seller_catalog_ts[uid] = _time.time()
        finally:
            await cat_client.close()
    except Exception:
        pass
    finally:
        _seller_catalog_refresh_tasks.discard(uid)

# --- Background pre-warm ---
_prewarm_task = None
_prewarm_running: bool = False    # flag global — solo 1 prewarm a la vez
_prewarm_queued: bool = False     # si True, lanzar otro prewarm al terminar el actual
_prewarm_queued_uid: str | None = None  # user_id del prewarm en cola (None = default)
_prewarm_error: str = ""          # último error para mostrar en UI
_prewarm_progress: dict = {"done": 0, "total": 0, "started_at": 0.0}  # progreso en tiempo real
_prewarm_source: str = "auto"     # "auto" | "manual" — para el historial de BM sync log
_prewarm_history: list = []       # historial en memoria: últimas 20 ejecuciones del prewarm
# ── Catálogo BM semanal — estado en memoria ──────────────────────────────────
_catalog_sync_running: bool = False
_catalog_sync_task: object = None  # asyncio.Task actual — para poder cancelarlo
_catalog_sync_history: list = []   # últimas 10 corridas: {ts, skus, elapsed_s, source, ok, error}
# Estadísticas de cobertura BM del último bulk fetch — para diagnóstico en Sync Stock
_bm_bulk_stats: dict = {}  # {bulk_gr_rows, bulk_all_rows, found, zero, zero_skus, fallback_used}

# --- BM Bulk Caches (dos: GR-only y ALL-conditions) ---
_bm_bulk_gr_cache:   tuple[float, list] | None = None  # (timestamp, GRA/GRB/GRC/NEW rows) LOC47+68
_bm_bulk_all_cache:  tuple[float, list] | None = None  # (timestamp, GRA/GRB/GRC/ICB/ICC/NEW rows) LOC47+68
_bm_bulk_loc47_cache:     tuple[float, list] | None = None  # (timestamp, GR rows)  solo LOC47 = CDMX
_bm_bulk_loc68_cache:     tuple[float, list] | None = None  # (timestamp, GR rows)  solo LOC68 = MTY
_bm_bulk_loctj_cache:     tuple[float, list] | None = None  # (timestamp, GR rows)  LOC45+69+43+42 = Tijuana vendible
_bm_bulk_loc47_all_cache: tuple[float, list] | None = None  # (timestamp, ALL rows) solo LOC47 = CDMX (TVs ICB/ICC)
_bm_bulk_loc68_all_cache: tuple[float, list] | None = None  # (timestamp, ALL rows) solo LOC68 = MTY (TVs ICB/ICC)
_bm_bulk_loctj_all_cache: tuple[float, list] | None = None  # (timestamp, ALL rows) LOC45+69+43+42 = Tijuana (TVs ICB/ICC)
_bm_tv_loc_running: bool = False  # True mientras _fetch_tv_wh_breakdown corre (evita instancias concurrentes)
_bm_prev_bulk_sku_set: set = set()  # SKUs (clave BM normalizada) del bulk anterior — para detectar desapariciones
_activate_suppressed: dict = {}     # {user_id_str: set(item_id_str)} — ítems ocultados de Activar, persistido en DB
# Muestra de campos RAW del bulk (antes de slimming) — para diagnóstico de campos disponibles.
_bm_bulk_raw_sample: dict | None = None  # primer row crudo de la última llamada bulk

# Campos mínimos que necesitamos de cada row BM bulk.
# Descartar todo lo demás para reducir el footprint de memoria de los caches globales.
# _lookup_diag usa: SKU, AvailableQTY, Reserve, TotalQty
# _enrich_with_bm_data usa: SKU, RetailPrice, LastRetailPricePurchaseHistory, AvgCostQTY, Brand, Model, Title
_BM_BULK_KEEP_FIELDS = frozenset({
    "SKU", "AvailableQTY", "Reserve", "TotalQty",
    "RetailPrice", "LastRetailPricePurchaseHistory", "AvgCostQTY",
    "Brand", "Model", "Title",
})

def _slim_bulk_rows(rows: list) -> list:
    """Descarta campos no usados de las filas BM bulk para reducir memoria."""
    return [{k: v for k, v in r.items() if k in _BM_BULK_KEEP_FIELDS} for r in rows]


def _cleanup_memory_caches():
    """Limpia entradas expiradas de los caches en memoria para liberar RAM.
    Llamar después de cada ciclo completo de prewarm.
    Los entries expirados (TTL vencido) normalmente quedan en el dict hasta que
    son sobreescritos, acumulando memoria indefinidamente con múltiples cuentas.
    """
    import gc as _gc
    now = _time.time()

    # _products_cache: TTL 15 min — limpiar entries con > 2× TTL de antigüedad
    _prod_ttl = _PRODUCTS_CACHE_TTL * 2
    _expired_prod = [k for k, (ts, _) in list(_products_cache.items()) if now - ts > _prod_ttl]
    for k in _expired_prod:
        _products_cache.pop(k, None)

    # _bm_stock_cache: cap a 12,000 entries — eliminar los más viejos si se excede
    _BM_STOCK_MAX = 12000
    if len(_bm_stock_cache) > _BM_STOCK_MAX:
        _sorted_bm = sorted(_bm_stock_cache.items(), key=lambda x: x[1][0])
        _to_remove = len(_bm_stock_cache) - _BM_STOCK_MAX + 1000  # liberar 1000 extra
        for k, _ in _sorted_bm[:_to_remove]:
            _bm_stock_cache.pop(k, None)

    # _stock_issues_cache: TTL 30 min — limpiar entries con > 2× TTL
    _si_ttl = _STOCK_ISSUES_TTL * 2
    _expired_si = [k for k, (ts, _) in list(_stock_issues_cache.items()) if now - ts > _si_ttl]
    for k in _expired_si:
        _stock_issues_cache.pop(k, None)

    # Forzar GC para liberar objetos temporales del prewarm inmediatamente
    _gc.collect()

    logger.info(
        f"[MEM-CLEANUP] products_cache={len(_products_cache)} ({len(_expired_prod)} eliminados), "
        f"bm_stock_cache={len(_bm_stock_cache)}, "
        f"stock_issues_cache={len(_stock_issues_cache)} ({len(_expired_si)} eliminados)"
    )

async def _sync_gap_stock_from_cache():
    """Baja stock en bm_sku_gaps cuando el caché BM en memoria confirma reducción.
    Solo usa datos ya disponibles en _bm_stock_cache — sin llamadas adicionales a BM.
    El gap scanner nocturno es la fuente autoritativa para SKUs sin caché."""
    if not _bm_stock_cache:
        return
    try:
        import aiosqlite as _aio_gap
        async with _aio_gap.connect(DATABASE_PATH) as _db:
            _gap_rows = await (await _db.execute(
                "SELECT sku, stock_total FROM bm_sku_gaps WHERE status='unlaunched'"
            )).fetchall()
            _updates = []
            for _gr in _gap_rows:
                _sk = _gr[0]
                _current = int(_gr[1] or 0)
                _entry = _bm_stock_cache.get(normalize_to_bm_sku(_sk))
                if _entry is not None:
                    _, _bm_data = _entry
                    _avail = int(_bm_data.get("avail_total") or 0)
                    if _avail < _current:
                        _updates.append((_avail, _sk))
            if _updates:
                await _db.executemany(
                    "UPDATE bm_sku_gaps SET stock_total=? WHERE sku=?",
                    _updates,
                )
                await _db.commit()
                logger.info(f"[GAP-SYNC] {len(_updates)} SKUs bajados desde caché BM")
    except Exception as _e:
        logger.warning(f"[GAP-SYNC] Error: {_e}")


# --- BM Health Monitor ---
_bm_health: dict = {
    "ok": None,           # None=nunca chequeado, True=up, False=down
    "latency_ms": 0,
    "last_check_ts": 0.0,
    "last_ok_ts": 0.0,
    "consecutive_failures": 0,
    "error_type": None,   # "timeout" | "auth" | "connection" | "error"
    "last_error": "",
}
_bm_health_log: list = []   # últimos 20 registros de health checks

async def _check_bm_health():
    """Estado de BM derivado del último bulk fetch — sin llamadas extra a BM.
    ok=True si el último bulk trajo filas. ok=False si falló o nunca corrió.
    """
    global _bm_health, _bm_health_log
    t0 = _time.time()
    ok = False
    error_type: str | None = None
    error_msg = ""
    elapsed_ms = 0
    try:
        # Derivar estado de BM del bulk cache — sin llamada extra a BM.
        if _bm_bulk_gr_cache and len(_bm_bulk_gr_cache[1]) > 0:
            ok = True
            elapsed_ms = 0
        else:
            ok = False
            error_type = "error"
            error_msg = "Bulk GR cache vacío o no inicializado"
    except asyncio.TimeoutError:
        elapsed_ms = round((_time.time() - t0) * 1000)
        ok = False
        error_type = "timeout"
        error_msg = f"Timeout después de {round(_time.time() - t0)}s (umbral: 20s)"
    except Exception as _exc:
        elapsed_ms = round((_time.time() - t0) * 1000)
        ok = False
        _estr = str(_exc).lower()
        if "401" in _estr or "403" in _estr or "unauthorized" in _estr or "login" in _estr:
            error_type = "auth"
        elif "connect" in _estr or "refused" in _estr or "unreachable" in _estr or "name or service" in _estr:
            error_type = "connection"
        else:
            error_type = "error"
        error_msg = str(_exc)[:200]

    # Registrar en log (máx 20 entradas)
    from datetime import datetime as _dt_h
    try:
        from zoneinfo import ZoneInfo as _ZI
        _tj_tz = _ZI("America/Tijuana")
        _time_label = _dt_h.now(_tj_tz).strftime("%H:%M:%S")
    except Exception:
        _time_label = _dt_h.utcfromtimestamp(_time.time()).strftime("%H:%M:%S") + " UTC"
    _bm_health_log.append({
        "ts": _time.time(),
        "time_label": _time_label,
        "ok": ok,
        "latency_ms": elapsed_ms,
        "error_type": error_type,
        "error_msg": error_msg,
    })
    if len(_bm_health_log) > 20:
        _bm_health_log.pop(0)

    _bm_health["last_check_ts"] = _time.time()
    if ok:
        _bm_health["ok"] = True
        _bm_health["latency_ms"] = elapsed_ms
        _bm_health["last_ok_ts"] = _time.time()
        _bm_health["consecutive_failures"] = 0
        _bm_health["error_type"] = None
        _bm_health["last_error"] = ""
    else:
        _bm_health["ok"] = False
        _bm_health["consecutive_failures"] = _bm_health.get("consecutive_failures", 0) + 1
        _bm_health["error_type"] = error_type
        _bm_health["last_error"] = error_msg
        logger.warning(f"[BM-HEALTH] BM no responde — fallo #{_bm_health['consecutive_failures']} ({elapsed_ms}ms) [{error_type}] {error_msg[:80]}")


def _bm_is_confirmed_down() -> bool:
    """True solo cuando el health loop confirmó que BM está caído (≥1 fallo conocido).
    None (nunca chequeado) → False (no bloqueamos por incertidumbre).
    True/False según último check real."""
    return _bm_health.get("ok") is False


async def _bm_health_loop():
    """Chequea BM cada 2 min en background."""
    await asyncio.sleep(10)   # primer check a los 10s del arranque
    while True:
        try:
            await _check_bm_health()
        except Exception as _e:
            logger.error(f"[BM-HEALTH] Error inesperado: {_e}")
        await asyncio.sleep(120)  # cada 2 minutos


async def _prewarm_caches(user_id: str = None):
    """Pre-carga products + orders + BM stock + stock issues en background.
    Solo corre una instancia a la vez. Si se llama mientras ya corre, marca
    _prewarm_queued=True y el prewarm activo lanza otro al terminar.
    user_id: cuenta a precalentar explícitamente. None = usar ContextVar / default."""
    global _prewarm_running, _prewarm_queued, _prewarm_queued_uid, _prewarm_error, _prewarm_source
    if _prewarm_running:
        _prewarm_queued = True
        if user_id:
            _prewarm_queued_uid = user_id
        return
    _prewarm_running = True
    _prewarm_queued = False
    _prewarm_error = ""
    _this_prewarm_start = _time.time()
    try:
        client = await get_meli_client(user_id=user_id)
        if not client:
            _prewarm_error = "No hay cliente ML activo"
            return
        # Cargar caché BM desde DB antes del prewarm (usa datos del último sync)
        await _load_bm_cache_from_db()
        try:
            async def _do_prewarm():
                from datetime import datetime, timedelta
                now = datetime.utcnow()
                date_from = (now - timedelta(days=30)).strftime("%Y-%m-%d")
                date_to = now.strftime("%Y-%m-%d")

                # IMPORTANTE: solo active+paused — cerrados/inactivos no necesitan gestión de stock.
                # include_all=True podría traer miles de items históricos y colgar el prewarm.
                all_bodies, all_orders = await asyncio.gather(
                    _get_all_products_cached(client, include_paused=True),
                    _get_orders_cached(client, date_from, date_to),
                )
                sales_map = _aggregate_sales_by_item(all_orders)
                products = _build_product_list(all_bodies, sales_map)
                _enrich_sku_from_orders(products, all_orders)

                # Fetchear BM para activos + pausados + inactivos.
                # "inactive" = "Inactiva sin stock" — ML auto-desactivó por qty=0.
                # Incluirlos garantiza que SNTV007283-tipo no queden STALE y generen alertas.
                bm_candidates = [
                    p for p in products
                    if p.get("sku") and p.get("status") in ("active", "paused", "inactive")
                ]
                # Bundles reales: agregar cada componente como candidato extra para que
                # se incluya en el MISMO bulk BM de arriba — nunca una llamada BM aparte
                # por componente (mismo cuidado de concurrencia que el resto del prewarm).
                _bundles = await token_store.get_all_bundles()
                for _bdl in _bundles.values():
                    for _comp in _bdl["components"]:
                        if _comp.get("sku"):
                            bm_candidates.append({"sku": _comp["sku"], "status": "active"})
                _prewarm_progress["done"] = 0
                # Total = SKUs únicos normalizados (no productos totales).
                # Con include_paused=True puede haber miles de listings del mismo SKU base;
                # la deduplicación por normalize_to_bm_sku garantiza 1 sola consulta BM por SKU.
                _prewarm_progress["total"] = len(set(normalize_to_bm_sku(p["sku"]) for p in bm_candidates))
                _prewarm_progress["started_at"] = _time.time()
                bm_map = await _get_bm_stock_cached(bm_candidates, retry_stale=True)
                # Cargar regla de distribución para esta cuenta (si existe)
                _dist_rule = await token_store.get_distribution_rule(str(client.user_id))
                _dist_settings = await token_store.get_distribution_settings() if _dist_rule else None
                _sold_history = await token_store.get_account_sold_history(str(client.user_id)) if _dist_rule else None
                _apply_bm_stock(products, bm_map, dist_rule=_dist_rule, dist_settings=_dist_settings, sold_history=_sold_history)
                _apply_bundle_stock_override(products, _bundles)

                # Helper: SKU bulk-verificado en ESTE ciclo de prewarm (ts > 0).
                # Entradas cargadas de DB (ts = 0.0) pueden tener stock obsoleto.
                # Las alertas SOLO usan datos confirmados por el bulk actual.
                def _bm_bulk_ok(sku: str) -> bool:
                    if not sku:
                        return False
                    _e = _bm_stock_cache.get(normalize_to_bm_sku(sku))
                    return _e is not None and _e[0] > 0.0

                # Recomendación inteligente de qty a sincronizar por velocidad de ventas.
                # Fórmula: stock para 14 días al ritmo actual, acotado a la cuota asignada.
                # Boost estacional: si hay un evento vigente (Buen Fin/Hot Sale/Navidad,
                # con lead_days de anticipación), se multiplica el target de demanda antes
                # de acotar — nunca toca disponibilidad publicada, solo la recomendación.
                import math as _math_rec
                from datetime import datetime as _dt_boost, timedelta as _td_boost
                _seasonal_events = await token_store.get_seasonal_events()
                _today_boost = _dt_boost.utcnow().date()

                def _seasonal_boost_for(_title: str, _cat_id: str) -> dict:
                    best = {"multiplier": 1.0, "event_name": None}
                    _title_up = (_title or "").upper()
                    for ev in _seasonal_events:
                        if not ev.get("active"):
                            continue
                        cat_f = (ev.get("category_filter") or "").strip()
                        if cat_f and cat_f.upper() not in _title_up and cat_f.upper() != (_cat_id or "").upper():
                            continue
                        try:
                            _start = _dt_boost.strptime(ev["start_date"], "%Y-%m-%d").date()
                            _end = _dt_boost.strptime(ev["end_date"], "%Y-%m-%d").date()
                        except (ValueError, TypeError):
                            continue
                        _lead = _td_boost(days=int(ev.get("lead_days") or 0))
                        if (_start - _lead) <= _today_boost <= _end and ev["multiplier"] > best["multiplier"]:
                            best = {"multiplier": ev["multiplier"], "event_name": ev["name"]}
                    return best

                # Para el banner de transparencia en el Stock tab — eventos vigentes
                # HOY (sin importar categoría), independiente del cruce por producto.
                _active_seasonal_events = []
                for _ev in _seasonal_events:
                    if not _ev.get("active"):
                        continue
                    try:
                        _ev_start = _dt_boost.strptime(_ev["start_date"], "%Y-%m-%d").date()
                        _ev_end = _dt_boost.strptime(_ev["end_date"], "%Y-%m-%d").date()
                    except (ValueError, TypeError):
                        continue
                    _ev_lead = _td_boost(days=int(_ev.get("lead_days") or 0))
                    if (_ev_start - _ev_lead) <= _today_boost <= _ev_end:
                        _active_seasonal_events.append({
                            "name": _ev["name"], "multiplier": _ev["multiplier"],
                            "end_date": _ev["end_date"], "category_filter": _ev.get("category_filter") or "",
                        })

                for _rp in products:
                    _r_raw  = int(_rp.get("_bm_avail_raw") or _rp.get("_bm_avail") or 0)
                    _r_alloc = int(_rp.get("_bm_avail") or 0)
                    _u30    = int(_rp.get("units_30d") or 0)
                    if _r_raw == 0:
                        _rp["_rec_qty"] = 0; _rp["_rec_badge"] = ""; _rp["_rec_u30"] = 0
                        continue
                    _cap = _r_alloc if _r_alloc > 0 else _r_raw
                    _boost = _seasonal_boost_for(_rp.get("title", ""), _rp.get("category_id", ""))
                    if _u30 == 0:
                        _rp["_rec_qty"]   = min(2, _cap)
                        _rp["_rec_badge"] = "sin historial"
                    else:
                        _target = max(1, int(_math_rec.ceil(_u30 / 30.0 * 14 * _boost["multiplier"])))
                        _rp["_rec_qty"]   = max(1, min(_cap, _target))
                        _rp["_rec_badge"] = (
                            "alta demanda" if _u30 >= 20 else
                            "demanda media" if _u30 >= 6 else
                            "baja demanda"
                        )
                    if _boost["multiplier"] > 1.0:
                        _rp["_rec_badge"] = f"{_rp['_rec_badge']} (temporada: {_boost['event_name']})".strip()
                    _rp["_rec_u30"] = _u30
                    _rp["_seasonal_boost"] = _boost["multiplier"]

                # Persistir caché BM en DB para sobrevivir reinicios.
                # SOLO guardar entradas con avail_total > 0 — los ceros de bulk fallido
                # no deben sobrevivir un restart y generar falsas alarmas de sobreventa.
                # Los ceros genuinos se re-verifican en el primer prewarm post-restart.
                # t=0.0 = cargado de DB sin verificar en este proceso (bulk miss con dato stale).
                # NO re-guardar esas entradas: perpetuarían datos incorrectos (ej: avail=549 real=0).
                # Solo persistir entradas verificadas en ESTE proceso (t > 0).
                try:
                    _bm_entries = [
                        (s, d, t) for s, (t, d) in _bm_stock_cache.items()
                        if d.get("avail_total", 0) > 0 and t > 0
                    ]
                    if _bm_entries:
                        await token_store.upsert_bm_stock_batch(_bm_entries)
                except Exception as _save_exc:
                    logger.warning(f"[PREWARM] Error persistiendo caché BM: {_save_exc}")
                # Nota: log_bm_sync_event se escribe en el finally externo
                # para garantizar que se escriba incluso en timeout.

                # BM metadata: RetailPrice USD, AvgCost, Brand (solo para candidatos)
                await _enrich_with_bm_product_info(bm_candidates)

                # Calcular márgenes en candidatos (necesario para GAP 5, 7, 6)
                fx = await _get_usd_to_mxn(client)
                _last_fx_rate = fx  # cachear para conversión USD en endpoints sin ML client
                _calc_margins(bm_candidates, fx)

                # Reconstruir _sku_cost_map desde el catálogo completo BM (AvgCostQTY × FX) —
                # antes solo se llenaba con bm_candidates (subconjunto angosto) y nunca se
                # limpiaba, quedando con datos viejos que ya no coincidían con retail (siempre
                # fresco). Mismo patrón que _sku_retail_map, misma fuente/frescura.
                _sku_cost_map.clear()
                for _csku, (_cts, _cusd) in _bm_cost_cache.items():
                    if 0 < _cusd < 9999:
                        _sku_cost_map[_csku] = round(_cusd * fx, 2)
                logger.info(f"[PREWARM] _sku_cost_map: {len(_sku_cost_map)} SKUs con AvgCostQTY MXN")

                # Reconstruir _sku_retail_map desde el catálogo completo BM (8484 SKUs × FX)
                # Cobertura total: todos los SKUs en DB, no solo los listings activos de ML
                _sku_retail_map.clear()
                for _rsku, (_rts, _rusd) in _bm_retail_ph_cache.items():
                    if 0 < _rusd < 9999:
                        _sku_retail_map[_rsku] = round(_rusd * fx, 2)
                logger.info(f"[PREWARM] _sku_retail_map: {len(_sku_retail_map)} SKUs con RetailPH MXN")

                # Bundles: margen real (suma de componentes) — después de reconstruir
                # _sku_cost_map/_sku_retail_map arriba, para que ya cubran los componentes.
                _apply_bundle_margin_override(bm_candidates, _bundles)

                # Precio sugerido por cobertura de stock — nunca auto-aplica, solo
                # sugiere (el usuario confirma vía /sync-price, igual que
                # ml_price_alerts). Regla v1, conservadora: escasez → +8% si quedan
                # <7 días de supply y sí se está vendiendo; sobrestock → -12% si
                # llevan >90 días de supply, nunca por debajo de _precio_piso.
                _coverage_alerts = []
                for _cp in bm_candidates:
                    _ds = _cp.get("_days_supply")
                    _price = _cp.get("price", 0) or 0
                    _u30 = _cp.get("units_30d", 0) or 0
                    if _ds is None or _price <= 0:
                        continue
                    if _ds < 7 and _u30 > 0:
                        _coverage_alerts.append({
                            "item_id": _cp["id"], "sku": _cp.get("sku", ""), "product_title": _cp.get("title", ""),
                            "current_price": _price, "suggested_price": round(_price * 1.08),
                            "reason": "escasez", "days_supply": _ds, "units_30d": _u30,
                        })
                    elif _ds > 90:
                        _sugg = round(_price * 0.88)
                        _piso = _cp.get("_precio_piso")
                        if _piso and _sugg < _piso:
                            _sugg = round(_piso)
                        if _sugg < _price:
                            _coverage_alerts.append({
                                "item_id": _cp["id"], "sku": _cp.get("sku", ""), "product_title": _cp.get("title", ""),
                                "current_price": _price, "suggested_price": _sugg,
                                "reason": "sobrestock", "days_supply": _ds, "units_30d": _u30,
                            })
                await token_store.replace_coverage_price_alerts(str(client.user_id), _coverage_alerts)

                # Pre-computar stock issues result — threshold default=10
                _DEFAULT_THRESHOLD = 10
                # Items sincronizados recientemente (TTL 60 min, cross-user, DB-backed):
                # excluirlos de alertas hasta que ML confirme el qty nuevo en el próximo sync.
                # Si ML volvió a 0 después de 60 min → el item re-aparece en alertas automáticamente.
                _synced_ids = await token_store.get_recently_synced_ids(str(client.user_id), ttl_seconds=3600)
                # Cargar ítems suprimidos de Activar (persistidos en DB por el usuario).
                _uid_str = str(client.user_id)
                if _uid_str not in _activate_suppressed:
                    _activate_suppressed[_uid_str] = await token_store.get_activate_suppressed(_uid_str)
                _uid_suppress = _activate_suppressed.get(_uid_str, set())

                # _bm_bulk_ok: True solo si el stock de este SKU fue confirmado por el bulk
                # ACTUAL de este prewarm (ts > 0). Entradas con ts=0 son warm-start de DB y
                # pueden tener stock obsoleto — excluirlas de alertas evita falsos positivos
                # cuando BM ya no tiene ese SKU en stock.
                restock = [p for p in products if p.get("available_quantity", 0) == 0 and (p.get("_bm_avail") or 0) > 0 and p.get("units", 0) > 0 and not p.get("is_full") and p.get("id") not in _synced_ids and _bm_bulk_ok(p.get("sku", ""))]
                restock.sort(key=lambda x: x.get("units", 0), reverse=True)
                # "_bm_avail" in p: BM fue consultado y respondió (avail=0 confirmado por BM).
                # Sin esta guarda, productos sin dato BM (fetch fallido) se clasifican como riesgo
                # porque (None or 0)==0. Solo flaggear cuando BM confirmó explícitamente avail=0.
                oversell_risk = [p for p in products if p.get("available_quantity", 0) > 0 and "_bm_avail" in p and p.get("_bm_avail", 0) == 0 and (p.get("_bm_avail_raw") or 0) == 0 and not p.get("is_full") and p.get("sku") and p.get("id") not in _synced_ids]
                oversell_risk.sort(key=lambda x: x.get("available_quantity", 0), reverse=True)
                restock_ids = {p["id"] for p in restock}
                # _bm_avail_verified_zero: si per-SKU verificó 0 recientemente, no incluir aunque
                # el bulk diga >0 — bulk de BM puede devolver phantom stock (bug BM server-side).
                activate = [p for p in products if p.get("available_quantity", 0) == 0 and (p.get("_bm_avail") or 0) > 0 and p["id"] not in restock_ids and not p.get("is_full") and p["id"] not in _synced_ids and str(p["id"]) not in _uid_suppress and not _bm_avail_verified_zero(p.get("sku", "")) and _bm_bulk_ok(p.get("sku", ""))]
                activate.sort(key=lambda x: x.get("_bm_avail", 0), reverse=True)
                critical = [
                    p for p in products
                    if p.get("available_quantity", 0) > 0
                    and 0 < (p.get("_bm_avail") or 0) <= _DEFAULT_THRESHOLD
                    and not p.get("is_full")
                    and p.get("sku")
                    and p.get("id") not in _synced_ids
                    and _bm_bulk_ok(p.get("sku", ""))
                ]
                critical.sort(key=lambda x: x.get("_bm_avail", 0))
                full_no_stock = [p for p in products if p.get("is_full") and p.get("available_quantity", 0) == 0 and (p.get("_bm_avail") or 0) > 0 and p.get("id") not in _synced_ids and _bm_bulk_ok(p.get("sku", ""))]
                full_no_stock.sort(key=lambda x: x.get("_bm_avail", 0), reverse=True)
                # GAP 7: Inventario estancado — stock en ambos lados pero 0 ventas en 30d
                stagnant = [
                    p for p in products
                    if (p.get("_bm_avail") or 0) > 0
                    and p.get("available_quantity", 0) > 0
                    and p.get("units", 0) == 0
                    and not p.get("is_full")
                    and p.get("sku")
                    and p.get("id") not in _synced_ids
                    and _bm_bulk_ok(p.get("sku", ""))
                ]
                stagnant.sort(
                    key=lambda x: (x.get("_bm_avail") or 0) * (x.get("price") or 1),
                    reverse=True
                )

                # GAP 5: Precio MeLi por debajo del RetailPrice PH de BM
                price_risk = [
                    p for p in bm_candidates
                    if p.get("price", 0) > 0
                    and p.get("_retail_ph_mxn", 0) > 0
                    and p["price"] < p["_retail_ph_mxn"]
                    and p.get("available_quantity", 0) > 0
                    and p.get("sku")
                ]
                price_risk.sort(
                    key=lambda x: x.get("_retail_ph_mxn", 0) - x.get("price", 0),
                    reverse=True
                )

                # Desbalance peligroso: MeLi publica más stock del que hay en BM
                imbalanced = [
                    p for p in products
                    if p.get("available_quantity", 0) > (p.get("_bm_avail_raw") or 0) > 0
                    and not p.get("is_full")
                    and p.get("sku")
                    and _bm_bulk_ok(p.get("sku", ""))
                ]
                imbalanced.sort(key=lambda x: x.get("available_quantity", 0) - (x.get("_bm_avail_raw") or 0), reverse=True)
                # Racha de Desbalance — memoria de cuántas horas seguidas lleva un SKU
                # así, para distinguir "recién detectado" de "posible error de config BM
                # persistente" (ej. LocationID mal clasificado, como 62/63 resuelto antes).
                await token_store.sync_stock_issue_streak(
                    str(client.user_id), "imbalanced",
                    {p.get("sku", ""): p.get("title", "") for p in imbalanced if p.get("sku")},
                )

                # Alert: SKU con formato BM que no aparece en bm_product_catalog
                # Fuente de verdad: catálogo BM descargado (no runtime cache/bulk).
                # Excluye prefijos numéricos (8501-style = dropship externo, no BM).
                _BM_PREFIXES = ("SN", "SHIL", "RMTC", "SHEL", "SHFL", "SHHP", "SHLB")
                try:
                    _cat_rows = await token_store.get_bm_catalog_all()
                    _bm_catalog_skus = {(r.get("sku") or "").upper() for r in _cat_rows if r.get("sku")}
                except Exception:
                    _bm_catalog_skus = set()
                no_bm_sku: list = []
                if _bm_catalog_skus:
                    _seen_no_bm: set = set()
                    for _p in products:
                        _raw = ((_p.get("sku") or "")).upper()
                        if not _raw or not any(_raw.startswith(_px) for _px in _BM_PREFIXES):
                            continue
                        _norm = normalize_to_bm_sku(_raw)
                        if _norm and _norm not in _bm_catalog_skus and _norm not in _seen_no_bm:
                            _seen_no_bm.add(_norm)
                            no_bm_sku.append(_p)

                # Drift de catálogo: SKUs con Desbalance persistente (>=24h seguidas) —
                # probable error de configuración BM, no problema de venta real.
                _drift_alerts = await token_store.get_drift_alerts(str(client.user_id), "imbalanced", min_hours=24.0)

                # Transferencia sugerida entre almacenes físicos — cruza demanda por
                # zona (de órdenes ML con ship_zone ya resuelto, ver backfill gradual)
                # contra dónde está el stock físico (mty/cdmx/tj, ya reales con el bulk
                # de Tijuana agregado arriba). Heurística v1: solo sugiere si el
                # desbalance demanda-vs-stock por zona es grande (>=30 puntos
                # porcentuales) y hay suficiente historial de demanda (>=5 unidades) —
                # deliberadamente conservador para no sugerir con datos ruidosos/escasos.
                _zone_demand_by_sku = await token_store.get_zone_demand_by_sku(str(client.user_id), "ml", days=60)

                def _suggest_transfer(_mty, _cdmx, _tj, _demand):
                    _stock = {"MTY": _mty, "CDMX": _cdmx, "TJ": _tj}
                    _total_stock = _mty + _cdmx + _tj
                    _total_demand = sum(_demand.values())
                    if _total_stock <= 0 or _total_demand < 5:
                        return None
                    _gaps = {z: (_demand.get(z, 0) / _total_demand) - (_stock[z] / _total_stock) for z in _stock}
                    _target = max(_gaps, key=_gaps.get)
                    _source = min(_gaps, key=_gaps.get)
                    if _target == _source or (_gaps[_target] - _gaps[_source]) < 0.30 or _stock[_source] < 2:
                        return None
                    _qty = min(_stock[_source], max(1, round(_stock[_source] * 0.3)))
                    return {"from_zone": _source, "to_zone": _target, "qty": _qty}

                transfer_suggestions = []
                for _tp in bm_candidates:
                    _t_mty = _tp.get("_bm_mty", 0) or 0
                    _t_cdmx = _tp.get("_bm_cdmx", 0) or 0
                    _t_tj = _tp.get("_bm_tj", 0) or 0
                    if not (_t_mty or _t_cdmx or _t_tj):
                        continue
                    _t_demand = _zone_demand_by_sku.get(_tp.get("sku", ""), {})
                    _sugg = _suggest_transfer(_t_mty, _t_cdmx, _t_tj, _t_demand)
                    if _sugg:
                        transfer_suggestions.append({
                            "sku": _tp.get("sku", ""), "product_title": _tp.get("title", ""),
                            "mty": _t_mty, "cdmx": _t_cdmx, "tj": _t_tj,
                            "demand_by_zone": _t_demand, **_sugg,
                        })

                # CLAVE: usar f"stock_issues:{uid}:t{threshold}" para que coincida con el endpoint
                _sic_key = f"stock_issues:{client.user_id}:t{_DEFAULT_THRESHOLD}"
                _sic_ts   = _time.time()
                _sic_data = {
                    "restock": restock, "oversell_risk": oversell_risk, "activate": activate,
                    "critical": critical, "full_no_stock": full_no_stock, "imbalanced": imbalanced,
                    "stagnant": stagnant, "price_risk": price_risk, "no_bm_sku": no_bm_sku,
                    "restock_count": len(restock) + len(activate),
                    "lost_revenue": sum(p.get("revenue", 0) for p in restock) + sum(p.get("price", 0) * min(p.get("_bm_avail", 0), 3) for p in activate),
                    "risk_count": len(oversell_risk), "risk_stock": sum(p.get("available_quantity", 0) for p in oversell_risk),
                    "activate_count": len(activate), "activate_stock": sum(p.get("_bm_avail", 0) for p in activate),
                    "critical_count": len(critical), "critical_bm_total": sum(p.get("_bm_avail", 0) for p in critical),
                    "full_no_stock_count": len(full_no_stock), "full_no_stock_bm": sum(p.get("_bm_avail", 0) for p in full_no_stock),
                    "imbalanced_count": len(imbalanced), "imbalanced_gap": sum(p.get("available_quantity", 0) - (p.get("_bm_avail") or 0) for p in imbalanced),
                    "stagnant_count": len(stagnant), "stagnant_bm": sum(p.get("_bm_avail", 0) for p in stagnant),
                    "price_risk_count": len(price_risk), "price_risk_gap": sum(p.get("_retail_ph_mxn", 0) - p.get("price", 0) for p in price_risk),
                    "no_bm_sku_count": len(no_bm_sku),
                    "bm_catalog_size": len(_bm_catalog_skus),
                    "threshold": _DEFAULT_THRESHOLD,
                    "active_seasonal_events": _active_seasonal_events,
                    "drift_alerts": _drift_alerts,
                    "drift_alerts_count": len(_drift_alerts),
                    "transfer_suggestions": transfer_suggestions,
                    "transfer_suggestions_count": len(transfer_suggestions),
                }

                # Guard: si el bulk de BM de esta corrida no verificó NINGÚN SKU de los
                # candidatos (BM caído, colgado, o sesión rota — visto 2026-07-23, el bulk
                # se quedó colgado mientras BM respondía bien a consultas puntuales), todos
                # los conteos de arriba salen en 0 por el gateo de _bm_bulk_ok(). Sin este
                # guard, ese resultado falso sobreescribe el snapshot bueno anterior (el que
                # sí sobrevive deploys vía SQLite) con puros ceros. Mejor conservar el
                # snapshot anterior — con su timestamp real — que mentir con "todo resuelto".
                _bulk_candidate_skus = set(normalize_to_bm_sku(p["sku"]) for p in bm_candidates)
                _bulk_verified_count = sum(1 for _s in _bulk_candidate_skus if _bm_bulk_ok(_s))
                _prev_sic_entry = _stock_issues_cache.get(_sic_key)
                _bulk_looks_dead = bool(_bulk_candidate_skus) and _bulk_verified_count == 0

                if _bulk_looks_dead and _prev_sic_entry:
                    logger.warning(
                        f"[STOCK-DB] Bulk BM no verificó ningún SKU de {len(_bulk_candidate_skus)} "
                        f"candidatos (uid={client.user_id}) — conservando snapshot anterior "
                        f"(edad {round(_time.time() - _prev_sic_entry[0])}s) en vez de sobreescribir con ceros."
                    )
                else:
                    _stock_issues_cache[_sic_key] = (_sic_ts, _sic_data)
                    # Persistir en SQLite — sobrevive deploys de Railway
                    try:
                        await token_store.save_stock_issues_snapshot(_sic_key, _sic_ts, _sic_data)
                    except Exception as _e:
                        logger.warning(f"[STOCK-DB] Error guardando snapshot: {_e}")

                # Background: fetch per-SKU warehouse (MTY/CDMX/TJ) para productos de Activar.
                # El bulk sólo da avail_total. El WH endpoint per-SKU da el desglose real.
                # Se corre en background para no bloquear el prewarm ni el Stock tab.
                _act_for_wh = [p for p in activate if p.get("sku")][:60]
                if _act_for_wh:
                    _wh_sic_key   = _sic_key
                    _wh_user_id   = client.user_id
                    _wh_threshold = _DEFAULT_THRESHOLD

                    async def _fetch_activate_wh(
                        _act=_act_for_wh, _key=_wh_sic_key,
                        _uid=_wh_user_id, _thr=_wh_threshold
                    ):
                        import logging as _wh_log
                        _wh_logger = _wh_log.getLogger(__name__)
                        await asyncio.sleep(3)
                        _updated = list(_act)
                        _n_ok = 0
                        _n_evict = 0
                        for _i, _ap in enumerate(_act):
                            _asku = _ap.get("sku", "")
                            if not _asku:
                                continue
                            try:
                                await _wh_phase(_asku, _track_progress=False)
                                _abk = normalize_to_bm_sku(_asku)
                                _ae  = _bm_stock_cache.get(_abk)
                                if _ae:
                                    _entry = _ae[1]
                                    _avail = _entry.get("avail_total", 0)
                                    _ver   = _entry.get("_v", False)
                                    if _ver and _avail > 0:
                                        # Per-SKU confirmó stock — actualizar ítem con avail real.
                                        _pu = dict(_ap)
                                        _pu["_bm_avail"]    = _avail
                                        _pu["_bm_reserved"] = _entry.get("reserved_total", 0)
                                        _pu["_bm_mty"]      = _entry.get("mty", 0)
                                        _pu["_bm_cdmx"]     = _entry.get("cdmx", 0)
                                        _pu["_bm_tj"]       = _entry.get("tj", 0)
                                        _updated[_i] = _pu
                                        _n_ok += 1
                                    elif _ver and _avail == 0:
                                        # Per-SKU confirmó 0 en LOC47+68 — evictar de Activar.
                                        _updated[_i] = None
                                        _n_evict += 1
                                    # else: BM falló (_v=False) — conservar valor del bulk.
                            except Exception:
                                pass
                            await asyncio.sleep(1)
                        # Actualizar snapshot: filtrar None (evictados) y limitar a IDs actuales.
                        # CRÍTICO: _cur_ids filtra ítems removidos por un prewarm más reciente.
                        _cur = _stock_issues_cache.get(_key)
                        if _cur:
                            _cur_ts, _cur_data = _cur
                            _cur_ids = {p.get("id") for p in _cur_data.get("activate", [])}
                            _safe_updated = [p for p in _updated if p is not None and p.get("id") in _cur_ids]
                            _new_data = dict(_cur_data)
                            _new_data["activate"] = _safe_updated
                            _new_data["activate_count"] = len(_safe_updated)
                            _stock_issues_cache[_key] = (_cur_ts, _new_data)
                            try:
                                await token_store.save_stock_issues_snapshot(_key, _cur_ts, _new_data)
                            except Exception:
                                pass
                        _wh_logger.info(
                            f"[ACTIVATE-WH] {_n_ok}/{len(_act)} confirmados con stock, "
                            f"{_n_evict} evictados (BM per-SKU confirmó 0 en LOC47+68)"
                        )

                    asyncio.create_task(_fetch_activate_wh())

            # Timeout de 600s — BM puede tener cientos de SKUs sin caché
            await asyncio.wait_for(_do_prewarm(), timeout=600.0)
        except asyncio.TimeoutError:
            _prewarm_error = "Timeout: el calculo tardo mas de 600s."
        finally:
            # Escribir BM sync log SIEMPRE — incluso en timeout o error parcial.
            # Fuera de _do_prewarm() para que sobreviva asyncio.TimeoutError.
            try:
                _bm_log_elapsed = round(_time.time() - _prewarm_progress.get("started_at", _time.time()), 1)
                _bm_log_skus    = len(_bm_stock_cache)
                _bm_log_retail  = len(_bm_retail_ph_cache)
                logger.info(f"[PREWARM] BM sync log: skus={_bm_log_skus}, elapsed={_bm_log_elapsed}s, source={_prewarm_source}, retail_ph={_bm_log_retail}")
                # Solo loguear cuando BM fue efectivamente descargado en este ciclo.
                # El startup corre prewarm 1x por cuenta ML (4 cuentas) pero solo la primera
                # hace fetch real de BM; las otras 3 usan el cache global (900s TTL).
                # Sin este guard aparecen 4 entradas idénticas en el historial.
                _bm_fetched_fresh = (
                    (_bm_bulk_gr_cache is not None and _bm_bulk_gr_cache[0] >= _this_prewarm_start)
                    or (_bm_bulk_all_cache is not None and _bm_bulk_all_cache[0] >= _this_prewarm_start)
                )
                if _bm_fetched_fresh:
                    _prewarm_history.append({
                        "ts":           _time.time(),
                        "sku_count":    _bm_log_skus,
                        "elapsed_s":    _bm_log_elapsed,
                        "source":       _prewarm_source,
                        "retail_ph":    _bm_log_retail,
                    })
                    if len(_prewarm_history) > 20:
                        _prewarm_history.pop(0)
                    await token_store.log_bm_sync_event(
                        sku_count=_bm_log_skus,
                        elapsed_s=_bm_log_elapsed,
                        source=_prewarm_source,
                    )
                    logger.info("[PREWARM] BM sync log escrito OK")
                    # Foto en disco de _bm_stock_cache — NO es una llamada nueva a BM,
                    # solo persiste lo que este mismo ciclo ya trajo, para que la vista
                    # de "Alertas de Stock" pueda consultarlo por SQL y sobreviva reinicios.
                    try:
                        _snapshot_rows = [
                            {
                                "sku": _sk,
                                "available_qty": _inv.get("avail_total", 0),
                                "reserve_qty": _inv.get("reserved_total", 0),
                                "total_qty": _inv.get("total", 0),
                            }
                            for _sk, (_ts, _inv) in _bm_stock_cache.items()
                            if _inv.get("_v")
                        ]
                        _snap_saved = await token_store.upsert_bm_stock_snapshot_batch(_snapshot_rows)
                        logger.info(f"[PREWARM] bm_stock_snapshot: {_snap_saved} SKUs guardados en disco")
                    except Exception as _snap_exc:
                        logger.warning(f"[PREWARM] Error guardando bm_stock_snapshot: {_snap_exc!r}")
                else:
                    logger.info("[PREWARM] BM sync log omitido — BM sirvió desde caché (no fetch real)")
            except Exception as _bm_log_exc:
                logger.warning(f"[PREWARM] Error escribiendo BM sync log: {_bm_log_exc!r}")
            await client.close()
    except Exception as _e:
        import traceback as _tb
        _prewarm_error = _tb.format_exc()
    finally:
        _prewarm_running = False
        _prewarm_source  = "auto"   # reset siempre — incluso si hubo error/timeout
        # Si hubo un prewarm en cola (p.ej. de "Sync ahora"), lanzarlo preservando el user_id
        if _prewarm_queued:
            _prewarm_queued = False
            _queued_uid = _prewarm_queued_uid
            _prewarm_queued_uid = None
            asyncio.create_task(_prewarm_caches(user_id=_queued_uid))


async def _fetch_tv_wh_breakdown():
    """Background task: fetch ALL-condition per-location bulks para desglose MTY/CDMX de TVs (SNTV*).

    Diseño:
    - Corre 180s DESPUÉS del prewarm — cuando _do_bulk_miss_retry (~50s) y _fetch_activate_wh (~60s)
      ya terminaron y el semáforo _BM_GLOBAL_SEM está quieto.
    - NO bloquea el prewarm. Lanzado con asyncio.create_task().
    - Solo actualiza entradas SNTV* en _bm_stock_cache (mutación in-place → result_map también se actualiza).
    - Flag _bm_tv_loc_running previene instancias concurrentes.
    """
    global _bm_tv_loc_running, _bm_bulk_loc47_all_cache, _bm_bulk_loc68_all_cache, _bm_bulk_loctj_all_cache
    import logging as _tvl
    _tvlog = _tvl.getLogger(__name__)

    if _bm_tv_loc_running:
        _tvlog.info("[BM-TV-WH] Task ya corriendo — skip")
        return
    _bm_tv_loc_running = True
    try:
        await asyncio.sleep(180)  # ceder espacio a bulk-miss retry + fetch_activate_wh

        from app.services.binmanager_client import get_shared_bm as _gsbm
        _tv_bm = await _gsbm()
        _TV_COND = "GRA,GRB,GRC,ICB,ICC,NEW"
        _ttl = 900
        _now = _time.time()

        # ── LOC47 ALL ───────────────────────────────────────────────────────
        _r47 = None
        if _bm_bulk_loc47_all_cache and (_now - _bm_bulk_loc47_all_cache[0]) < _ttl:
            _r47 = _bm_bulk_loc47_all_cache[1]
            _tvlog.info(f"[BM-TV-WH] LOC47-ALL cache ({len(_r47)} rows)")
        else:
            try:
                _f47 = await asyncio.wait_for(
                    _tv_bm.get_bulk_stock(conditions=_TV_COND, location_id="47"), timeout=60.0)
                if _f47:
                    _bm_bulk_loc47_all_cache = (_time.time(), _slim_bulk_rows(_f47))
                    _r47 = _f47
                    _tvlog.info(f"[BM-TV-WH] LOC47-ALL fetch OK: {len(_f47)} filas")
                elif _bm_bulk_loc47_all_cache:
                    _r47 = _bm_bulk_loc47_all_cache[1]
            except Exception as _e47:
                _tvlog.warning(f"[BM-TV-WH] LOC47-ALL error: {_e47}")
                if _bm_bulk_loc47_all_cache:
                    _r47 = _bm_bulk_loc47_all_cache[1]

        # ── LOC68 ALL ───────────────────────────────────────────────────────
        _r68 = None
        if _bm_bulk_loc68_all_cache and (_now - _bm_bulk_loc68_all_cache[0]) < _ttl:
            _r68 = _bm_bulk_loc68_all_cache[1]
            _tvlog.info(f"[BM-TV-WH] LOC68-ALL cache ({len(_r68)} rows)")
        else:
            try:
                _f68 = await asyncio.wait_for(
                    _tv_bm.get_bulk_stock(conditions=_TV_COND, location_id="68"), timeout=60.0)
                if _f68:
                    _bm_bulk_loc68_all_cache = (_time.time(), _slim_bulk_rows(_f68))
                    _r68 = _f68
                    _tvlog.info(f"[BM-TV-WH] LOC68-ALL fetch OK: {len(_f68)} filas")
                elif _bm_bulk_loc68_all_cache:
                    _r68 = _bm_bulk_loc68_all_cache[1]
            except Exception as _e68:
                _tvlog.warning(f"[BM-TV-WH] LOC68-ALL error: {_e68}")
                if _bm_bulk_loc68_all_cache:
                    _r68 = _bm_bulk_loc68_all_cache[1]

        # ── LOC-TJ ALL (45,69,43,42) — agregado 2026-07-23, antes tj quedaba en 0 ──
        _rtj = None
        if _bm_bulk_loctj_all_cache and (_now - _bm_bulk_loctj_all_cache[0]) < _ttl:
            _rtj = _bm_bulk_loctj_all_cache[1]
            _tvlog.info(f"[BM-TV-WH] LOC-TJ-ALL cache ({len(_rtj)} rows)")
        else:
            try:
                _ftj = await asyncio.wait_for(
                    _tv_bm.get_bulk_stock(conditions=_TV_COND, location_id="45,69,43,42"), timeout=60.0)
                if _ftj:
                    _bm_bulk_loctj_all_cache = (_time.time(), _slim_bulk_rows(_ftj))
                    _rtj = _ftj
                    _tvlog.info(f"[BM-TV-WH] LOC-TJ-ALL fetch OK: {len(_ftj)} filas")
                elif _bm_bulk_loctj_all_cache:
                    _rtj = _bm_bulk_loctj_all_cache[1]
            except Exception as _etj:
                _tvlog.warning(f"[BM-TV-WH] LOC-TJ-ALL error: {_etj}")
                if _bm_bulk_loctj_all_cache:
                    _rtj = _bm_bulk_loctj_all_cache[1]

        if not _r47 and not _r68 and not _rtj:
            _tvlog.warning("[BM-TV-WH] Los 3 bulks fallaron — sin actualización TV")
            return

        # Construir lookups
        def _tv_lkp_build(rows):
            ex, by = {}, {}
            for _row in (rows or []):
                _sk = (_row.get("SKU") or "").upper().strip()
                if _sk:
                    ex[_sk] = _row
                    by.setdefault(_extract_base_sku(_sk), []).append(_row)
            return ex, by

        def _tv_lkp(ex, by, key):
            _rr = [ex[key]] if key in ex else by.get(key, [])
            if not _rr:
                return 0
            _av = sum(int(v.get("AvailableQTY") or 0) for v in _rr)
            if _av == 0 and all(v.get("AvailableQTY") is None for v in _rr):
                _av = sum(int(v.get("TotalQty") or 0) for v in _rr)
            return _av

        _ex47, _by47 = _tv_lkp_build(_r47 or [])
        _ex68, _by68 = _tv_lkp_build(_r68 or [])
        _extj, _bytj = _tv_lkp_build(_rtj or [])

        _tv_n = 0
        for _ck, (_cts, _cd) in list(_bm_stock_cache.items()):
            if not _ck.upper().startswith("SNTV") or _cts == 0.0:
                continue  # solo SNTV* verificadas
            _cdmx = _tv_lkp(_ex47, _by47, _ck.upper())
            _mty  = _tv_lkp(_ex68, _by68, _ck.upper())
            _tj   = _tv_lkp(_extj, _bytj, _ck.upper())
            _avt  = _cd.get("avail_total", 0) or 0
            _lsum = _cdmx + _mty + _tj
            # Confiar en el bulk per-location ALL (ICB/ICC incluido) sobre el bulk combinado.
            # El bulk combinado LOC47+68+TJ retorna a veces un Available inferior al real
            # (discrepancia de agregación en BM API). Si per-location suma más, actualizar
            # avail_total para que BM Disp refleje el valor correcto.
            if _lsum > _avt:
                _cd["avail_total"] = _lsum
            _cd["cdmx"] = _cdmx
            _cd["mty"]  = _mty
            _cd["tj"]   = _tj
            _cd["_wh_fetched"] = True
            # Actualizar ts a tiempo actual: marca esta entrada como bulk-verificada (ts > 0).
            # Sin esto, SNTV* quedan con ts=0 (DB warm-start) y serían excluidas de alertas.
            _bm_stock_cache[_ck] = (_time.time(), _cd)
            _tv_n += 1

        _tvlog.info(f"[BM-TV-WH] MTY/CDMX actualizado para {_tv_n} TVs (SNTV*)")

        # Persistir entradas SNTV* al DB con mty/cdmx ya actualizados.
        # El DB save del prewarm ocurre a T+0 (antes de este task a T+180s), así que
        # el DB queda con mty=0/_wh_fetched=False. Sin este save, cada restart/deploy
        # arranca con MTY="—" para todos los TVs durante 3 minutos.
        try:
            from app.db import token_store as _tv_ts
            _tv_entries = [
                (_ck, _bm_stock_cache[_ck][1], _bm_stock_cache[_ck][0])
                for _ck in _bm_stock_cache
                if _ck.upper().startswith("SNTV")
                and _bm_stock_cache[_ck][0] > 0
                and (_bm_stock_cache[_ck][1].get("avail_total", 0) > 0
                     or _bm_stock_cache[_ck][1].get("_wh_fetched"))
            ]
            if _tv_entries:
                await _tv_ts.upsert_bm_stock_batch(_tv_entries)
                _tvlog.info(f"[BM-TV-WH] {len(_tv_entries)} entradas SNTV* persistidas en DB")
        except Exception as _tv_db_err:
            _tvlog.warning(f"[BM-TV-WH] Error persistiendo en DB: {_tv_db_err}")

        # Invalidar _stock_issues_cache: fue construido en prewarm (T+0) con avail_total
        # incorrecto para SNTV*. Ahora que tenemos mty/cdmx/avail correctos, forzar
        # reconstrucción en el próximo request del Stock tab.
        _stock_issues_cache.clear()
        _tvlog.info("[BM-TV-WH] _stock_issues_cache limpiado — próximo request reconstruye con datos BM correctos")
        # Disparar prewarm para reconstruir stock_issues_cache en background sin esperar al usuario.
        if not _prewarm_running:
            asyncio.create_task(_prewarm_caches())
            _tvlog.info("[BM-TV-WH] Prewarm de reconstrucción disparado")

    except Exception as _tv_err:
        import logging as _tvl2
        _tvl2.getLogger(__name__).error(f"[BM-TV-WH] Error inesperado: {_tv_err}")
    finally:
        _bm_tv_loc_running = False


async def _get_bm_stock_cached(products: list, sku_key="sku", retry_stale: bool = False) -> dict:
    """Devuelve {sku: {mty, cdmx, tj, total, avail_total}} para products, con cache.
    Usa Warehouse endpoint para desglose MTY/CDMX/TJ y InventoryBySKUAndCondicion_Quantity
    para stock verdaderamente disponible (Available, excluyendo reservados).
    retry_stale: True solo en prewarm — hace retry serial de SKUs STALE (puede tardar 60-120s).
                 False en requests del usuario — evita timeout de 90s.
    """
    import httpx, json as _json
    BM_WH_URL   = "https://binmanager.mitechnologiesinc.com/InventoryReport/InventoryReport/Get_GlobalStock_InventoryBySKU_Warehouse"
    BM_AVAIL_URL = "https://binmanager.mitechnologiesinc.com/InventoryReport/InventoryReport/InventoryBySKUAndCondicion_Quantity"

    result_map = {}
    to_fetch = []
    # Deduplicar por SKU base BM (normalize_to_bm_sku): SNTV007270-GRA y SNTV007270 NEW
    # son el mismo producto en BM → 1 sola consulta, resultado compartido entre ambos.
    _seen_bm_keys: set = set()

    def _cache_is_valid(c):
        # BM caído → TTL doble para no re-intentar fetches que van a fallar
        _bm_down_now = _bm_health.get("consecutive_failures", 0) >= 2
        _effective_ttl = _BM_CACHE_TTL * 2 if _bm_down_now else _BM_CACHE_TTL
        if not c or (_time.time() - c[0]) >= _effective_ttl:
            return False
        data = c[1]
        # reserve>0 pero total=0 y avail=0 → snapshot incoherente del bulk BM.
        # TotalQty siempre debe ser >= Reserve; este triplete indica dato parcial/corrupto.
        # Forzar retry per-SKU para obtener el valor real de BM.
        if data.get("reserved_total", 0) > 0 and data.get("total", 0) == 0 and data.get("avail_total", 0) == 0:
            return False
        # Entradas con total=0 y avail=0 solo son válidas si el fetch fue verificado (_v=True).
        # Sin _v (DB antigua, timeout) se re-fetchean para no servir 0s de fetches fallidos.
        if data.get("total", 0) == 0 and data.get("avail_total", 0) == 0:
            return bool(data.get("_v"))
        # total>0, avail=0, reserve=0 → matemáticamente incoherente.
        # Indica fallo silencioso de CONCEPTID=1 (devolvió (0,0) sin encontrar el SKU).
        if data.get("total", 0) > 0 and data.get("avail_total", 0) == 0 and data.get("reserved_total", 0) == 0:
            return False
        return True

    for p in products:
        sku = p.get(sku_key, "")
        if not sku:
            continue
        bm_key = normalize_to_bm_sku(sku)  # clave normalizada: primeros 10 chars
        cached = _bm_stock_cache.get(bm_key)
        if _cache_is_valid(cached):
            result_map[sku] = cached[1]
        elif bm_key not in _seen_bm_keys:
            to_fetch.append(sku)
            _seen_bm_keys.add(bm_key)
        # Si bm_key ya está en _seen_bm_keys (duplicado cross-account o variante),
        # no agregar a to_fetch. result_map se llenará en el post-fetch pass abajo.

    # También incluir SKUs de variaciones para calcular BM correcto por variación
    seen_skus = set(normalize_to_bm_sku(s) for s in to_fetch)
    seen_skus.update(normalize_to_bm_sku(s) for s in result_map)
    for p in products:
        if not p.get("has_variations"):
            continue
        for v in p.get("variations", []):
            v_sku = v.get("sku", "")
            if not v_sku:
                continue
            v_bm_key = normalize_to_bm_sku(v_sku)
            if v_bm_key in seen_skus:
                cached = _bm_stock_cache.get(v_bm_key)
                if _cache_is_valid(cached):
                    result_map[v_sku] = cached[1]
                continue
            cached = _bm_stock_cache.get(v_bm_key)
            if _cache_is_valid(cached):
                result_map[v_sku] = cached[1]
            else:
                to_fetch.append(v_sku)
            seen_skus.add(v_bm_key)

    if not to_fetch:
        return result_map

    # ── MODO CACHE-ONLY ────────────────────────────────────────────────────────
    # Solo el prewarm (retry_stale=True) hace llamadas reales a BM.
    # Requests de usuarios nunca tocan BM — sirven datos stale o vacíos del caché.
    # Esto evita que múltiples usuarios simultáneos saturen BM con llamadas directas.
    if not retry_stale:
        for _sku in to_fetch:
            _bk = normalize_to_bm_sku(_sku)
            _stale = _bm_stock_cache.get(_bk)
            if _stale:
                result_map[_sku] = _stale[1]   # dato antiguo — mejor que 0 falso
            # Si no hay nada en caché, result_map no tiene entrada → _bm_avail=None
            # → no se genera alerta de oversell por dato desconocido
        return result_map

    _EMPTY_BM = {"mty": 0, "cdmx": 0, "tj": 0, "total": 0, "avail_total": 0, "reserved_total": 0, "no_vendible": 0}

    def _parse_wh_rows(rows):
        """Suma QtyTotal por almacen. Retorna (mty, cdmx, tj)."""
        mty = cdmx = tj = 0
        for row in (rows or []):
            qty = row.get("QtyTotal", 0) or 0
            wname = (row.get("WarehouseName") or "").lower()
            if "monterrey" in wname or "maxx" in wname:
                mty += qty
            elif "autobot" in wname or "cdmx" in wname or "ebanistas" in wname:
                cdmx += qty
            else:
                tj += qty
        return mty, cdmx, tj

    def _store_wh(sku, rows_wh, avail_direct=0, reserve_direct=0, no_vendible_direct=0, avail_ok=True, wh_responded=True):
        """Parsea filas del Warehouse endpoint (MTY/CDMX/TJ) + avail/reserve directo de BM.

        avail_direct:   AvailableQTY de Get_GlobalStock_InventoryBySKU CONCEPTID=1+LOCATIONID=47,62,68,45,69,43,42 (MTY+CDMX+Cuautitlán+TJ real vendible)
        reserve_direct: Reserve del mismo endpoint — unidades reservadas para órdenes pendientes.
        avail_ok:       True si get_stock_with_reserve respondió (tuple); False si fue excepción/timeout.
        wh_responded:   True si el WH endpoint devolvió JSON válido (aunque vacío []).
                        False si devolvió HTML (sesión expirada) — JSON parse falló.
                        [] vacío con wh_responded=True ES dato verificado (SKU sin stock en esas ubicaciones).
                        [] vacío con wh_responded=False significa que NO sabemos el estado real.

        Casos verificados:
          SNTV001764: TotalQty=215, Reserve=2, AvailableQTY=213 ✓
          SNAC000029: AvailableQTY=2467, Reserve directo de BM ✓
          SNTV006485: física=1, reservada=1 → AvailableQTY=0 ✓
        """
        mty, cdmx, tj = _parse_wh_rows(rows_wh)
        warehouse_total = mty + cdmx
        avail_total     = int(avail_direct or 0)
        reserved_total  = int(reserve_direct or 0)
        no_vendible     = int(no_vendible_direct or 0)
        # Fallback avail: si avail=0 con stock físico real, usar warehouse_total.
        # Dos casos que justifican el fallback:
        #   1) avail_ok=False: get_stock_with_reserve lanzó excepción/timeout — dato desconocido
        #   2) avail_ok=True pero reserve=0: CONCEPTID=1 devolvió (0,0) sin encontrar el SKU.
        #      Si TotalQty=67 y Reserve=0, AvailableQTY debería ser 67 — el (0,0) es un fallo silencioso.
        #      Genuinamente reservado tendría reserve > 0 (ej: SNTV006485: total=1, reserve=1 → avail=0 correcto).
        if avail_total == 0 and warehouse_total > 0 and (not avail_ok or reserved_total == 0):
            avail_total = warehouse_total
        # _v=True: BM respondió con datos reales (incluyendo 0 genuino) o ya hay stock.
        # avail_ok=True: get_stock_with_reserve retornó tuple — respuesta verificada aunque sea (0,0).
        # avail_ok=False: retornó None (timeout/sesión) — no sabemos el estado real.
        verified = avail_ok or avail_total > 0 or reserved_total > 0

        # Fix A: si BM falló (verified=False, todo en cero), NO sobreescribir entrada válida.
        # Causa: bajo carga del prewarm, sesión BM expira → get_stock_with_reserve retorna None
        # → avail_ok=False, avail=0 → verified=False → sin esta guarda sobreescribiría la entrada
        # previa con datos buenos (ej: avail_total=2146) → falso oversell_risk hasta TTL.
        if not verified and avail_total == 0 and warehouse_total == 0:
            existing = _bm_stock_cache.get(normalize_to_bm_sku(sku))
            if existing:
                _ex_ts, _ex_data = existing
                if _ex_data.get("_v") and _ex_data.get("avail_total", 0) > 0:
                    return  # Preservar datos previos verificados — no clobber con session-failure zeros

        inv = {"mty": mty, "cdmx": cdmx, "tj": tj, "total": warehouse_total,
               "avail_total": avail_total, "reserved_total": reserved_total,
               "no_vendible": no_vendible, "_v": verified,
               "_wh_fetched": wh_responded}  # True = per-SKU WH endpoint fue llamado → MTY/CDMX/TJ son reales
        # Guardar bajo clave normalizada (base BM SKU, 10 chars) para que todas las variantes
        # del mismo producto (SNTV007270-GRA, SNTV007270 NEW, etc.) compartan una sola entrada.
        _bm_stock_cache[normalize_to_bm_sku(sku)] = (_time.time(), inv)
        # Agregar a result_map con el SKU original de MeLi para que _apply_bm_stock lo encuentre.
        # Incluir también entradas verificadas con stock=0: BM confirmó genuinamente 0 unidades.
        # Si no se incluyen aquí, _apply_bm_stock no puede distinguir "BM dijo 0" de "BM no consultado"
        # y el filtro oversell_risk usa (None or 0)==0 generando falsos positivos.
        if inv["total"] > 0 or avail_total > 0 or verified:
            result_map[sku] = inv
        return inv["total"] > 0 or avail_total > 0

    def _store_empty(sku):
        _bm_stock_cache[normalize_to_bm_sku(sku)] = (_time.time(), _EMPTY_BM)

    # Semaphore(1) = estrictamente secuencial — esperar respuesta antes de lanzar el siguiente.
    # Evita rate-limiting de BM. ~600 SKUs × ~0.5s = ~5 min por ciclo de prewarm (15 min).
    wh_sem = asyncio.Semaphore(1)

    async def _wh_phase(sku, http=None, _track_progress=True):
        """Consulta Get_GlobalStock_InventoryBySKU CONCEPTID=1 — fuente única de stock vendible.
        1 solo request HTTP por SKU (WH breakdown eliminado para reducir concurrencia BM).

        Con sem=12 + 1 request = 12 simultáneos máx → bien bajo el límite de 20 de httpx.
        MTY/CDMX/TJ breakdown = 0 (no disponible sin endpoint WH — solo avail total).
        """
        # normalize_to_bm_sku: split en primer espacio/guión → siempre 10 chars BM correctos.
        # _clean_sku_for_bm + _extract_base_sku NO manejan "(cantidad:2)" porque \(\d+\)
        # no matchea texto con letras/dos-puntos, dejando "SNHG000038 cantidad:2" → BM retorna 0.
        base = normalize_to_bm_sku(sku)
        if not base:
            _store_empty(sku)
            return
        async with wh_sem:
            try:
                # get_stock_with_reserve: CONCEPTID=1, LOCATIONID=47,62,68,45,69,43,42 (MTY+CDMX+Cuautitlán+TJ real vendible) — fuente única correcta.
                # Retorna (AvailableQTY, Reserve) cuando BM responde con datos reales (incluyendo 0,0).
                # Retorna None cuando hay fallo de sesión/red — diferente de 0 genuino.
                # timeout=8s: cubre re-login interno (3-5s) + latencia normal. Antes era 25s —
                # con BM lento por mantenimiento, 2 rondas × 25s = 50s → timeout de 90s en el tab.
                _stock = await asyncio.wait_for(
                    bm_cli.get_stock_with_reserve(base, conditions=_bm_conditions_for_sku(sku)),
                    timeout=8.0,
                )
                # _avail_ok=True: BM respondió (tuple) — dato verificado aunque sea (0,0) genuino.
                # _avail_ok=False: retornó None (timeout/sesión) — no sabemos el stock real.
                _avail_ok = _stock is not None
                avail_direct = _stock[0] if _avail_ok else 0
                reserve_direct = _stock[1] if _avail_ok else 0
                _store_wh(sku, [], avail_direct=avail_direct, reserve_direct=reserve_direct,
                          avail_ok=_avail_ok, wh_responded=False)
                if _track_progress:
                    _prewarm_progress["done"] = _prewarm_progress.get("done", 0) + 1
                return
            except Exception as _exc:
                import logging as _log
                _log.getLogger(__name__).warning(f"[BM-CACHE] Error para {sku}: {_exc}")
        _store_empty(sku)
        if _track_progress:
            _prewarm_progress["done"] = _prewarm_progress.get("done", 0) + 1

    # Fast-fail: si BM está caído (2+ fallos consecutivos), servir cache stale en lugar de
    # bloquear 600 × 25s = 10+ min esperando timeouts. El health loop detecta la caída.
    if _bm_health.get("consecutive_failures", 0) >= 2:
        logger.warning(f"[BM-CACHE] BM DOWN — skip fetch de {len(to_fetch)} SKUs, usando cache stale")
        _ff_now = _time.time()
        _ff_max_age = _BM_CACHE_TTL * 2  # 14 min — mismo TTL efectivo que _cache_is_valid usa cuando BM está caído
        for p in products:
            sku = p.get(sku_key, "")
            if not sku or sku in result_map:
                continue
            cached = _bm_stock_cache.get(normalize_to_bm_sku(sku))
            # ts=0.0 = cargado de DB sin verificar en este proceso → NO servir.
            # Entrada expirada (>14 min) = dato demasiado viejo para confiar → NO servir.
            # Mejor sin dato que con dato incorrecto (ej: avail=549 real=0).
            if cached and cached[0] > 0 and (_ff_now - cached[0]) < _ff_max_age:
                result_map[sku] = cached[1]
        return result_map

    from app.services.binmanager_client import get_shared_bm
    bm_cli = await get_shared_bm()

    _bulk_miss_set: set = set()  # inicializar aquí — accesible en post-fetch pass aunque to_fetch<=30

    if len(to_fetch) > 30:
        # BULK FETCH DUAL: dos caches separados por condición.
        # _bm_bulk_gr_cache  → GRA,GRB,GRC,NEW  — para todo SKU no-SNTV
        # _bm_bulk_all_cache → GRA,GRB,GRC,ICB,ICC,NEW — para SNTV* (cualquier TV puede ser ICB/ICC)
        # BM filtra server-side por CONDITION → no hace falta post-filtrar por campo.
        _BM_COND_GR  = "GRA,GRB,GRC,NEW"
        _BM_COND_ALL = "GRA,GRB,GRC,ICB,ICC,NEW"
        _used_bulk = False
        global _bm_bulk_gr_cache, _bm_bulk_all_cache

        _need_all = any(_bm_conditions_for_sku(s) == _BM_COND_ALL for s in to_fetch)

        # ── GR bulk (15 min TTL normal; ilimitado cuando BM está caído) ────────
        _bm_is_down_now = _bm_health.get("consecutive_failures", 0) >= 2
        _bulk_returned_empty = False  # True si BM respondió OK pero devolvió lista vacía
        _bulk_gr_rows = None
        if _bm_bulk_gr_cache:
            _age_gr = _time.time() - _bm_bulk_gr_cache[0]
            # Servir cache si: fresco (<15 min) O BM marcado caído Y no excede 2h.
            # Cap de 2h: aunque BM esté "caído" según health check, forzar re-intento
            # si el bulk tiene >2h — el health check puede estar equivocado (endpoint
            # individual falla pero bulk funciona). El except abajo tiene fallback a stale.
            _use_cache = _age_gr < 900 or (_bm_is_down_now and _age_gr < 7200)
            if _use_cache:
                _bulk_gr_rows = _bm_bulk_gr_cache[1]
                _age_label = f"{round(_age_gr)}s" + (" [STALE-BM-DOWN]" if _bm_is_down_now and _age_gr >= 900 else "")
                logger.info(f"[BM-CACHE] Reutilizando GR bulk cache ({_age_label})")
        if _bulk_gr_rows is None:
            try:
                _fresh_gr = await asyncio.wait_for(
                    bm_cli.get_bulk_stock(conditions=_BM_COND_GR),
                    timeout=270.0,
                )
                if _fresh_gr:
                    global _bm_bulk_raw_sample
                    if _fresh_gr and _bm_bulk_raw_sample is None:
                        _bm_bulk_raw_sample = {k: (type(v).__name__ if not isinstance(v, (str, int, float, bool, type(None))) else v) for k, v in _fresh_gr[0].items()}
                    _bm_bulk_gr_cache = (_time.time(), _slim_bulk_rows(_fresh_gr))
                    _bm_health["ok"] = True
                    _bm_health["last_ok_ts"] = _time.time()
                    _bm_health["consecutive_failures"] = 0
                    _bulk_gr_rows = _fresh_gr
                    logger.info(f"[BM-CACHE] GR bulk fetch OK: {len(_fresh_gr)} filas")
                else:
                    # Fix B1: BM respondió sin excepción pero devolvió vacío/None — tratar como fallo.
                    # Sin este else, _bulk_gr_rows queda None y el except-stale no se ejecuta → KPIs en 0.
                    logger.warning("[BM-CACHE] GR bulk fetch devolvió vacío — fallback a stale cache")
                    _bulk_returned_empty = True  # señal para evitar retries individuales
                    if _bm_bulk_gr_cache:
                        _bulk_gr_rows = _bm_bulk_gr_cache[1]
                        logger.warning(f"[BM-CACHE] GR usando stale ({len(_bulk_gr_rows)} rows) tras bulk vacío")
                    _bm_health["consecutive_failures"] = _bm_health.get("consecutive_failures", 0) + 1
            except Exception as _bulk_err:
                logger.warning(f"[BM-CACHE] GR bulk fetch error: {_bulk_err} — usando stale")
                # Si falla el fetch, intentar usar cache aunque sea antiguo
                if _bm_bulk_gr_cache:
                    _bulk_gr_rows = _bm_bulk_gr_cache[1]
                    logger.warning(f"[BM-CACHE] GR fallback a cache stale tras error fetch")

        # ── Bulk por ubicación: LOC47=CDMX, LOC68=MTY, LOC45+69+43+42=Tijuana
        # (para desglose MTY/CDMX/TJ). Solo cuando el GR bulk fue fresco (mismo
        # ciclo) — evitar fetches extra si ya hay cache. TJ agregado 2026-07-23
        # (antes _bm_tj quedaba siempre en 0 — ver DEVLOG, "zonas de almacén").
        global _bm_bulk_loc47_cache, _bm_bulk_loc68_cache, _bm_bulk_loctj_cache
        _bulk_loc47_rows = None  # CDMX (LOC 47)
        _bulk_loc68_rows = None  # MTY  (LOC 68)
        _bulk_loctj_rows = None  # Tijuana (LOC 45,69,43,42)
        if _bulk_gr_rows is not None and not _bm_is_down_now:
            # Reutilizar si la cache de ubicación es tan fresca como el GR bulk
            _loc_ttl = 900  # mismo TTL que GR bulk
            if _bm_bulk_loc47_cache and (_time.time() - _bm_bulk_loc47_cache[0]) < _loc_ttl:
                _bulk_loc47_rows = _bm_bulk_loc47_cache[1]
                logger.info(f"[BM-CACHE] Reutilizando LOC47 (CDMX) cache ({len(_bulk_loc47_rows)} rows)")
            else:
                try:
                    _fresh_l47 = await asyncio.wait_for(
                        bm_cli.get_bulk_stock(conditions=_BM_COND_GR, location_id="47"),
                        timeout=270.0,
                    )
                    if _fresh_l47:
                        _bm_bulk_loc47_cache = (_time.time(), _slim_bulk_rows(_fresh_l47))
                        _bulk_loc47_rows = _fresh_l47
                        logger.info(f"[BM-CACHE] LOC47 (CDMX) bulk OK: {len(_fresh_l47)} filas")
                    elif _bm_bulk_loc47_cache:
                        _bulk_loc47_rows = _bm_bulk_loc47_cache[1]
                except Exception as _le47:
                    logger.warning(f"[BM-CACHE] LOC47 bulk error: {_le47}")
                    if _bm_bulk_loc47_cache:
                        _bulk_loc47_rows = _bm_bulk_loc47_cache[1]
            if _bm_bulk_loc68_cache and (_time.time() - _bm_bulk_loc68_cache[0]) < _loc_ttl:
                _bulk_loc68_rows = _bm_bulk_loc68_cache[1]
                logger.info(f"[BM-CACHE] Reutilizando LOC68 (MTY) cache ({len(_bulk_loc68_rows)} rows)")
            else:
                try:
                    _fresh_l68 = await asyncio.wait_for(
                        bm_cli.get_bulk_stock(conditions=_BM_COND_GR, location_id="68"),
                        timeout=270.0,
                    )
                    if _fresh_l68:
                        _bm_bulk_loc68_cache = (_time.time(), _slim_bulk_rows(_fresh_l68))
                        _bulk_loc68_rows = _fresh_l68
                        logger.info(f"[BM-CACHE] LOC68 (MTY) bulk OK: {len(_fresh_l68)} filas")
                    elif _bm_bulk_loc68_cache:
                        _bulk_loc68_rows = _bm_bulk_loc68_cache[1]
                except Exception as _le68:
                    logger.warning(f"[BM-CACHE] LOC68 bulk error: {_le68}")
                    if _bm_bulk_loc68_cache:
                        _bulk_loc68_rows = _bm_bulk_loc68_cache[1]
            if _bm_bulk_loctj_cache and (_time.time() - _bm_bulk_loctj_cache[0]) < _loc_ttl:
                _bulk_loctj_rows = _bm_bulk_loctj_cache[1]
                logger.info(f"[BM-CACHE] Reutilizando LOC-TJ (45,69,43,42) cache ({len(_bulk_loctj_rows)} rows)")
            else:
                try:
                    _fresh_ltj = await asyncio.wait_for(
                        bm_cli.get_bulk_stock(conditions=_BM_COND_GR, location_id="45,69,43,42"),
                        timeout=270.0,
                    )
                    if _fresh_ltj:
                        _bm_bulk_loctj_cache = (_time.time(), _slim_bulk_rows(_fresh_ltj))
                        _bulk_loctj_rows = _fresh_ltj
                        logger.info(f"[BM-CACHE] LOC-TJ bulk OK: {len(_fresh_ltj)} filas")
                    elif _bm_bulk_loctj_cache:
                        _bulk_loctj_rows = _bm_bulk_loctj_cache[1]
                except Exception as _letj:
                    logger.warning(f"[BM-CACHE] LOC-TJ bulk error: {_letj}")
                    if _bm_bulk_loctj_cache:
                        _bulk_loctj_rows = _bm_bulk_loctj_cache[1]

        # ── ALL bulk (solo si hay SKUs SNTV-ICB/ICC/bundle) ──────────────────
        _bulk_all_rows = None
        if _need_all:
            if _bm_bulk_all_cache:
                _age_all = _time.time() - _bm_bulk_all_cache[0]
                _use_cache_all = _age_all < 900 or (_bm_is_down_now and _age_all < 7200)
                if _use_cache_all:
                    _bulk_all_rows = _bm_bulk_all_cache[1]
                    _age_label_all = f"{round(_age_all)}s" + (" [STALE-BM-DOWN]" if _bm_is_down_now and _age_all >= 900 else "")
                    logger.info(f"[BM-CACHE] Reutilizando ALL bulk cache ({_age_label_all})")
            if _bulk_all_rows is None:
                try:
                    _fresh_all = await asyncio.wait_for(
                        bm_cli.get_bulk_stock(conditions=_BM_COND_ALL),
                        timeout=270.0,
                    )
                    if _fresh_all:
                        _slimmed_all = _slim_bulk_rows(_fresh_all)
                        _bm_bulk_all_cache = (_time.time(), _slimmed_all)
                        _bulk_all_rows = _slimmed_all
                        logger.info(f"[BM-CACHE] ALL bulk fetch OK: {len(_fresh_all)} filas")
                    else:
                        # Fix B2: mismo caso que GR — bulk vacío sin excepción → stale fallback
                        logger.warning("[BM-CACHE] ALL bulk fetch devolvió vacío — fallback a stale cache")
                        if _bm_bulk_all_cache:
                            _bulk_all_rows = _bm_bulk_all_cache[1]
                except Exception as _bulk_err:
                    logger.warning(f"[BM-CACHE] ALL bulk fetch error: {_bulk_err} — usando stale")
                    if _bm_bulk_all_cache:
                        _bulk_all_rows = _bm_bulk_all_cache[1]

        if _bulk_gr_rows is not None or _bulk_all_rows is not None:
            def _build_lookup(rows):
                exact, by_base = {}, {}
                for _brow in (rows or []):
                    _sk = ((_brow.get("SKU") or "")).upper().strip()
                    if not _sk:
                        continue
                    exact[_sk] = _brow
                    by_base.setdefault(_extract_base_sku(_sk), []).append(_brow)
                return exact, by_base

            _exact_gr,  _by_base_gr  = _build_lookup(_bulk_gr_rows)  if _bulk_gr_rows  else ({}, {})
            _exact_all, _by_base_all = _build_lookup(_bulk_all_rows) if _bulk_all_rows else ({}, {})

            def _lookup(exact, by_base, fbase):
                row = exact.get(fbase)
                rows_to_sum = [row] if row is not None else by_base.get(fbase, [])
                if not rows_to_sum:
                    return 0, 0
                avail   = sum(int(v.get("AvailableQTY") or 0) for v in rows_to_sum)
                reserve = sum(int(v.get("Reserve")      or 0) for v in rows_to_sum)
                # Fallback a TotalQty SOLO si BM no envió AvailableQTY (campo null).
                # No activar cuando AvailableQTY llegó como 0 genuino — asumir avail=total
                # genera sobreventa si hay unidades reservadas no reportadas.
                if avail == 0 and reserve == 0:
                    _all_avail_null = all(v.get("AvailableQTY") is None for v in rows_to_sum)
                    if _all_avail_null:
                        total = sum(int(v.get("TotalQty") or 0) for v in rows_to_sum)
                        if total > 0:
                            avail = total  # AvailableQTY no vino → estimar desde TotalQty
                return avail, reserve

            _diag_found = 0           # SKUs con avail > 0
            _diag_zero_in_bulk  = 0   # encontrados en bulk con avail=0 (BM confirmó 0)
            _diag_not_in_bulk   = 0   # no encontrados en bulk → retry per-SKU
            _diag_zero_in_bulk_skus: list = []
            _diag_not_in_bulk_skus:  list = []
            _diag_fallback = 0        # SKUs donde se usó TotalQty fallback
            _bulk_miss_set: set = set()  # SKUs no en bulk → avail_ok=False → _v=False → retry

            # Wrapper de _lookup con diagnóstico integrado
            def _lookup_diag(exact, by_base, fbase, fsku):
                nonlocal _diag_found, _diag_zero_in_bulk, _diag_not_in_bulk, _diag_fallback
                row = exact.get(fbase)
                rows_to_sum = [row] if row is not None else by_base.get(fbase, [])
                if not rows_to_sum:
                    # SKU no está en bulk — el bulk no lo incluyó, NO significa 0 stock.
                    # Marcarlo como miss: avail_ok=False → _v=False → stale retry hace per-SKU.
                    _diag_not_in_bulk += 1
                    if len(_diag_not_in_bulk_skus) < 50:
                        _diag_not_in_bulk_skus.append(fsku)
                    _bulk_miss_set.add(fsku)
                    return 0, 0, 0
                avail       = sum(int(v.get("AvailableQTY")   or 0) for v in rows_to_sum)
                reserve     = sum(int(v.get("Reserve")         or 0) for v in rows_to_sum)
                no_vendible = sum(int(v.get("NoVendibleQty")   or 0) for v in rows_to_sum)
                # Fallback a TotalQty SOLO si BM no envió AvailableQTY (campo null).
                # No activar cuando AvailableQTY llegó como 0 genuino — ahí reserve puede
                # ser > 0 aunque no se vea, y asumir avail=total genera sobreventa.
                if avail == 0 and reserve == 0:
                    _all_avail_null = all(v.get("AvailableQTY") is None for v in rows_to_sum)
                    if _all_avail_null:
                        total = sum(int(v.get("TotalQty") or 0) for v in rows_to_sum)
                        if total > 0:
                            avail = total
                            _diag_fallback += 1
                if avail > 0:
                    _diag_found += 1
                else:
                    # BM confirmó explícitamente 0 (SKU en bulk, AvailableQTY=0)
                    _diag_zero_in_bulk += 1
                    if len(_diag_zero_in_bulk_skus) < 30:
                        _diag_zero_in_bulk_skus.append(fsku)
                return avail, reserve, no_vendible

            for _fsku in to_fetch:
                _fbase = normalize_to_bm_sku(_fsku)
                if not _fbase:
                    _store_empty(_fsku)
                    _prewarm_progress["done"] = _prewarm_progress.get("done", 0) + 1
                    continue
                # Usar el bulk correcto según las condiciones del SKU
                if _bm_conditions_for_sku(_fsku) == _BM_COND_ALL:
                    _avail, _res, _nvq = _lookup_diag(_exact_all, _by_base_all, _fbase, _fsku)
                else:
                    _avail, _res, _nvq = _lookup_diag(_exact_gr, _by_base_gr, _fbase, _fsku)
                # Bulk miss: NO llamar _store_wh — Fix A en _store_wh preservaría el valor
                # stale de DB (ej: 549 de era LOC62) porque la entrada vieja tiene _v=True.
                # Se retried per-SKU en _do_bulk_miss_retry() abajo.
                # BM no incluye SKUs con 0 stock en bulk → "no en bulk" ≠ "no en BM".
                if _fsku in _bulk_miss_set:
                    _prewarm_progress["done"] = _prewarm_progress.get("done", 0) + 1
                    continue
                # Encontrado en bulk: BM confirmó el valor (sea 0 o >0).
                _store_wh(_fsku, [], avail_direct=_avail, reserve_direct=_res,
                          no_vendible_direct=_nvq,
                          avail_ok=True, wh_responded=False)
                _prewarm_progress["done"] = _prewarm_progress.get("done", 0) + 1

            # Guardar estadísticas de cobertura para diagnóstico en Sync Stock
            global _bm_bulk_stats
            _diag_zero = _diag_zero_in_bulk + _diag_not_in_bulk  # total para compat UI
            _bm_bulk_stats = {
                "bulk_gr_rows":       len(_bulk_gr_rows)  if _bulk_gr_rows  else 0,
                "bulk_all_rows":      len(_bulk_all_rows) if _bulk_all_rows else 0,
                "skus_total":         len(to_fetch),
                "found":              _diag_found,
                "zero":               _diag_zero,
                "zero_in_bulk":       _diag_zero_in_bulk,
                "not_in_bulk":        _diag_not_in_bulk,
                "fallback_used":      _diag_fallback,
                "zero_skus":          _diag_not_in_bulk_skus,    # los que serán retried per-SKU
                "zero_in_bulk_skus":  _diag_zero_in_bulk_skus,   # BM confirmó 0 (no retried)
                "ts":                 _time.time(),
            }
            logger.info(f"[BM-BULK] Cobertura: {_diag_found}/{len(to_fetch)} con stock, "
                        f"{_diag_zero_in_bulk} BM confirmó 0, {_diag_not_in_bulk} no en bulk (retry per-SKU), "
                        f"{_diag_fallback} via TotalQty fallback")
            _used_bulk = True

            # ── Segunda pasada: MTY/CDMX/TJ desde bulks por ubicación ─────────
            # LOC47=CDMX, LOC68=MTY, LOC45+69+43+42=Tijuana. Usa GR per-location
            # para todos los SKUs. TJ agregado 2026-07-23 — antes quedaba en 0
            # siempre (dato vestigial, ver DEVLOG "zonas de almacén").
            if _bulk_loc47_rows is not None or _bulk_loc68_rows is not None or _bulk_loctj_rows is not None:
                _loc_exact47, _loc_base47 = _build_lookup(_bulk_loc47_rows or [])
                _loc_exact68, _loc_base68 = _build_lookup(_bulk_loc68_rows or [])
                _loc_exacttj, _loc_basetj = _build_lookup(_bulk_loctj_rows or [])
                _wh_updated = 0
                for _wh_sku in to_fetch:
                    _wh_bk = normalize_to_bm_sku(_wh_sku)
                    if _wh_bk.upper().startswith("SNTV"):
                        continue  # TV WH breakdown maneja SNTV* a T+180s con ICB/ICC conditions
                    _existing = _bm_stock_cache.get(_wh_bk)
                    if not _existing or not _existing[1].get("_v"):
                        continue  # solo actualizar entradas verificadas
                    _cdmx_avail, _ = _lookup(_loc_exact47, _loc_base47, _wh_bk)
                    _mty_avail,  _ = _lookup(_loc_exact68, _loc_base68, _wh_bk)
                    _tj_avail,   _ = _lookup(_loc_exacttj, _loc_basetj, _wh_bk)
                    _wh_ts, _wh_data = _existing
                    # Mutar _wh_data IN PLACE para que result_map (mismo objeto) también se actualice.
                    # Si se crea dict nuevo, result_map queda desactualizado y el template muestra "—".
                    _avail_total = _wh_data.get("avail_total", 0) or 0
                    _loc_sum = _mty_avail + _cdmx_avail + _tj_avail
                    if _loc_sum > _avail_total and _avail_total > 0:
                        _scale = _avail_total / _loc_sum
                        _mty_avail  = round(_mty_avail  * _scale)
                        _cdmx_avail = round(_cdmx_avail * _scale)
                        _tj_avail   = _avail_total - _mty_avail - _cdmx_avail
                    _wh_data["cdmx"] = _cdmx_avail
                    _wh_data["mty"]  = _mty_avail
                    _wh_data["tj"]   = _tj_avail
                    _wh_data["_wh_fetched"] = True
                    # No se necesita re-asignar _bm_stock_cache — _wh_data ya es el objeto referenciado.
                    _wh_updated += 1
                logger.info(f"[BM-WH] Desglose MTY/CDMX/TJ actualizado para {_wh_updated} SKUs desde LOC47/LOC68/LOC-TJ")

            # ── Reconciliación bulk-a-bulk: SKUs que desaparecieron del ciclo anterior ────────────
            # Compara el bulk actual vs el anterior para detectar SKUs que tenían stock y ya no
            # aparecen. Esos se agregan a _bulk_miss_set para que el retry per-SKU los verifique
            # y los actualice a 0 (nunca se borran del sistema — solo cambia la cantidad).
            global _bm_prev_bulk_sku_set
            _this_bulk_sku_set: set = set()
            for _recon_row in (_bulk_gr_rows or []) + (_bulk_all_rows or []):
                _recon_sk = normalize_to_bm_sku((_recon_row.get("SKU") or "").upper().strip())
                if _recon_sk:
                    _this_bulk_sku_set.add(_recon_sk)

            if _bm_prev_bulk_sku_set and _this_bulk_sku_set:
                _bm_key_to_ml_sku = {normalize_to_bm_sku(s): s for s in to_fetch if s}
                _miss_bm_keys     = {normalize_to_bm_sku(s) for s in _bulk_miss_set if s}
                _disappeared_bm   = (
                    _bm_prev_bulk_sku_set            # estaba en el bulk anterior
                    & set(_bm_key_to_ml_sku.keys())  # relevante para nuestros listings ML
                    - _this_bulk_sku_set             # ya no en el bulk actual
                    - _miss_bm_keys                  # no ya en la cola de misses
                )
                # Solo los que tenían stock previo (>0) — son los más urgentes de verificar.
                _extra_recon = [
                    _bm_key_to_ml_sku[_nk]
                    for _nk in _disappeared_bm
                    if (_bm_stock_cache.get(_nk, (0.0, {}))[1].get("avail_total") or 0) > 0
                    and _nk in _bm_key_to_ml_sku
                ][:30]
                if _extra_recon:
                    logger.info(f"[BM-RECON] {len(_extra_recon)} SKUs desaparecieron del bulk "
                                f"con stock previo — agregando al retry per-SKU para verificar")
                    for _rml in _extra_recon:
                        _bulk_miss_set.add(_rml)
                logger.info(f"[BM-RECON] Bulk diff: prev={len(_bm_prev_bulk_sku_set)}, "
                            f"actual={len(_this_bulk_sku_set)}, desaparecieron={len(_disappeared_bm)}")

            _bm_prev_bulk_sku_set = _this_bulk_sku_set

            # Retry per-SKU para bulk misses CON ts=0.0 (nunca verificados) O CON stale
            # avail_total>0 (tenían stock antes pero ya no están en el bulk → probablemente 0).
            # BM omite SKUs con stock=0 del bulk, así que "no en bulk" + "stale>0" = sospechoso.
            if retry_stale and _bulk_miss_set and not _bulk_returned_empty:
                _miss_list = [
                    s for s in _bulk_miss_set
                    if not normalize_to_bm_sku(s).upper().startswith("SNTV")  # TVs → _fetch_tv_wh_breakdown los maneja
                    and (
                        (_bm_stock_cache.get(normalize_to_bm_sku(s), (0.0, {}))[0]) == 0.0
                        or ((_bm_stock_cache.get(normalize_to_bm_sku(s), (0.0, {}))[1].get("avail_total") or 0) > 0)
                    )
                ][:50]
                if _miss_list:
                    async def _do_bulk_miss_retry(miss_skus=_miss_list):
                        import logging as _log_miss
                        _log_miss.getLogger(__name__).info(
                            f"[BM-BULK] Retry per-SKU para {len(miss_skus)} bulk misses (ts=0 o stale>0)"
                        )
                        await asyncio.sleep(5)
                        _db_updates = []
                        for _msku in miss_skus:
                            await _wh_phase(_msku, _track_progress=False)
                            _bk = normalize_to_bm_sku(_msku)
                            _bm_entry = _bm_stock_cache.get(_bk)
                            if _bm_entry:
                                # Siempre actualizar DB — avail puede ser 0 (BM confirmó sin stock)
                                # o >0 (tiene stock real). NUNCA borrar: los SKUs persisten en el
                                # sistema, solo cambia la cantidad. Si BM falló, Fix A en _store_wh
                                # preservó el valor anterior → guardamos ese valor sin sobrescribir.
                                _db_updates.append((_bk, _bm_entry[1], _bm_entry[0]))
                            else:
                                # Edge case: _wh_phase no pudo guardar en cache (raro).
                                # Actualizar DB a 0 explícito en lugar de borrar el SKU.
                                _db_updates.append((_bk, {
                                    "avail_total": 0, "reserved_total": 0, "mty": 0,
                                    "cdmx": 0, "tj": 0, "total": 0, "no_vendible": 0,
                                    "_v": False,
                                }, _time.time()))
                            await asyncio.sleep(1)
                        if _db_updates:
                            try:
                                await token_store.upsert_bm_stock_batch(_db_updates)
                                _n_zero = sum(1 for _, _d, _ in _db_updates
                                              if not (_d.get("avail_total") or 0))
                                _log_miss.getLogger(__name__).info(
                                    f"[BM-BULK] Bulk-miss retry: {len(_db_updates)} SKUs actualizados "
                                    f"({_n_zero} en 0, {len(_db_updates) - _n_zero} con stock)"
                                )
                            except Exception as _e_db:
                                _log_miss.getLogger(__name__).warning(f"[BM-BULK] Error upsert DB: {_e_db}")
                        _log_miss.getLogger(__name__).info(
                            f"[BM-BULK] Bulk-miss retry completado: {len(miss_skus)} SKUs"
                        )
                    asyncio.create_task(_do_bulk_miss_retry())

            # Lanzar desglose MTY/CDMX para TVs (SNTV*) como background task desacoplado.
            # Corre 180s después para no competir con _do_bulk_miss_retry y _fetch_activate_wh.
            # Solo si hay SKUs TV en este batch y no hay ya una instancia corriendo.
            if _need_all and not _bm_tv_loc_running:
                asyncio.create_task(_fetch_tv_wh_breakdown())
                logger.info("[BM-TV-WH] Task MTY/CDMX TVs lanzado (corre en 180s)")

        if not _used_bulk:
            # Fix B3: último recurso — servir desde _bm_stock_cache per-SKU aunque esté expirado.
            # Cuando ambos bulk fallan (stale también ausente), mejor datos viejos que result_map vacío.
            # result_map vacío → _apply_bm_stock no puede set _bm_avail → KPIs todos en 0.
            logger.warning(f"[BM-CACHE] Bulk falló — sirviendo _bm_stock_cache stale per-SKU para {len(to_fetch)} SKUs. Retry en próximo ciclo.")
            for _fsku in to_fetch:
                _fbase = normalize_to_bm_sku(_fsku)
                _stale_cached = _bm_stock_cache.get(_fbase)
                if _stale_cached:
                    result_map[_fsku] = _stale_cached[1]
    else:
        # Lote pequeño (≤30 SKUs): per-SKU directo sigue siendo eficiente
        await asyncio.gather(*[_wh_phase(s) for s in to_fetch], return_exceptions=True)

    # Fix C: retry serial para SKUs STALE — fire-and-forget para no bloquear prewarm ni Stock tab.
    # Solo en prewarm (retry_stale=True) Y solo cuando el bulk NO fue usado (fallback per-SKU).
    # Cuando el bulk corrió OK, SKUs no encontrados = genuinamente no en BM → sin retry necesario.
    # NUNCA cuando _bulk_returned_empty: si BM respondió pero devolvió vacío, las queries
    # individuales también van a fallar → evitar el ciclo de 200+ segundos de hits a BM.
    if retry_stale and not _used_bulk and not _bulk_returned_empty:
        _stale_after_prewarm = [
            s for s in to_fetch
            if not _bm_stock_cache.get(normalize_to_bm_sku(s), (None, {}))[1].get("_v")
        ]
        _stale_to_retry = _stale_after_prewarm[:100]
        if _stale_to_retry:
            async def _do_stale_retry(_skus=_stale_to_retry):
                import logging as _log_retry
                _log_retry.getLogger(__name__).info(
                    f"[BM-CACHE] Retry serial BG: {len(_skus)} SKUs STALE — esperando 10s para sesión BM"
                )
                # Esperar 10s: deja que la sesión BM se estabilice tras el parallel prewarm
                # y que el prewarm de la próxima cuenta no compita con estos retries.
                await asyncio.sleep(10)
                for _retry_sku in _skus:
                    await _wh_phase(_retry_sku, _track_progress=False)
                    # 2s entre retries: breathing room para BM — evita saturar la sesión
                    await asyncio.sleep(2)
                _log_retry.getLogger(__name__).info(
                    f"[BM-CACHE] Retry serial BG completado: {len(_skus)} SKUs procesados"
                )
            asyncio.create_task(_do_stale_retry())

    # Post-fetch pass: llenar result_map para SKUs que fueron deduplicados (bm_key ya en
    # _seen_bm_keys pero result_map nunca se pobló). Ahora el cache sí tiene el dato.
    # Ejemplo: "SNTV007270-GRA" fue el SKU fetcheado; "SNTV007270 NEW" del mismo prewarm
    # fue omitido de to_fetch (misma bm_key) → aquí se sirve del cache.
    # IMPORTANTE: excluir bulk-miss SKUs — el post-fetch pass NO debe agregar datos stale
    # de SKUs que el bulk no encontró (ej: SHIL000026 con 545 stale). El retry per-SKU
    # los corregirá. Sin esta exclusión, el dato stale reaparece en result_map aunque
    # el bulk confirmó que no están en LOC47+68.
    _pf_miss_filtered = 0
    for p in products:
        sku = p.get(sku_key, "")
        if not sku or sku in result_map:
            continue
        if sku in _bulk_miss_set:
            _pf_miss_filtered += 1
            continue  # bulk miss: esperar al retry per-SKU, no agregar stale data
        bm_key = normalize_to_bm_sku(sku)
        cached = _bm_stock_cache.get(bm_key)
        if cached and _cache_is_valid(cached):
            result_map[sku] = cached[1]
    if _pf_miss_filtered:
        logger.info(f"[BM-POSTFETCH] {_pf_miss_filtered} bulk-miss SKUs filtrados (stale guard activo)")
    # Lo mismo para variaciones
    for p in products:
        if not p.get("has_variations"):
            continue
        for v in p.get("variations", []):
            v_sku = v.get("sku", "")
            if not v_sku or v_sku in result_map:
                continue
            if v_sku in _bulk_miss_set:
                continue
            v_bm_key = normalize_to_bm_sku(v_sku)
            cached = _bm_stock_cache.get(v_bm_key)
            if cached and _cache_is_valid(cached):
                result_map[v_sku] = cached[1]

    # Persistir nuevas entradas BM a DB (fire-and-forget — no bloquea la respuesta)
    if to_fetch:
        now_ts = _time.time()
        entries_to_persist = []
        for _sku in to_fetch:
            _bm_key = normalize_to_bm_sku(_sku)
            cached = _bm_stock_cache.get(_bm_key)
            if cached:
                entries_to_persist.append((_sku, cached[1], cached[0]))
        if entries_to_persist:
            async def _persist_bm():
                try:
                    await token_store.upsert_bm_stock_batch(entries_to_persist)
                except Exception as _e:
                    import logging as _log
                    _log.getLogger(__name__).debug(f"[BM-DB] persist error: {_e}")
            asyncio.create_task(_persist_bm())

    return result_map


def _dist_apply_pool(
    pool: int,
    bm_sku: str,
    units_30d: int,
    dist_rule: dict | None,
    dist_settings: dict | None,
    sold_history: dict | None,
) -> tuple[int, float]:
    """Aplica la regla de distribución de cuenta al pool BM disponible.

    Retorna (pool_ajustado, days_supply).
    - Si dist_rule es None → devuelve pool sin cambios (comportamiento legacy).
    - Aplica safety_buffer antes de calcular el %, pool nunca baja de 0.
    - En modo escasez, si la cuenta tiene scarce_enabled=False pero tiene
      historial de ventas del SKU → se habilita con mínimo 20%.
    """
    if not dist_rule or not dist_settings:
        return pool, 9999.0

    buffer = int(dist_settings.get("safety_buffer_units", 2))
    effective = max(0, pool - buffer)

    threshold_units = int(dist_settings.get("scarce_threshold_units", 10))
    threshold_days  = int(dist_settings.get("scarce_threshold_days", 7))
    daily_rate = (units_30d or 0) / 30.0
    days_supply = effective / daily_rate if daily_rate > 0 else 9999.0

    is_scarce = effective < threshold_units or days_supply < threshold_days

    if is_scarce:
        if not dist_rule.get("scarce_enabled", True):
            has_history = bool(sold_history and sold_history.get(bm_sku, 0) > 0)
            if not has_history:
                return 0, days_supply
            pct = max(0.2, float(dist_rule.get("pct_scarce", 0.0)))
        else:
            pct = float(dist_rule.get("pct_scarce", 1.0))
    else:
        pct = float(dist_rule.get("pct_full", 1.0))

    return max(0, int(effective * pct)), days_supply


def _apply_bm_stock(
    products: list,
    bm_map: dict,
    sku_key: str = "sku",
    dist_rule: dict | None = None,
    dist_settings: dict | None = None,
    sold_history: dict | None = None,
):
    """Aplica datos de stock BM a la lista de productos.
    _bm_avail    = disponible real ajustado por regla de distribución de cuenta.
    _bm_reserved = unidades reservadas (Required en BM).
    _bm_total    = stock físico total (incluye reservados) — solo para referencia.
    _days_supply = días de supply estimados (stock / ventas diarias).
    _is_scarce   = True si el SKU está en modo escasez para esta cuenta.
    """
    for p in products:
        _units_30d = p.get("units_30d", 0) or 0
        if p.get("has_variations"):
            any_var_sku = False
            # Group variations by their normalized BM key to avoid double-counting
            # when multiple ML variations map to the same BM SKU.
            from collections import defaultdict as _dd
            _bm_key_vars: dict = _dd(list)  # bm_key → [variation_dicts]
            for v in p.get("variations", []):
                v_sku = v.get("sku", "")
                if v_sku:
                    any_var_sku = True
                _bk = normalize_to_bm_sku(v_sku) if v_sku else ""
                _bm_key_vars[_bk].append(v)

            tot_mty = tot_cdmx = tot_tj = tot_avail = tot_reserved = tot_no_vendible = 0
            tot_avail_raw = 0  # raw BM total (pre-distribution) for display
            _any_inv_found = False  # Fix B4: rastrear si al menos una variación tuvo dato BM real
            _p_days_supply = 9999.0
            for _bk, _vars in _bm_key_vars.items():
                # Look up BM data: try each variation's raw SKU until we find a match
                inv = None
                if _bk:
                    for _v in _vars:
                        inv = bm_map.get(_v.get("sku", ""))
                        if inv:
                            break
                if inv:
                    _any_inv_found = True
                    _n = len(_vars)
                    _pool_raw = inv.get("avail_total", 0)
                    tot_avail_raw += _pool_raw
                    # units_30d para este BM key: suma sold_quantity de sus variaciones
                    # (sold_quantity es lifetime ML, buen proxy de popularidad relativa).
                    # Fallback: prorratear el total del padre si no hay dato de variación.
                    _var_sold_qtys = [int(v.get("sold_quantity") or 0) for v in _vars]
                    _var_units_30d_key = sum(_var_sold_qtys) or (_units_30d // max(len(_bm_key_vars), 1))
                    _pool, _ds = _dist_apply_pool(_pool_raw, _bk, _var_units_30d_key, dist_rule, dist_settings, sold_history)
                    _p_days_supply = min(_p_days_supply, _ds)
                    # Distribuir pool proporcionalmente por sold_quantity de cada variación.
                    # Si todas tienen 0 (listing nuevo), caer a split equitativo.
                    _total_sold = sum(_var_sold_qtys)
                    # Deduplicated parent totals — add once per unique BM key
                    tot_mty += inv["mty"]
                    tot_cdmx += inv["cdmx"]
                    tot_tj += inv["tj"]
                    tot_avail += _pool
                    tot_reserved += inv.get("reserved_total", 0)
                    tot_no_vendible += inv.get("no_vendible", 0)
                    _assigned = 0
                    for i, v in enumerate(_vars):
                        v["_bm_total"] = inv["total"] // _n if _n > 1 else inv["total"]
                        if _total_sold > 0:
                            # Proporcional: cada variación recibe su cuota según ventas históricas
                            _share = round(_pool * _var_sold_qtys[i] / _total_sold)
                            # Última variación absorbe el resto para no perder unidades por redondeo
                            v["_bm_avail"] = (_pool - _assigned) if i == _n - 1 else _share
                            _assigned += _share
                        else:
                            # Split equitativo para listings nuevos sin historial
                            _quot, _rem = divmod(_pool, _n)
                            v["_bm_avail"] = _quot + (1 if i == 0 and _rem else 0)
                        v["_bm_reserved"] = inv.get("reserved_total", 0) // _n
                else:
                    for v in _vars:
                        v["_bm_total"] = 0
                        v["_bm_avail"] = 0
                        v["_bm_reserved"] = 0

            # Fix B4: solo asignar _bm_avail al padre si al menos una variación tuvo dato BM real.
            # Sin esta guarda, _apply_bm_stock asigna _bm_avail=0 cuando bm_map está vacío (bulk falló),
            # lo cual hace que el filtro oversell_risk (que usa `"_bm_avail" in p` como guarda) genere
            # falsos positivos — productos con available_quantity>0 aparecen como riesgo de sobreventa.
            if any_var_sku and _any_inv_found:
                p["_bm_mty"] = tot_mty
                p["_bm_cdmx"] = tot_cdmx
                p["_bm_tj"] = tot_tj
                p["_bm_total"] = tot_mty + tot_cdmx + tot_tj
                p["_bm_avail"] = tot_avail
                p["_bm_avail_raw"] = tot_avail_raw
                p["_bm_reserved"] = tot_reserved
                p["_bm_no_vendible"] = tot_no_vendible
                p["_bm_wh_fetched"] = any(
                    bm_map.get(v.get("sku", ""), {}).get("_wh_fetched") for v in p.get("variations", [])
                )
                p["_days_supply"] = round(_p_days_supply, 1) if _p_days_supply < 9999 else None
                p["_is_scarce"] = dist_rule is not None and (
                    tot_avail_raw < int((dist_settings or {}).get("scarce_threshold_units", 10))
                    or (_p_days_supply < int((dist_settings or {}).get("scarce_threshold_days", 7)))
                )
            else:
                inv = bm_map.get(p.get(sku_key))
                if inv:
                    _pool_raw = inv.get("avail_total", 0)
                    _bk = normalize_to_bm_sku(p.get(sku_key, ""))
                    _pool, _ds = _dist_apply_pool(_pool_raw, _bk, _units_30d, dist_rule, dist_settings, sold_history)
                    p["_bm_mty"] = inv["mty"]
                    p["_bm_cdmx"] = inv["cdmx"]
                    p["_bm_tj"] = inv["tj"]
                    # inv["total"] es el warehouse_total calculado al crear la entrada (siempre
                    # 0 — rows_wh viene vacío); mty/cdmx/tj se actualizan DESPUÉS in-place vía
                    # la segunda pasada del prewarm, así que hay que sumarlos aquí, no leer "total".
                    p["_bm_total"] = inv["mty"] + inv["cdmx"] + inv["tj"]
                    p["_bm_avail"] = _pool
                    p["_bm_avail_raw"] = _pool_raw
                    p["_bm_reserved"] = inv.get("reserved_total", 0)
                    p["_bm_no_vendible"] = inv.get("no_vendible", 0)
                    p["_bm_wh_fetched"] = inv.get("_wh_fetched", False)
                    p["_days_supply"] = round(_ds, 1) if _ds < 9999 else None
                    p["_is_scarce"] = dist_rule is not None and (
                        _pool_raw < int((dist_settings or {}).get("scarce_threshold_units", 10))
                        or (_ds < int((dist_settings or {}).get("scarce_threshold_days", 7)))
                    )
        else:
            inv = bm_map.get(p.get(sku_key))
            if inv:
                _pool_raw = inv.get("avail_total", 0)
                _bk = normalize_to_bm_sku(p.get(sku_key, ""))
                _pool, _ds = _dist_apply_pool(_pool_raw, _bk, _units_30d, dist_rule, dist_settings, sold_history)
                p["_bm_mty"] = inv["mty"]
                p["_bm_cdmx"] = inv["cdmx"]
                p["_bm_tj"] = inv["tj"]
                p["_bm_total"] = inv["mty"] + inv["cdmx"] + inv["tj"]
                p["_bm_avail"] = _pool
                p["_bm_avail_raw"] = _pool_raw
                p["_bm_reserved"] = inv.get("reserved_total", 0)
                p["_bm_no_vendible"] = inv.get("no_vendible", 0)
                p["_bm_wh_fetched"] = inv.get("_wh_fetched", False)
                p["_days_supply"] = round(_ds, 1) if _ds < 9999 else None
                p["_is_scarce"] = dist_rule is not None and (
                    _pool_raw < int((dist_settings or {}).get("scarce_threshold_units", 10))
                    or (_ds < int((dist_settings or {}).get("scarce_threshold_days", 7)))
                )


def _enrich_sku_from_orders(products: list, orders: list):
    """Enriquece SKU de productos desde ordenes (fallback para items sin SKU en datos)."""
    sku_map = {}
    for order in orders:
        for oi in order.get("order_items", []):
            it = oi.get("item", {})
            raw_sku = it.get("seller_sku") or it.get("seller_custom_field") or ""
            if raw_sku and it.get("id"):
                base = normalize_to_bm_sku(raw_sku)
                existing = sku_map.get(it["id"], "")
                if not existing or len(base) < len(existing):
                    sku_map[it["id"]] = base
    for p in products:
        if not p.get("sku") and p["id"] in sku_map:
            p["sku"] = sku_map[p["id"]]


def _get_var_sku(v: dict) -> str:
    """Extrae SKU de una variación (seller_custom_field o SELLER_SKU attribute)."""
    v_sku = v.get("seller_custom_field") or ""
    if not v_sku or v_sku == "None":
        v_sku = ""
        for va in v.get("attributes", []):
            if va.get("id") == "SELLER_SKU" and va.get("value_name"):
                v_sku = va["value_name"]
                break
    return v_sku


def _build_product_list(bodies: list, sales_map: dict = None) -> list[dict]:
    """Construye lista de productos desde item bodies con SKU y ventas."""
    products = []
    for body in bodies:
        iid = body.get("id", "")
        if not iid:
            continue
        sku = _get_item_sku(body)
        shipping = body.get("shipping", {})

        # Para items con variaciones, mostrar la suma de stock de TODAS las variaciones
        # en la fila del parent. Cada variacion tiene su stock independiente en MeLi.
        # El parent.available_quantity puede ser 0 aunque una variacion tenga stock
        # (comportamiento FULL donde cada variacion es independiente).
        raw_vars = body.get("variations", [])
        avail_qty = body.get("available_quantity", 0)
        if raw_vars and len(raw_vars) > 1:
            # Sumar stock de todas las variaciones — refleja la realidad del listing
            avail_qty = sum(v.get("available_quantity", 0) for v in raw_vars)

        p = {
            "id": iid,
            "title": body.get("title", ""),
            "thumbnail": body.get("thumbnail", ""),
            "price": body.get("price", 0),
            "original_price": body.get("original_price"),
            "available_quantity": avail_qty,
            "sku": sku,
            "permalink": body.get("permalink", ""),
            "pictures_count": len(body.get("pictures", [])),
            "has_video": body.get("video_id") is not None,
            "category_id": body.get("category_id", ""),
            "status": body.get("status", "active"),
            "is_full": shipping.get("logistic_type", "") == "fulfillment",
            "catalog_listing": bool(body.get("catalog_listing")),
        }
        if sales_map:
            s = sales_map.get(iid, {"units": 0, "revenue": 0, "fees": 0})
            p["units"] = s["units"]
            p["units_30d"] = s["units"]
            p["revenue"] = s["revenue"]
            p["revenue_30d"] = s["revenue"]
            p["fees"] = s.get("fees", 0)
        else:
            p["units_30d"] = 0
            p["revenue_30d"] = 0

        # Extraer variaciones si hay mas de 1
        if len(raw_vars) > 1:
            variations = []
            for v in raw_vars:
                v_sku = _get_var_sku(v)
                combos = []
                for ac in v.get("attribute_combinations", []):
                    combos.append(f"{ac.get('name', '')}: {ac.get('value_name', '')}")
                variations.append({
                    "id": v.get("id", ""),
                    "sku": v_sku,
                    "stock": v.get("available_quantity", 0),
                    "price": v.get("price", p["price"]),
                    "combo": ", ".join(combos) if combos else f"Var {v.get('id', '')}",
                })
            p["variations"] = variations
            p["has_variations"] = True

        products.append(p)
    return products


async def _enrich_category_names(client, products: list):
    """Resuelve category_id -> nombre legible. Usa cache permanente."""
    cat_ids = set()
    for p in products:
        cid = p.get("category_id", "")
        if cid and cid not in _category_cache:
            cat_ids.add(cid)
    if cat_ids:
        sem = asyncio.Semaphore(10)
        async def _fetch_cat(cid):
            async with sem:
                try:
                    data = await client.get(f"/categories/{cid}")
                    return cid, data.get("name", cid)
                except Exception:
                    return cid, cid
        results = await asyncio.gather(*[_fetch_cat(c) for c in cat_ids])
        for cid, name in results:
            _category_cache[cid] = name
    for p in products:
        cid = p.get("category_id", "")
        p["category_name"] = _category_cache.get(cid, cid)


async def _enrich_variation_skus(client, products: list):
    """Para items con variaciones sin SKU, fetcha datos individuales para obtener SELLER_SKU."""
    # Identificar items que tienen variaciones con SKU vacios
    needs_fetch = []
    for p in products:
        vars_list = p.get("variations")
        if not vars_list:
            continue
        has_empty = any(not v.get("sku") for v in vars_list)
        if has_empty:
            needs_fetch.append(p["id"])

    if not needs_fetch:
        return

    # Limitar a 20 items para no sobrecargar
    needs_fetch = needs_fetch[:20]
    sem = asyncio.Semaphore(5)

    async def _fetch(item_id):
        async with sem:
            try:
                data = await client.get(f"/items/{item_id}")
                return item_id, data
            except Exception:
                return item_id, None

    results = await asyncio.gather(*[_fetch(iid) for iid in needs_fetch], return_exceptions=True)

    # Mapear variaciones actualizadas
    var_sku_map = {}  # {item_id: {var_id: sku}}
    for r in results:
        if isinstance(r, Exception) or r is None:
            continue
        iid, data = r
        if not data or not isinstance(data, dict):
            continue
        for v in data.get("variations", []):
            vid = v.get("id")
            if not vid:
                continue
            v_sku = v.get("seller_custom_field") or ""
            if not v_sku or v_sku == "None":
                v_sku = ""
                for va in v.get("attributes", []):
                    if va.get("id") == "SELLER_SKU" and va.get("value_name"):
                        v_sku = va["value_name"]
                        break
            if v_sku:
                var_sku_map.setdefault(iid, {})[str(vid)] = v_sku

    # Aplicar SKUs encontrados
    for p in products:
        iid = p["id"]
        if iid not in var_sku_map:
            continue
        for v in p.get("variations", []):
            if not v.get("sku"):
                v["sku"] = var_sku_map[iid].get(str(v["id"]), "")


async def _get_page_reviews(client, products: list):
    """Fetcha ratings/reseñas para todos los items de la página en paralelo. Modifica products in-place."""
    sem = asyncio.Semaphore(5)

    async def _fetch(p):
        async with sem:
            rv = await client.get_item_reviews(p["id"], limit=1)
            if isinstance(rv, dict) and rv:
                p["_rating"] = rv.get("rating_average") or rv.get("data", {}).get("rating_average") or 0
                p["_rating_count"] = rv.get("paging", {}).get("total") or rv.get("total") or 0
            else:
                p["_rating"] = None
                p["_rating_count"] = 0

    await asyncio.gather(*[_fetch(p) for p in products], return_exceptions=True)


async def _get_page_purchase_experience(client, products: list):
    """Fetcha purchase_experience por item — detecta listings penalizados. Modifica products in-place."""
    sem = asyncio.Semaphore(5)

    async def _fetch(p):
        async with sem:
            data = await client.get_purchase_experience(p["id"])
            if isinstance(data, dict):
                p["_px_status"] = data.get("status", "")
                p["_px_penalized"] = data.get("status", "").upper() == "PENALIZED"
                penalties = data.get("penalties", [])
                p["_px_penalties"] = [pen.get("type", "") for pen in penalties if isinstance(pen, dict)]
            else:
                p["_px_status"] = ""
                p["_px_penalized"] = False
                p["_px_penalties"] = []

    await asyncio.gather(*[_fetch(p) for p in products], return_exceptions=True)


# Cache para highlights por categoría — TTL 24h (se actualiza semanalmente)
_highlights_cache: dict = {}
_HIGHLIGHTS_TTL = 86400


async def _get_best_sellers_for_page(client, products: list):
    """Fetcha bestsellers de cada categoría única en la página. Marca _is_bestseller en los items del top 20."""
    cat_ids = list({p.get("category_id", "") for p in products if p.get("category_id")})
    if not cat_ids:
        return

    bestseller_ids: set = set()
    now = _time.time()

    async def _fetch_cat(cat_id):
        cached = _highlights_cache.get(cat_id)
        if cached and (now - cached[0]) < _HIGHLIGHTS_TTL:
            return cached[1]
        items = await client.get_category_highlights(cat_id)
        id_set = {i.get("id", "") for i in items if isinstance(i, dict) and i.get("id")}
        _highlights_cache[cat_id] = (now, id_set)
        return id_set

    results = await asyncio.gather(*[_fetch_cat(c) for c in cat_ids], return_exceptions=True)
    for r in results:
        if isinstance(r, set):
            bestseller_ids.update(r)

    for p in products:
        p["_is_bestseller"] = p["id"] in bestseller_ids


# ---------- Product Intelligence tabs ----------

@app.post("/api/cache/invalidate-products")
async def invalidate_products_cache():
    """Invalida cache de productos para forzar re-fetch desde MeLi."""
    cleared = 0
    for cache in (_products_cache, _orders_cache, _sale_price_cache):
        cleared += len(cache)
        cache.clear()
    return {"ok": True, "cleared": cleared}


@app.get("/partials/products-inventory", response_class=HTMLResponse)
async def products_inventory_partial(
    request: Request,
    preset: str = "all",
    search: str = "",
    sort_by: str = "",
    enrich: str = "basic",
    full_filter: str = "all",
    page: int = 1,
    per_page: int = 20,
    alert_days: int = 30,
):
    """Tab Inventario unificado: reemplaza all/top/stock/low/full."""
    from datetime import datetime, timedelta
    client = await get_meli_client()
    if not client:
        return HTMLResponse("<p>Error: No autenticado</p>")
    try:
        now = datetime.utcnow()
        days = max(7, min(alert_days, 90))
        date_from = (now - timedelta(days=days)).strftime("%Y-%m-%d")
        date_to = now.strftime("%Y-%m-%d")

        # Fase 1: fetch paralelo (products + orders)
        # include_paused=True (active+paused) — misma clave que usa el prewarm,
        # por lo que el prewarm ya calienta este cache y la respuesta es instantanea.
        # include_all=True traía closed/inactive/under_review → key diferente → siempre frío.
        all_bodies, all_orders = await asyncio.gather(
            _get_all_products_cached(client, include_paused=True),
            _get_orders_cached(client, date_from, date_to),
        )
        sales_map = _aggregate_sales_by_item(all_orders)
        products = _build_product_list(all_bodies, sales_map)
        _enrich_sku_from_orders(products, all_orders)

        # --- Apply CACHED BM stock (instant, no API calls) ---
        # Only use whatever is already in the BM cache from prewarm/previous loads
        # Entries with total=0 AND avail=0 (EMPTY) are skipped — will be re-fetched per page
        for p in products:
            sku = p.get("sku", "")
            if sku:
                cached = _bm_stock_cache.get(normalize_to_bm_sku(sku))
                if cached and (_time.time() - cached[0]) < _BM_CACHE_TTL:
                    data = cached[1]
                    p["_bm_total"] = data.get("total", 0)
                    p["_bm_mty"] = data.get("mty", 0)
                    p["_bm_cdmx"] = data.get("cdmx", 0)
                    p["_bm_tj"] = data.get("tj", 0)
                    p["_bm_avail"] = data.get("avail_total", 0)
                    p["_bm_reserved"] = data.get("reserved_total", 0)
                    p["_bm_has_data"] = True

        # Recomendaciones
        for p in products:
            recs = []
            if p["pictures_count"] < 6:
                recs.append("Agregar mas fotos (minimo 8)")
            if not p["has_video"]:
                recs.append("Agregar video al listado")
            if p["available_quantity"] == 0:
                recs.append("Reponer stock para no perder posicionamiento")
            if p.get("units", 0) == 0 and p["available_quantity"] > 0:
                recs.append("Candidato para deal/promocion")
            p["recommendations"] = recs

        # --- Stock alerts from cached BM data (no waiting) ---
        # Muestra items con ventas, sin stock MeLi, y BM disponible>0 para alertar al usuario
        _sa_synced = await token_store.get_recently_synced_ids(str(client.user_id), ttl_seconds=3600)
        stock_alerts = [
            p for p in products
            if p.get("units", 0) > 0
            and p.get("available_quantity", 0) == 0
            and (p.get("_bm_avail") or 0) > 0  # tiene stock disponible (excluye reservados)
            and p.get("id") not in _sa_synced
        ]
        stock_alerts.sort(key=lambda x: x.get("units", 0), reverse=True)

        # --- Filtrado por preset ---
        if preset == "top":
            products = [p for p in products if p.get("units", 0) > 0]
        elif preset == "stock":
            products = [p for p in products if p.get("_bm_avail", 0) > 0]
        elif preset == "low":
            products = [p for p in products if p.get("units", 0) <= 2]
        elif preset == "full":
            products = [p for p in products if p.get("is_full")]
        elif preset == "full_candidates":
            # Listings que NO están en FULL pero venden bien y tienen stock
            products = [
                p for p in products
                if not p.get("is_full")
                and p.get("available_quantity", 0) > 0
                and p.get("units", 0) > 2
                and p.get("sku")
            ]
            products.sort(key=lambda x: x.get("units", 0), reverse=True)
        elif preset == "no_stock":
            products = [p for p in products if p.get("available_quantity", 0) == 0]
        elif preset == "accion":
            # Vista unificada de urgencia: sobreventa + sin stock + stock crítico
            THRESHOLD = 10
            if enrich != "full":
                enrich = "full"  # siempre enriquecido para mostrar costos y márgenes
            risk_ids = {
                p["id"] for p in products
                if p.get("available_quantity", 0) > 0
                and (p.get("_bm_avail") or 0) == 0
                and not p.get("is_full")
                and p.get("sku")
            }
            restock_ids = {
                p["id"] for p in products
                if p.get("available_quantity", 0) == 0
                and (p.get("_bm_avail") or 0) > 0
                and p.get("units", 0) > 0
            }
            critical_ids = {
                p["id"] for p in products
                if p.get("available_quantity", 0) > 0
                and 0 < (p.get("_bm_avail") or 0) <= THRESHOLD
                and not p.get("is_full")
                and p.get("sku")
                and p["id"] not in risk_ids
            }
            for p in products:
                pid = p["id"]
                if pid in risk_ids:
                    p["_urgency"] = "risk"
                elif pid in restock_ids:
                    p["_urgency"] = "restock"
                elif pid in critical_ids:
                    p["_urgency"] = "critical"
            products = [p for p in products if p.get("_urgency")]
            _urg_order = {"risk": 0, "restock": 1, "critical": 2}
            products.sort(key=lambda x: (_urg_order[x.get("_urgency", "critical")], -x.get("units", 0)))

        # Filtro FULL adicional
        if full_filter == "full":
            products = [p for p in products if p.get("is_full")]
        elif full_filter == "not_full":
            products = [p for p in products if not p.get("is_full")]

        # Busqueda por texto (incluye SKUs de variaciones)
        # Ademas busca directamente en MeLi API para encontrar items que no esten en cache
        if search and search.strip():
            q = search.strip().lower()

            # 1. Busqueda directa en MeLi API por seller_sku y keyword
            existing_ids = {p["id"] for p in products}
            extra_ids = set()
            try:
                # Buscar por seller_sku (mas preciso)
                sku_results = await client.get(
                    f"/users/{client.user_id}/items/search",
                    params={"seller_sku": search.strip(), "limit": 50},
                )
                for rid in sku_results.get("results", []):
                    if rid not in existing_ids:
                        extra_ids.add(rid)
                # Buscar por keyword (titulo, etc)
                kw_results = await client.get(
                    f"/users/{client.user_id}/items/search",
                    params={"q": search.strip(), "limit": 50},
                )
                for rid in kw_results.get("results", []):
                    if rid not in existing_ids:
                        extra_ids.add(rid)
            except Exception:
                pass

            # 2. Fetch detalles de items extra encontrados
            if extra_ids:
                extra_list = list(extra_ids)
                sem = asyncio.Semaphore(5)
                async def _fbatch(ids):
                    async with sem:
                        try:
                            return await client.get_items_details(ids)
                        except Exception:
                            return []
                batches = [extra_list[i:i+20] for i in range(0, len(extra_list), 20)]
                batch_results = await asyncio.gather(*[_fbatch(b) for b in batches])
                extra_bodies = [b for br in batch_results for b in br]
                extra_products = _build_product_list(extra_bodies, sales_map)
                _enrich_sku_from_orders(extra_products, all_orders)
                # Aplicar BM cache
                for p in extra_products:
                    sku_val = p.get("sku", "")
                    if sku_val:
                        cached = _bm_stock_cache.get(normalize_to_bm_sku(sku_val))
                        if cached and (_time.time() - cached[0]) < _BM_CACHE_TTL:
                            bm_data = cached[1]
                            p["_bm_total"] = bm_data.get("total", 0)
                            p["_bm_mty"] = bm_data.get("mty", 0)
                            p["_bm_cdmx"] = bm_data.get("cdmx", 0)
                            p["_bm_tj"] = bm_data.get("tj", 0)
                            p["_bm_avail"] = bm_data.get("avail_total", 0)
                            p["_bm_reserved"] = bm_data.get("reserved_total", 0)
                            p["_bm_has_data"] = True
                products.extend(extra_products)
                existing_ids.update(extra_ids)

            # 3. Filtrar por texto
            def _matches(p):
                if q in p.get("id", "").lower():
                    return True
                if q in (p.get("sku") or "").lower():
                    return True
                if q in p.get("title", "").lower():
                    return True
                for v in p.get("variations", []):
                    if q in (v.get("sku") or "").lower():
                        return True
                return False
            products = [p for p in products if _matches(p)]

        total_count = len(products)

        # Ordenamiento
        if not sort_by:
            sort_by = {
                "top": "units_desc",
                "stock": "bm_desc",
                "low": "stock_desc",
                "full": "stock_desc",
                "no_stock": "units_desc",
            }.get(preset, "stock_desc")

        field, direction = (sort_by.rsplit("_", 1) + ["desc"])[:2]
        reverse = direction == "desc"
        sort_keys = {
            "stock": lambda p: p.get("available_quantity", 0),
            "units": lambda p: p.get("units", 0),
            "bm": lambda p: p.get("_bm_avail", 0),
            "price": lambda p: p.get("price", 0),
            "revenue": lambda p: p.get("revenue", 0),
            "margin": lambda p: p.get("_margen_pct") if p.get("_margen_pct") is not None else -999,
            "photos": lambda p: p.get("pictures_count", 0),
        }
        products.sort(key=sort_keys.get(field, sort_keys["stock"]), reverse=reverse)

        # --- Pagination ---
        from math import ceil
        if per_page <= 0:
            per_page = 20
        if per_page >= total_count:
            total_pages = 1
            page = 1
            page_products = products
        else:
            total_pages = max(1, ceil(total_count / per_page))
            page = max(1, min(page, total_pages))
            start = (page - 1) * per_page
            page_products = products[start:start + per_page]

        # --- Trigger background BM prefetch para candidatos (non-blocking) ---
        # Solo productos con ventas o stock (no todos los 6000+) para no timeout.
        _bg_key = f"bm_bg:{client.user_id}"
        if _bg_key not in _bm_stock_cache:
            _bm_stock_cache[_bg_key] = (_time.time(), {})
            _bg_candidates = [
                p for p in products
                if p.get("sku") and (p.get("units", 0) > 0 or p.get("available_quantity", 0) > 0 or p.get("is_full"))
            ]
            asyncio.ensure_future(_get_bm_stock_cached(_bg_candidates))

        # --- Enrich ONLY page products ---
        # ORDEN CRITICO: variation SKUs deben popularse ANTES del BM fetch.
        # Si corren en paralelo, _get_bm_stock_cached ve variaciones sin SKU y solo
        # fetcha el padre. Luego _apply_bm_stock ve variaciones con SKU (enriquecidas)
        # pero bm_map no tiene esos SKUs específicos → BM=0 para todos con variaciones.
        usd_to_mxn = 0.0
        page_ids = [p["id"] for p in page_products]

        # Paso 1: SKUs de variaciones (debe terminar antes del BM fetch)
        await _enrich_variation_skus(client, page_products)

        # Paso 2: BM + precios + visitas en paralelo (variaciones ya tienen SKU correcto)
        parallel_tasks = [
            _get_bm_stock_cached(page_products),       # [0] bm_map
            _get_sale_prices_cached(client, page_ids), # [1] sale_prices
            client.get_items_visits_bulk(page_ids),    # [2] visits_map (CVR)
        ]
        if enrich == "full":
            parallel_tasks.append(_enrich_with_bm_product_info(page_products))  # [3]
            parallel_tasks.append(_get_usd_to_mxn(client))                      # [4]
            parallel_tasks.append(_get_page_reviews(client, page_products))     # [5] in-place

        enrich_results = await asyncio.gather(*parallel_tasks)
        bm_map = enrich_results[0]
        sale_prices = enrich_results[1]
        visits_map = enrich_results[2] if isinstance(enrich_results[2], dict) else {}

        _apply_bm_stock(page_products, bm_map)
        _bundles_pp = await token_store.get_all_bundles()
        _apply_bundle_stock_override(page_products, _bundles_pp)

        # Calcular CVR (Conversion Rate) = unidades vendidas / visitas * 100
        for p in page_products:
            visits = visits_map.get(p["id"], 0) or 0
            units = p.get("units", 0) or 0
            p["_visits_30d"] = visits
            p["_cvr"] = round(units / visits * 100, 1) if visits > 0 else None

        if enrich == "full":
            usd_to_mxn = enrich_results[4] if len(enrich_results) > 4 else 0.0
            _calc_margins(page_products, usd_to_mxn)
            _apply_bundle_margin_override(page_products, _bundles_pp)
            # Purchase experience (penalizaciones) + Best sellers — enrich=full only
            await asyncio.gather(
                _get_page_purchase_experience(client, page_products),
                _get_best_sellers_for_page(client, page_products),
                return_exceptions=True,
            )

        for p in page_products:
            sp = sale_prices.get(p["id"])
            if sp:
                p["original_price"] = sp["regular_amount"]
                p["price"] = sp["amount"]
                p["_has_deal"] = True
            else:
                p["_has_deal"] = False

        # --- Enrich alerts with estimated lost revenue ---
        for a in stock_alerts:
            units = a.get("units", 0)
            price = a.get("price", 0)
            d = alert_days or 30
            daily_avg = units / d if d > 0 else 0
            a["_alert_units"] = units
            a["_alert_revenue"] = round(units * price, 0)
            a["_est_lost_revenue"] = round(daily_avg * price * d * 0.5, 0)
        stock_alerts.sort(key=lambda x: x.get("_est_lost_revenue", 0), reverse=True)

        return templates.TemplateResponse(request, "partials/products_inventory.html", {            "products": page_products,
            "preset": preset,
            "search": search,
            "sort_by": sort_by,
            "enrich": enrich,
            "full_filter": full_filter,
            "total_count": total_count,
            "usd_to_mxn": round(usd_to_mxn, 2),
            "stock_alerts": stock_alerts,
            "page": page,
            "per_page": per_page,
            "total_pages": total_pages,
            "alert_days": alert_days,
        })
    finally:
        await client.close()


# --- Mark alert item as synced (evita duplicar trabajo entre usuarios) ---

@app.post("/partials/mark-synced/{item_id}")
async def mark_alert_synced(item_id: str, request: Request):
    """Registra un item como sincronizado; se excluye de alertas 60 min (cross-user, DB-backed)."""
    client = await get_meli_client()
    uid = str(client.user_id) if client else "unknown"
    if client: await client.close()
    _du = getattr(request.state, "dashboard_user", None) or {}
    synced_by = _du.get("username") or _du.get("email") or "unknown"
    asyncio.create_task(token_store.save_item_sync(item_id, uid, 0, synced_by))
    return Response(status_code=204)


