@app.get("/partials/products-deals", response_class=HTMLResponse)
async def products_deals_partial(request: Request):
    """Deals: detecta deals activos via bulk promotions API + top candidatos por stock."""
    import logging as _log
    import traceback as _tb
    from datetime import datetime, timedelta
    client = await get_meli_client()
    if not client:
        return HTMLResponse("<p>Error: No autenticado</p>")
    try:
        now = datetime.utcnow()
        date_from = (now - timedelta(days=30)).strftime("%Y-%m-%d")
        date_to = now.strftime("%Y-%m-%d")

        # ── Paso 1: obtener datos base en paralelo ─────────────────────────
        # promotions: campaña del seller → items en bulk (sin loops por item)
        all_bodies, all_orders, user_promos = await asyncio.gather(
            _get_all_products_cached(client, include_paused=True),
            client.fetch_all_orders(date_from=date_from, date_to=date_to),
            client.get_user_promotions(),
            return_exceptions=True,
        )
        if isinstance(all_bodies, Exception):
            raise all_bodies
        if isinstance(all_orders, Exception):
            all_orders = []
        if isinstance(user_promos, Exception):
            user_promos = []

        # ── Paso 2: obtener items de TODAS las campañas en paralelo ──────────
        # Sin filtro de status: campañas inactivas retornan 0 items rápido;
        # MARKETPLACE_CAMPAIGN puede tener status distinto a "started"/"active"
        _auto_types = {"SMART", "PRE_NEGOTIATED", "SELLER_COUPON_CAMPAIGN", "MARKETPLACE_CAMPAIGN"}
        _skip_statuses = {"finished", "expired", "cancelled", "paused"}
        all_promos = [
            p for p in user_promos
            if p.get("id") and p.get("type")
            and p.get("status") not in _skip_statuses
        ]
        promo_item_tasks = [
            client.get_promotion_items(p["id"], p["type"])
            for p in all_promos
        ]
        promo_items_lists = await asyncio.gather(*promo_item_tasks, return_exceptions=True)

        # Construir mapa item_id → datos de promo
        promo_items_map: dict = {}
        for promo, result in zip(all_promos, promo_items_lists):
            if isinstance(result, Exception) or not result:
                continue
            for item in result:
                iid = item.get("id")
                if not iid:
                    continue
                promo_items_map[iid] = {
                    "original_price": item.get("original_price"),
                    "deal_price": item.get("price"),
                    "meli_percentage": item.get("meli_percentage", 0),
                    "net_proceeds": item.get("net_proceeds"),
                    "start_date": item.get("start_date"),
                    "finish_date": item.get("end_date") or item.get("finish_date"),
                    "_promo_type": promo.get("type"),
                    "_promo_id": promo.get("id"),
                    "_promo_name": promo.get("name", ""),
                    "_promo_is_auto": promo.get("type") in _auto_types,
                }

        # ── Paso 3: clasificar productos ──────────────────────────────────
        sales_map = _aggregate_sales_by_item(all_orders)
        # Pre-cargar ratios neto/total desde historial real — mejora precisión de _neto_ml
        # sin esperar que el tab Ventas sea cargado primero.
        _preload_item_neto_ratios(all_orders)
        products = _build_product_list(all_bodies, sales_map)

        # Stamp every product with the account that owns it so the UI can
        # pass the correct account_id on write operations regardless of what
        # account is active at click time.
        for p in products:
            p["_account_id"] = client.user_id

        active_deals = []
        candidates = []
        for p in products:
            iid = p.get("id", "")
            # Deal activo = en mapa de promos O tiene original_price > price en body ML
            promo_data = promo_items_map.get(iid)
            op = p.get("original_price")
            has_deal_body = bool(op and op > p.get("price", 0))
            if promo_data or has_deal_body:
                p["_has_deal"] = True
                p["_deal_is_ml_auto"] = bool(promo_data and promo_data.get("_promo_is_auto"))
                p["_deal_types"] = [promo_data["_promo_type"]] if promo_data else []
                p["_promotions"] = [promo_data] if promo_data else []
                if has_deal_body and not promo_data:
                    p["_has_price_reduction"] = True  # original_price > price en body ML
                # Datos extra de la promo (fechas, % ML, etc.)
                if promo_data:
                    # Usar original_price de la API de promos si el body de ML no lo tiene
                    # (setdefault falla cuando la clave existe con valor None)
                    promo_op = promo_data.get("original_price")
                    if promo_op and not p.get("original_price"):
                        p["original_price"] = promo_op
                    p["_meli_promo_pct"] = promo_data.get("meli_percentage", 0)
                    p["_promo_start"] = promo_data.get("start_date")
                    p["_promo_finish"] = promo_data.get("finish_date")
                    p["_promo_type_str"] = promo_data.get("_promo_type", "")
                    p["_promo_name"] = promo_data.get("_promo_name", "")
                    # Precio real de campaña (lo que paga el comprador)
                    _raw_deal = promo_data.get("deal_price")
                    p["_promo_deal_price"] = _raw_deal
                    # Detectar si hay reducción real de precio
                    _cur_p = p.get("price") or 0
                    _orig_p2 = p.get("original_price") or 0
                    p["_has_price_reduction"] = bool(
                        (_raw_deal and _cur_p > 0 and _raw_deal < _cur_p)
                        or (_orig_p2 > _cur_p > 0)
                        or p.get("_meli_promo_pct", 0) > 0
                    )
                active_deals.append(p)
            elif p.get("available_quantity", 0) > 0 and p.get("status", "active") != "closed":
                candidates.append(p)

        # Limitar active_deals a los más relevantes (seller-managed primero, luego por ventas)
        active_deals.sort(key=lambda p: (
            0 if not p.get("_deal_is_ml_auto") else 1,  # seller deals primero
            -(p.get("units_30d") or 0)
        ))
        active_deals = active_deals[:200]

        # Top candidatos por stock
        candidates.sort(key=lambda p: p.get("available_quantity", 0), reverse=True)
        candidates_pre = candidates[:60]

        # ── Per-item enrichment: corrige _promo_deal_price con precio real del comprador ─
        # La API bulk devuelve price=precio_vendedor para MARKETPLACE_CAMPAIGN.
        # La API per-item (/seller-promotions/items/{id}) devuelve el precio real que paga el comprador.
        # Correr en paralelo: active_deals[:100] + top25 candidatos.
        top25 = candidates_pre[:25]
        _enrich_tasks = []
        if active_deals:
            _enrich_tasks.append(_enrich_with_promotions(client, active_deals[:100], id_key="id"))
        if top25:
            _enrich_tasks.append(_enrich_with_promotions(client, top25, id_key="id"))
        if _enrich_tasks:
            await asyncio.gather(*_enrich_tasks, return_exceptions=True)
        newly_found = [p for p in top25 if p.get("_has_deal")]
        if newly_found:
            active_deals.extend(newly_found)
            top25_ids = {p["id"] for p in newly_found}
            candidates_pre = [p for p in candidates_pre if p["id"] not in top25_ids]
        candidates = candidates_pre[:60]

        # ── Paso 4: enriquecer con BM, FX, SKUs en paralelo ──────────────
        all_to_enrich = active_deals + candidates
        _gr = await asyncio.gather(
            _get_bm_stock_cached(all_to_enrich),
            _enrich_with_bm_product_info(all_to_enrich),
            _get_usd_to_mxn(client),
            _enrich_variation_skus(client, all_to_enrich),
            _enrich_category_names(client, all_to_enrich),
            return_exceptions=True,
        )
        bm_map = _gr[0] if not isinstance(_gr[0], Exception) else {}
        usd_to_mxn = _gr[2] if not isinstance(_gr[2], Exception) else 17.0
        _apply_bm_stock(all_to_enrich, bm_map)
        _bundles_deals = await token_store.get_all_bundles()
        _apply_bundle_stock_override(all_to_enrich, _bundles_deals)
        _deal_cfg = await token_store.get_deal_config(str(client.user_id))
        _calc_margins(all_to_enrich, usd_to_mxn, _deal_cfg["deal_buffer_pct"], _deal_cfg["retail_target_pct"])
        _apply_bundle_margin_override(all_to_enrich, _bundles_deals)

        # Persistir historial de ventas en background (no bloquea el render)
        _save_ml_orders_history_bg(all_orders, str(client.user_id), usd_to_mxn)

        # ── KPIs y recomendaciones ────────────────────────────────────────
        deals_revenue = sum(p.get("revenue_30d", 0) for p in active_deals)
        deals_units = sum(p.get("units_30d", 0) for p in active_deals)

        # Calcular días restantes para cada deal activo (basado en _promo_finish)
        for p in active_deals:
            pf = p.get("_promo_finish")
            p["_days_remaining"] = None
            if pf:
                try:
                    fin_str = str(pf)[:19].replace("T", " ")
                    fin = datetime.strptime(fin_str, "%Y-%m-%d %H:%M:%S")
                    p["_days_remaining"] = max(0, (fin - now).days)
                except Exception:
                    try:
                        p["_days_remaining"] = max(0, (datetime.strptime(str(pf)[:10], "%Y-%m-%d") - now).days)
                    except Exception:
                        pass

        # Score de oportunidad para candidatos (ventas × peso + margen disponible + stock BM)
        for p in candidates:
            ventas = p.get("units_30d", 0) or 0
            margen = p.get("_margen_pct") or 0
            bm_stock = p.get("_bm_avail", 0) or 0
            score = (ventas * 3.0) + (max(0.0, margen - 10.0) * 0.8) + (min(bm_stock, 60) * 0.25)
            p["_opp_score"] = round(score, 1)

        recs = []
        # 0. Deals próximos a vencer (urgente — insert al inicio)
        expiring_soon = [p for p in active_deals if p.get("_days_remaining") is not None and p["_days_remaining"] <= 5]
        if expiring_soon:
            expiring_soon.sort(key=lambda p: p.get("_days_remaining", 99))
            recs.append({
                "type": "danger", "icon": "!",
                "title": f"{len(expiring_soon)} deal(s) vencen en los proximos 5 dias",
                "desc": "Si vencen sin renovar perdes posicionamiento. Revisa y renueva los que esten vendiendo bien.",
                "products": [{"id": p["id"], "title": p["title"][:40], "detail": f"{p.get('_days_remaining', '?')}d — {p.get('_promo_type_str', 'DEAL')}"} for p in expiring_soon[:5]],
            })
        neg_margin = [p for p in active_deals if p.get("_margen_pct") is not None and p["_margen_pct"] < 0]
        if neg_margin:
            neg_margin.sort(key=lambda p: p["_margen_pct"])
            recs.append({
                "type": "danger", "icon": "!",
                "title": f"{len(neg_margin)} deal(s) con margen negativo",
                "desc": "Estos deals pierden dinero en cada venta. Revisa si conviene desactivarlos o subir el precio.",
                "products": [{"id": p["id"], "title": p["title"][:40], "detail": f"Margen {p['_margen_pct']:.1f}%"} for p in neg_margin[:5]],
            })
        high_stock_no_sales = [p for p in candidates if p.get("available_quantity", 0) >= 10 and p.get("units_30d", 0) == 0]
        if high_stock_no_sales:
            high_stock_no_sales.sort(key=lambda p: p["available_quantity"], reverse=True)
            recs.append({
                "type": "warning", "icon": "S",
                "title": f"{len(high_stock_no_sales)} producto(s) con alto stock sin ventas",
                "desc": "Mucho inventario parado. Un deal agresivo puede activar la demanda.",
                "products": [{"id": p["id"], "title": p["title"][:40], "detail": f"Stock: {p['available_quantity']}"} for p in high_stock_no_sales[:5]],
            })
        good_sellers_no_deal = [p for p in candidates if p.get("units_30d", 0) >= 3 and p.get("_margen_pct") is not None and p["_margen_pct"] >= 15]
        if good_sellers_no_deal:
            good_sellers_no_deal.sort(key=lambda p: p["units_30d"], reverse=True)
            recs.append({
                "type": "success", "icon": "^",
                "title": f"{len(good_sellers_no_deal)} producto(s) vendiendo bien con buen margen",
                "desc": "Ya venden sin deal y tienen margen para descuento. Un deal los puede catapultar.",
                "products": [{"id": p["id"], "title": p["title"][:40], "detail": f"{p['units_30d']} uds, margen {p['_margen_pct']:.0f}%"} for p in good_sellers_no_deal[:5]],
            })
        bm_available = [p for p in candidates if p.get("_bm_avail") is not None and p["_bm_avail"] > 20 and p.get("available_quantity", 0) <= 5]
        if bm_available:
            bm_available.sort(key=lambda p: p["_bm_avail"], reverse=True)
            recs.append({
                "type": "info", "icon": "R",
                "title": f"{len(bm_available)} producto(s) con stock BM disponible alto pero poco en MeLi",
                "desc": "Reabastecer MeLi y activar deal para impulsar rotacion.",
                "products": [{"id": p["id"], "title": p["title"][:40], "detail": f"BM disp: {p['_bm_avail']}, MeLi: {p['available_quantity']}"} for p in bm_available[:5]],
            })

        cat_counts = {}
        for p in candidates:
            cn = p.get("category_name", "")
            if cn:
                cat_counts[cn] = cat_counts.get(cn, 0) + 1
        categories = sorted(cat_counts.keys())

        return templates.TemplateResponse(request, "partials/products_deals.html", {
            "active_deals": active_deals,
            "candidates": candidates,
            "usd_to_mxn": round(usd_to_mxn, 2),
            "deals_revenue": deals_revenue,
            "deals_units": deals_units,
            "recommendations": recs,
            "categories": categories,
            "cat_counts": cat_counts,
            "total_no_deal_no_sales": len([p for p in candidates if p.get("units_30d", 0) == 0]),
            "deal_buffer_pct": _deal_cfg["deal_buffer_pct"],
            "retail_target_pct": _deal_cfg["retail_target_pct"],
        })
    except Exception as _deals_exc:
        _log.getLogger("deals").error(f"products_deals_partial error: {_deals_exc}\n{_tb.format_exc()}")
        return HTMLResponse(
            f'<div class="p-6 text-red-600 text-sm font-mono">'
            f'<b>Error Deals:</b> {type(_deals_exc).__name__}: {_deals_exc}'
            f'<pre class="text-xs mt-2 whitespace-pre-wrap overflow-auto max-h-64">{_tb.format_exc()}</pre></div>',
            status_code=200
        )
    finally:
        await client.close()


