@app.get("/amazon", response_class=HTMLResponse)
async def amazon_dashboard(request: Request, tab: str = Query(default="dashboard")):
    """
    Dashboard Amazon — muestra ventas diarias, métricas y contexto de la
    cuenta Amazon activa (seleccionada con active_amazon_id cookie).

    Si no hay cuentas Amazon configuradas, muestra pantalla de bienvenida
    con botón para conectar.
    El PIN se valida automáticamente via PinMiddleware.
    """
    user = await get_current_user()
    ctx = await _accounts_ctx(request)

    # Obtener info de la cuenta Amazon activa (para el banner)
    active_amazon_id = ctx.get("active_amazon_id")
    amazon_account = None
    if active_amazon_id:
        amazon_account = await token_store.get_amazon_account(active_amazon_id)

    active_tab = tab if tab in ("dashboard", "ventas", "salud", "operaciones", "finanzas", "fba", "listings", "deals") else "dashboard"
    ctx["amazon_account"] = amazon_account
    ctx["active_platform"] = "amz"
    ctx["active_amazon_tab"] = active_tab
    ctx["nav_tabs"] = _build_nav_tabs("amz", ctx.get("dashboard_user"))
    du = ctx.get("dashboard_user") or {}
    sections = du.get("allowed_sections") or []
    unrestricted = (not sections) or du.get("role") == "admin"
    all_salud_subtabs = list(user_store.PERMISSION_TREE["amz"]["salud"]["subtabs"].keys())
    all_ventas_subtabs = list(user_store.PERMISSION_TREE["amz"]["ventas"]["subtabs"].keys())
    salud_allowed = all_salud_subtabs if unrestricted else user_store.get_allowed_subtabs(sections, "amz", "salud")
    ventas_allowed = all_ventas_subtabs if unrestricted else user_store.get_allowed_subtabs(sections, "amz", "ventas")
    ctx["amz_salud_allowed_subtabs"] = salud_allowed
    ctx["amz_salud_default_subtab"] = salud_allowed[0] if salud_allowed else None
    ctx["amz_ventas_allowed_subtabs"] = ventas_allowed
    ctx["amz_ventas_default_subtab"] = ventas_allowed[0] if ventas_allowed else None
    return templates.TemplateResponse(request, "amazon_dashboard.html", {"user": user, **ctx})


@app.get("/api/amazon/asin-search")
async def amazon_asin_search(
    asin: str = Query(..., description="ASIN Amazon de 10 caracteres"),
    seller_id: str = Query("", description="seller_id de la cuenta; vacío = cuenta activa"),
    days: int = Query(30, ge=7, le=365),
):
    """
    Busca un ASIN específico: info de catálogo (título, imagen, marca) + métricas de
    ventas del período usando Sales API v1 con filtro por ASIN.
    El marketplace (MX/US/CA) se determina automáticamente desde las credenciales
    de la cuenta seleccionada.
    """
    from datetime import datetime as _dta, timedelta as _tda
    asin = asin.strip().upper()
    if not asin or len(asin) != 10:
        return {"error": "ASIN debe tener exactamente 10 caracteres", "asin": asin}

    # Resolver cuenta
    _sid = seller_id.strip() or ""
    try:
        from app.services.amazon_client import get_amazon_client as _get_amz
        client = await _get_amz(_sid or None)
    except Exception as _e:
        return {"error": f"No se pudo inicializar el cliente Amazon: {_e}"}
    if not client:
        return {"error": "No hay cuenta Amazon activa. Selecciona una cuenta."}

    try:
        _now = _dta.utcnow()
        date_to_excl = (_now + _tda(days=1)).strftime("%Y-%m-%d")
        date_from = (_now - _tda(days=days)).strftime("%Y-%m-%d")

        # ── 1. Catalog + Offers + Sales metrics en paralelo ──────────────
        catalog_task = client.get_catalog_item(asin)
        offers_task = client.get_item_offers(asin)
        metrics_task = client.get_order_metrics(
            date_from=date_from,
            date_to_exclusive=date_to_excl,
            granularity="Day",
            asin=asin,
        )
        metrics_total_task = client.get_order_metrics(
            date_from=date_from,
            date_to_exclusive=date_to_excl,
            granularity="Total",
            asin=asin,
        )

        catalog_raw, offers_raw, metrics_daily, metrics_total = await asyncio.gather(
            catalog_task, offers_task, metrics_task, metrics_total_task,
            return_exceptions=True,
        )

        # ── 2. Parse catalog ──────────────────────────────────────────────
        product_info: dict = {"asin": asin, "found": False}
        if isinstance(catalog_raw, dict) and catalog_raw:
            summaries = catalog_raw.get("summaries", [])
            if summaries:
                s = summaries[0]
                product_info.update({
                    "found": True,
                    "title": s.get("itemName", ""),
                    "brand": s.get("brand", ""),
                    "manufacturer": s.get("manufacturer", ""),
                    "model_number": s.get("modelNumber", ""),
                    "item_class": s.get("itemClassificationSalesRank", ""),
                    "marketplace": client.marketplace_name if hasattr(client, "marketplace_name") else "",
                })
            # Images
            images_raw = catalog_raw.get("images", [])
            main_img = ""
            if images_raw:
                for img_block in images_raw:
                    imgs = img_block.get("images", [])
                    for img in imgs:
                        if img.get("variant") == "MAIN":
                            main_img = img.get("link", "")
                            break
                    if main_img:
                        break
            product_info["image_url"] = main_img

            # Attributes: list_price
            # Amazon Catalog API v2022-04-01 devuelve value como dict {amount,currency}
            # O como float directo según el ASIN — manejar ambos formatos.
            attrs = catalog_raw.get("attributes", {})
            list_price_attr = attrs.get("list_price", [{}])
            if list_price_attr and isinstance(list_price_attr, list):
                lp = list_price_attr[0]
                _lp_val = lp.get("value", {}) if isinstance(lp, dict) else {}
                if isinstance(_lp_val, dict):
                    product_info["list_price"] = _lp_val.get("amount", _lp_val.get("Amount", 0))
                    product_info["list_price_currency"] = _lp_val.get("currency", _lp_val.get("currencyCode", "USD"))
                elif isinstance(_lp_val, (int, float)) and _lp_val:
                    product_info["list_price"] = float(_lp_val)
                    product_info["list_price_currency"] = "USD"

            # BSR — salesRanks
            bsr_ranks: list = []
            for rb in catalog_raw.get("salesRanks", []):
                for cr in rb.get("classificationRanks", []):
                    bsr_ranks.append({
                        "category": cr.get("title", ""),
                        "rank": int(cr.get("rank", 0) or 0),
                    })
                for dr in rb.get("displayGroupRanks", []):
                    bsr_ranks.append({
                        "category": dr.get("title", ""),
                        "rank": int(dr.get("rank", 0) or 0),
                        "is_display": True,
                    })
            product_info["bsr"] = bsr_ranks

        # ── 3. Parse sales metrics ────────────────────────────────────────
        daily_rows = []
        if isinstance(metrics_daily, list):
            for row in metrics_daily:
                ts_sales = row.get("totalSales") or {}
                avg_price = row.get("averageUnitPrice") or {}
                # interval format: "2026-05-13T00:00:00-07:00--2026-05-14T00:00:00-07:00"
                itvl = row.get("interval", "")
                date_label = itvl[:10] if itvl else ""
                units = int(row.get("unitCount", 0) or 0)
                orders = int(row.get("orderCount", 0) or 0)
                rev = float((ts_sales.get("amount") if isinstance(ts_sales, dict) else ts_sales) or 0)
                currency = ts_sales.get("currencyCode", "USD") if isinstance(ts_sales, dict) else "USD"
                avg = float((avg_price.get("amount") if isinstance(avg_price, dict) else avg_price) or 0)
                if units > 0 or orders > 0:
                    daily_rows.append({
                        "date": date_label,
                        "units": units,
                        "orders": orders,
                        "revenue": round(rev, 2),
                        "avg_price": round(avg, 2),
                        "currency": currency,
                    })

        # ── 4. Total summary ──────────────────────────────────────────────
        totals = {"units": 0, "orders": 0, "revenue": 0.0, "avg_price": 0.0, "currency": "USD"}
        if isinstance(metrics_total, list) and metrics_total:
            t = metrics_total[0]
            ts = t.get("totalSales") or {}
            ap = t.get("averageUnitPrice") or {}
            totals = {
                "units": int(t.get("unitCount", 0) or 0),
                "orders": int(t.get("orderCount", 0) or 0),
                "revenue": round(float((ts.get("amount") if isinstance(ts, dict) else ts) or 0), 2),
                "avg_price": round(float((ap.get("amount") if isinstance(ap, dict) else ap) or 0), 2),
                "currency": ts.get("currencyCode", "USD") if isinstance(ts, dict) else "USD",
            }

        # ── 5. Parse competitive offers ───────────────────────────────────
        offers_info: dict = {
            "total_offers": 0,
            "buy_box_price": None,
            "buy_box_currency": "USD",
            "list_price": None,
            "list_price_currency": "USD",
            "sellers": [],
        }
        if isinstance(offers_raw, dict) and offers_raw:
            _op = offers_raw.get("payload", offers_raw)
            if isinstance(_op, dict):
                _sum = _op.get("Summary", {})
                offers_info["total_offers"] = int(_sum.get("TotalOfferCount", 0) or 0)
                _bb = _sum.get("BuyBoxPrices", [])
                if _bb:
                    _lp_bb = _bb[0].get("LandedPrice", {})
                    _bb_amt = float(_lp_bb.get("Amount", 0) or 0)
                    if _bb_amt:
                        offers_info["buy_box_price"] = round(_bb_amt, 2)
                        offers_info["buy_box_currency"] = _lp_bb.get("CurrencyCode", "USD")
                _lp_s = _sum.get("ListPrice", {})
                if _lp_s:
                    _lp_amt = float(_lp_s.get("Amount", 0) or 0)
                    if _lp_amt:
                        offers_info["list_price"] = round(_lp_amt, 2)
                        offers_info["list_price_currency"] = _lp_s.get("CurrencyCode", "USD")
                for _o in (_op.get("Offers", []) or [])[:20]:
                    _lp_o = _o.get("ListingPrice", {})
                    _sh_o = _o.get("Shipping", {})
                    _fb_o = _o.get("SellerFeedbackRating", {})
                    _price = float(_lp_o.get("Amount", 0) or 0)
                    _ship = float(_sh_o.get("Amount", 0) or 0)
                    offers_info["sellers"].append({
                        "seller_id": _o.get("SellerId", ""),
                        "price": round(_price, 2),
                        "shipping": round(_ship, 2),
                        "landed": round(_price + _ship, 2),
                        "currency": _lp_o.get("CurrencyCode", "USD"),
                        "is_fba": bool(_o.get("IsFulfilledByAmazon", False)),
                        "is_buy_box": bool(_o.get("IsBuyBoxWinner", False)),
                        "is_prime": bool((_o.get("PrimeInformation") or {}).get("IsPrime", False)),
                        "feedback_count": int(_fb_o.get("FeedbackCount", 0) or 0),
                        "feedback_pct": float(_fb_o.get("SellerPositiveFeedbackRating", 0) or 0),
                    })

        # ── 6. Current price from listings DB ────────────────────────────
        listing_info: dict = {}
        try:
            import aiosqlite as _aio_as
            async with _aio_as.connect(DATABASE_PATH) as _db:
                _db.row_factory = _aio_as.Row
                row = await (await _db.execute(
                    "SELECT sku, price, status, title FROM amazon_listings WHERE seller_id=? AND asin=? LIMIT 1",
                    (_sid or client.seller_id, asin)
                )).fetchone()
                if row:
                    listing_info = dict(row)
        except Exception:
            pass

        return {
            "asin": asin,
            "days": days,
            "seller_id": client.seller_id,
            "marketplace": getattr(client, "marketplace_name", ""),
            "product": product_info,
            "listing": listing_info,
            "offers": offers_info,
            "totals": totals,
            "daily": daily_rows,
        }
    except Exception as _exc:
        logger.warning(f"[ASIN-SEARCH] {asin}: {_exc}")
        return {"error": str(_exc), "asin": asin}


