# ═══════════════════════════════════════════════════════════════════════════
# STOCK SYNC SCHEDULER — Alertas proactivas de sobreventa (Week 3)
# Cada 4 horas verifica: items activos en MeLi con BM disponible = 0
# ═══════════════════════════════════════════════════════════════════════════

_STOCK_SYNC_INTERVAL = 4 * 3600   # 4 horas
_stock_sync_running: dict = {}     # user_id -> bool (lock por cuenta)
_auto_zero_enabled: dict = {}      # user_id -> bool (poner qty=0 automáticamente al detectar riesgo)


async def _run_stock_sync_for_user(user_id: str):
    """Compara stock activo de MeLi con BM disponible para detectar riesgo de sobreventa."""
    if _stock_sync_running.get(user_id):
        return
    _stock_sync_running[user_id] = True
    try:
        print(f"[STOCK-SYNC] Iniciando sync para user {user_id}...")
        client = await get_meli_client(user_id=user_id)

        # 1. Obtener todos los items activos (scroll completo)
        all_items = []
        offset = 0
        limit = 50
        while True:
            try:
                resp = await client.get(f"/users/{user_id}/items/search",
                                        params={"status": "active", "offset": offset, "limit": limit})
                ids = resp.get("results", [])
                if not ids:
                    break
                # Fetch detalles
                details = await client.get_items_details(ids)
                all_items.extend(details)
                paging = resp.get("paging", {})
                total = paging.get("total", 0)
                offset += limit
                if offset >= total:
                    break
            except Exception as e:
                print(f"[STOCK-SYNC] Error fetching items page offset={offset}: {e}")
                break

        print(f"[STOCK-SYNC] {len(all_items)} items activos obtenidos para {user_id}")

        # 2. Construir lista minimal de productos para _get_bm_stock_cached
        products = []
        item_map = {}
        for item in all_items:
            body = item.get("body", item) if isinstance(item, dict) else item
            iid = body.get("id", "") if isinstance(body, dict) else getattr(body, "id", "")
            body_dict = body if isinstance(body, dict) else vars(body)
            sku = _get_item_sku(body_dict)
            if not sku or not iid:
                continue
            # Excluir FULL items — ML controla su stock, no se puede modificar vía API
            logistic_type = (body_dict.get("shipping") or {}).get("logistic_type", "")
            if logistic_type == "fulfillment":
                continue
            qty   = body_dict.get("available_quantity", 0) or 0
            title = body_dict.get("title", "") or ""
            price = body_dict.get("price", 0) or 0
            products.append({"sku": sku, "item_id": iid, "meli_stock": qty, "title": title, "price": price})
            item_map[iid] = {"sku": sku, "meli_stock": qty, "title": title, "price": price}

        # 3. Obtener stock BM para todos los productos
        bm_map = await _get_bm_stock_cached(products)

        # 4. Detectar sobreventas: MeLi stock > 0 pero BM disponible = 0
        # IMPORTANTE: si BM no retornó datos para un SKU (error/503) → NO flaggear.
        # Solo flaggear si BM confirmó explícitamente avail_total=0.
        alerts = []
        for p in products:
            sku = p["sku"]
            base_sku = _clean_sku_for_bm(sku)
            bm_info = bm_map.get(sku) or bm_map.get(base_sku)
            if bm_info is None:
                # BM no retornó datos (error/503) → skip, no crear falso positivo
                continue
            bm_avail = bm_info.get("avail_total", 0)
            meli_stock = p["meli_stock"]
            if meli_stock > 0 and bm_avail == 0:
                alerts.append({
                    "item_id": p["item_id"],
                    "title": p["title"],
                    "sku": sku,
                    "meli_stock": meli_stock,
                    "price": p.get("price", 0),
                    "bm_avail": 0,
                    "alert_type": "oversell",
                })

        # 5. Guardar alertas y status
        await token_store.save_sync_alerts(user_id, alerts)
        await token_store.save_sync_status(user_id, len(alerts), "ok")
        print(f"[STOCK-SYNC] Done user {user_id}: {len(alerts)} alertas de sobreventa")

        # Auto qty=0: delegado al stock_sync_multi (BM→ML+Amazon cada 5 min).
        # Este sync viejo solo detecta alertas — no modifica stock para evitar conflictos.
    except Exception as e:
        print(f"[STOCK-SYNC] Error en sync para {user_id}: {e}")
        try:
            await token_store.save_sync_status(user_id, 0, f"error: {str(e)[:100]}")
        except Exception:
            pass
    finally:
        _stock_sync_running[user_id] = False


async def _stock_sync_loop():
    """Loop periódico que ejecuta el stock sync para todas las cuentas MeLi."""
    await asyncio.sleep(60)  # Esperar 1 min al arranque para que los tokens se siembren
    while True:
        try:
            accounts = await token_store.get_all_tokens()
            for acc in accounts:
                uid = acc.get("user_id", "")
                if uid:
                    await _run_stock_sync_for_user(uid)
                    await asyncio.sleep(5)  # Separar llamadas entre cuentas
        except Exception as e:
            print(f"[STOCK-SYNC-LOOP] Error: {e}")
        await asyncio.sleep(_STOCK_SYNC_INTERVAL)


def start_stock_sync():
    """Inicia el loop de stock sync en background."""
    asyncio.create_task(_stock_sync_loop())


# ── Captura periódica de ventas para order_history / ledger de deuda ────────
# Antes, order_history solo se llenaba si alguien visitaba Deals (ML) o
# Planeación→Velocidad (Amazon) — dependía de que alguien navegara a esas
# pestañas por cuenta. Este loop cubre las 7 cuentas (4 ML + 3 Amazon) solo,
# sin depender de que nadie visite nada.
_SUPPLIER_DEBT_SYNC_INTERVAL = 3600  # 1 hora


async def _supplier_debt_sync_loop():
    """Recorre las 4 cuentas ML (ventana corta, upsert es idempotente) y
    dispara _save_amazon_orders_bg (ya cubre las 3 cuentas Amazon con su
    propio guard de 2h) — mantiene order_history y el ledger de deuda al
    día sin depender de que alguien visite Deals/Planeación."""
    await asyncio.sleep(90)  # dejar que los tokens se siembren al arranque
    while True:
        try:
            accounts = await token_store.get_all_tokens()
            for acc in accounts:
                uid = acc.get("user_id", "")
                if not uid:
                    continue
                try:
                    client = await get_meli_client(user_id=uid)
                    if not client:
                        continue
                    now = datetime.utcnow()
                    date_from = (now - timedelta(days=3)).strftime("%Y-%m-%d")
                    date_to = now.strftime("%Y-%m-%d")
                    orders = await client.fetch_all_orders(date_from=date_from, date_to=date_to)
                    usd_to_mxn = await _get_usd_to_mxn(client)
                    _save_ml_orders_history_bg(orders, uid, usd_to_mxn)
                except Exception as e:
                    logger.warning(f"[SUPPLIER-DEBT-SYNC] Error ML uid={uid}: {e}")
                await asyncio.sleep(5)  # separar llamadas entre cuentas

            asyncio.create_task(_save_amazon_orders_bg(days=3))
        except Exception as e:
            logger.warning(f"[SUPPLIER-DEBT-SYNC] Error: {e}")
        await asyncio.sleep(_SUPPLIER_DEBT_SYNC_INTERVAL)


def start_supplier_debt_sync():
    """Inicia el loop de captura de ventas para el ledger de deuda."""
    asyncio.create_task(_supplier_debt_sync_loop())


# ── Reconciliación de Alertas de Stock — no depende solo de notificaciones ──
# Bug real encontrado: una alerta se crea correctamente cuando el envío
# está en "ready_to_print", pero si el envío avanza a "in_packing_list" (o
# se envía/entrega/resulta FULL) SIN que llegue una notificación nueva para
# esa orden (ML no siempre reavisa por cada cambio de sub-estado, sobre
# todo si "Shipments" no está activo en el DevCenter), la alerta se queda
# congelada mostrando algo que ya no es cierto. Este loop revisa
# activamente el estado real de CADA alerta activa cada 5 min — no espera
# a que nos avisen.
_REALTIME_ALERTS_RECONCILE_INTERVAL = 300  # 5 min


async def _reconcile_realtime_alerts_once() -> dict:
    """Revisa todas las alertas activas contra el estado real de su envío
    en ML y borra las que ya no son accionables. Retorna un resumen."""
    alerts = await token_store.get_all_realtime_alerts_for_reconcile()
    checked = 0
    removed = 0
    errors = 0
    clients_cache: dict = {}
    try:
        for a in alerts:
            account_id = a.get("account_id", "")
            if a.get("platform") != "ml" or not account_id:
                continue
            try:
                client = clients_cache.get(account_id)
                if client is None:
                    client = await get_meli_client(user_id=account_id)
                    if not client:
                        continue
                    clients_cache[account_id] = client

                shipping_id = a.get("shipping_id") or ""
                if not shipping_id:
                    order = await client.resolve_order(a["order_id"])
                    shipping_id = str((order.get("shipping") or {}).get("id") or "")
                    if shipping_id:
                        await token_store.update_realtime_stock_alert_shipping_id(a["id"], shipping_id)
                if not shipping_id:
                    continue  # sin dato — no se puede confirmar, se deja para el próximo ciclo

                shipment = await client.get_shipment(shipping_id)
                checked += 1
                if not _shipment_should_alert(shipment):
                    await token_store.delete_realtime_stock_alert_by_id(a["id"])
                    removed += 1
                await asyncio.sleep(0.3)  # no saturar la API de ML
            except Exception as e:
                errors += 1
                logger.warning(f"[ALERTS-RECONCILE] Error orden {a.get('order_id')}: {e}")
    finally:
        for c in clients_cache.values():
            await c.close()
    logger.info(f"[ALERTS-RECONCILE] revisadas={checked} borradas={removed} errores={errors}")
    return {"checked": checked, "removed": removed, "errors": errors}


async def _realtime_alerts_reconcile_loop():
    await asyncio.sleep(120)
    while True:
        try:
            await _reconcile_realtime_alerts_once()
        except Exception as e:
            logger.warning(f"[ALERTS-RECONCILE] Error en ciclo: {e}")
        await asyncio.sleep(_REALTIME_ALERTS_RECONCILE_INTERVAL)


def start_realtime_alerts_reconcile():
    asyncio.create_task(_realtime_alerts_reconcile_loop())


async def _token_refresh_loop():
    """Auto-renueva tokens MeLi.
    - Normal: cada 5h (ML access tokens duran 6h)
    - Si falla (rate limit / error): reintenta cada 60s hasta que funcione
    Usa el refresh_token del DB (más actual por rotación de ML).
    """
    await asyncio.sleep(300)  # 5 min initial delay — dejar que todo arranque primero
    while True:
        try:
            from app.services import token_store as _ts
            accounts = await _ts.get_all_tokens()
            ok, failed = 0, 0
            for acc in accounts:
                uid = acc.get("user_id", "")
                db_rt = acc.get("refresh_token", "")
                if uid and db_rt:
                    before = await _ts.get_tokens(uid)
                    before_at = (before or {}).get("access_token", "")
                    await _seed_one(uid, db_rt, f"uid={uid}")
                    after = await _ts.get_tokens(uid)
                    after_at = (after or {}).get("access_token", "")
                    if after_at and after_at != before_at:
                        ok += 1
                    else:
                        failed += 1
            if ok > 0 or not accounts:
                print(f"[TOKEN_REFRESH] {ok}/{len(accounts)} cuentas renovadas OK — próximo en 5h")
                await asyncio.sleep(5 * 3600)
            else:
                print(f"[TOKEN_REFRESH] {failed}/{len(accounts)} fallaron — reintentando en 60s")
                await asyncio.sleep(60)
        except Exception as e:
            print(f"[TOKEN_REFRESH] Error: {e} — reintentando en 60s")
            await asyncio.sleep(60)


def start_token_refresh():
    """Inicia el loop de auto-refresh de tokens en background."""
    asyncio.create_task(_token_refresh_loop())


