@app.post("/api/stock/alerts/restock-dismiss")
async def stock_alerts_restock_dismiss(request: Request):
    """Marca un aviso de reactivación como atendido. Body: {id}."""
    du = getattr(request.state, "dashboard_user", None) or {}
    if not du:
        return JSONResponse({"error": "forbidden"}, status_code=403)
    try:
        body = await request.json()
    except Exception:
        return JSONResponse({"detail": "JSON inválido"}, status_code=400)
    resolution_id = body.get("id")
    if not resolution_id:
        return JSONResponse({"detail": "id es requerido"}, status_code=400)
    await token_store.mark_resolution_reactivated(int(resolution_id), du["username"])
    return JSONResponse({"ok": True})


@app.get("/api/stock/bm-sync-log")
async def bm_sync_log_endpoint():
    """Historial de ejecuciones del prewarm BM — para la tarjeta Caché de Stock BM.
    Usa historial en memoria primero (sobrevive Railway ephemeral DB).
    """
    now = _time.time()

    def _fmt_entry(ts, sku_count, elapsed_s, source, retail_ph=None):
        age_s = now - ts
        if age_s < 120:
            age_str = f"hace {int(age_s)}s"
        elif age_s < 3600:
            age_str = f"hace {int(age_s // 60)}min"
        else:
            age_str = f"hace {int(age_s // 3600)}h"
        return {
            "synced_at": ts,
            "age_str":   age_str,
            "sku_count": sku_count,
            "elapsed_s": elapsed_s,
            "source":    source,
            "retail_ph": retail_ph,
        }

    # Historial en memoria (fuente primaria — resistente a reinicios de DB)
    if _prewarm_history:
        entries = [
            _fmt_entry(h["ts"], h["sku_count"], h["elapsed_s"], h["source"], h.get("retail_ph"))
            for h in reversed(_prewarm_history)
        ]
        return JSONResponse({"log": entries, "source": "memory"})

    # Fallback: DB (útil solo si el proceso lleva corriendo desde antes del fix)
    try:
        rows = await token_store.get_bm_sync_log(limit=10)
        entries = [
            _fmt_entry(r["synced_at"], r["sku_count"], r["elapsed_s"], r["source"])
            for r in rows
        ]
    except Exception:
        entries = []
    return JSONResponse({"log": entries, "source": "db"})


@app.get("/api/bm/status")
async def bm_health_status():
    """Estado de salud de BinManager — para el indicador en navbar."""
    from datetime import datetime
    h = _bm_health
    down_since_min = None
    if h["ok"] is False and h["last_ok_ts"] > 0:
        down_since_min = round((_time.time() - h["last_ok_ts"]) / 60)
    last_check_iso = (
        datetime.utcfromtimestamp(h["last_check_ts"]).strftime("%H:%M") if h["last_check_ts"] else None
    )
    return JSONResponse({
        "ok": h["ok"],
        "latency_ms": h["latency_ms"],
        "last_check_iso": last_check_iso,
        "consecutive_failures": h["consecutive_failures"],
        "down_since_min": down_since_min,
        "error_type": h.get("error_type"),
        "last_error": h.get("last_error", ""),
    })


@app.get("/api/catalog/status")
async def catalog_status_endpoint(request: Request):
    """Estado del sync semanal de catálogo BM. Solo admin."""
    du = getattr(request.state, "dashboard_user", None) or {}
    if du.get("role") != "admin":
        return JSONResponse({"error": "Acceso denegado"}, status_code=403)
    now = _time.time()
    last_db_sync = await token_store.get_bm_catalog_last_sync()
    last_db_age_h = round((now - last_db_sync) / 3600, 1) if last_db_sync > 0 else None
    # Próximo domingo 9pm Monterrey (02:00 UTC lunes)
    from datetime import datetime as _dt, timezone as _tz, timedelta as _td
    _dnow = _dt.now(_tz.utc)
    # Domingo 9pm MTY CDT = lunes 02:00 UTC
    days_until_monday = (0 - _dnow.weekday()) % 7
    if days_until_monday == 0 and _dnow.hour >= 2:
        days_until_monday = 7
    _next = (_dnow + _td(days=days_until_monday)).replace(hour=2, minute=0, second=0, microsecond=0)
    next_run_h = round((_next - _dnow).total_seconds() / 3600, 1)

    def _fmt(h):
        age_s = now - h["ts"]
        if age_s < 120:   age_str = f"hace {int(age_s)}s"
        elif age_s < 3600: age_str = f"hace {int(age_s//60)}min"
        else:              age_str = f"hace {int(age_s//3600)}h {int((age_s%3600)//60)}min"
        return {**h, "age_str": age_str}

    return JSONResponse({
        "running":         _catalog_sync_running,
        "history":         [_fmt(h) for h in reversed(_catalog_sync_history)],
        "cache_count":     len(_bm_retail_ph_cache),
        "last_db_sync_ts": last_db_sync,
        "last_db_age_h":   last_db_age_h,
        "next_auto_run_h": next_run_h,
        "next_auto_run_label": f"domingo 9pm MTY (en ~{next_run_h}h)",
    })


@app.post("/api/catalog/sync")
async def catalog_sync_trigger(request: Request):
    """Dispara el sync manual del catálogo BM. Solo admin."""
    du = getattr(request.state, "dashboard_user", None) or {}
    if du.get("role") != "admin":
        return JSONResponse({"error": "Acceso denegado"}, status_code=403)
    if _catalog_sync_running:
        return JSONResponse({"ok": False, "error": "Ya está corriendo un sync"})
    asyncio.create_task(_sync_bm_product_catalog(source="manual"))
    return JSONResponse({"ok": True, "message": "Sync iniciado en background"})


@app.post("/api/catalog/cancel")
async def catalog_sync_cancel(request: Request):
    """Cancela el sync en curso del catálogo BM. Solo admin."""
    du = getattr(request.state, "dashboard_user", None) or {}
    if du.get("role") != "admin":
        return JSONResponse({"error": "Acceso denegado"}, status_code=403)
    if not _catalog_sync_running or _catalog_sync_task is None:
        return JSONResponse({"ok": False, "error": "No hay sync en curso"})
    try:
        _catalog_sync_task.cancel()
        return JSONResponse({"ok": True, "message": "Cancelación enviada"})
    except Exception as _e:
        return JSONResponse({"ok": False, "error": str(_e)})


