# ===========================
# RETORNOS / DEVOLUCIONES
# ===========================

# Mapa completo de tipos de reclamo ML → etiqueta legible
CLAIM_REASON_MAP: dict[str, str] = {
    # PDD — Producto Defectuoso o Diferente
    "PDD":  "Defectuoso/Diferente",
    "PDD1": "Defecto de fábrica",
    "PDD2": "No coincide con descripción",
    "PDD3": "Producto incorrecto",
    "PDD4": "Partes faltantes",
    "PDD5": "Dañado en tránsito",
    "PDD6": "No funciona",
    # PNTR — Producto No Recibido (prefijo largo)
    "PNTR": "No recibido",
    # PNR — Producto No Recibido (prefijo corto — usado por ML en la práctica)
    "PNR":  "No recibido",
    # Otros
    "CANCEL": "Cancelación",
}

def _strip_html_msg(text: str) -> str:
    """Los mensajes de reclamo ML a veces vienen con HTML crudo (compuestos con el
    editor de texto enriquecido de ML — clases 'coco-editor-*'). Quita las etiquetas
    y decodifica entidades para dejar texto plano legible."""
    import re as _re_sh
    import html as _html_sh
    if not text:
        return ""
    t = _re_sh.sub(r"</p>|<br\s*/?>", "\n", text)
    t = _re_sh.sub(r"<[^>]+>", "", t)
    t = _html_sh.unescape(t)
    return _re_sh.sub(r"\n{3,}", "\n\n", t).strip()


def _claim_reason_label(reason_id: str) -> str:
    rid = (reason_id or "").upper().strip()
    # Buscar coincidencia exacta primero, luego prefijo de 4 chars, luego 3
    return (CLAIM_REASON_MAP.get(rid)
            or CLAIM_REASON_MAP.get(rid[:4])
            or CLAIM_REASON_MAP.get(rid[:3])
            or f"Reclamo ({rid})")

def _claim_category(reason_id: str) -> str:
    """Categoría amplia para filtros: 'pdd' | 'pntr' | 'other'."""
    rid = (reason_id or "").upper()
    if rid.startswith("PDD"):              return "pdd"
    if rid.startswith("PNTR") or rid.startswith("PNR"): return "pntr"
    return "other"

# Cache de claims por (user_id, date_from, date_to) — TTL 2 min
_returns_claims_cache: dict = {}
_returns_claims_locks: dict = {}   # un asyncio.Lock por clave de caché
_RETURNS_CLAIMS_TTL = 120  # seg

async def _fetch_all_claims_cached(client, df, dt) -> list:
    """fetch_all_claims con cache de 2 min para compartir entre summary/table/timeline.

    Usa double-checked locking por clave para evitar que N endpoints concurrentes
    (summary + table + analysis + top-products + timeline) fetcheen ML en paralelo
    cuando el cache está vacío, lo que provoca 429 → MeliApiError 'Max retries exceeded'.
    """
    import time as _tc
    key = (client.user_id, df or "", dt or "")
    # Fast-path: hit de caché sin adquirir lock
    entry = _returns_claims_cache.get(key)
    if entry and (_tc.time() - entry[0]) < _RETURNS_CLAIMS_TTL:
        return entry[1]
    # Slow-path: adquirir lock por clave — sólo un fetch simultáneo por (user, desde, hasta)
    if key not in _returns_claims_locks:
        _returns_claims_locks[key] = asyncio.Lock()
    async with _returns_claims_locks[key]:
        # Re-check: otra coroutine pudo haber poblado el cache mientras esperábamos el lock
        entry = _returns_claims_cache.get(key)
        if entry and (_tc.time() - entry[0]) < _RETURNS_CLAIMS_TTL:
            return entry[1]
        claims = await client.fetch_all_claims(date_from=df, date_to=dt)
        _returns_claims_cache[key] = (_tc.time(), claims)
        return claims

_bm_retail_cache: tuple[float, dict] | None = None  # (ts, {sku: retail_usd})
_BM_RETAIL_TTL = 600  # 10 min



async def _get_bm_retail_prices() -> dict:
    """Returns {bm_sku: retail_price_usd} with 10-min cache. Uses get_bulk_stock()."""
    global _bm_retail_cache
    import time as _t2
    if _bm_retail_cache and (_t2.time() - _bm_retail_cache[0]) < _BM_RETAIL_TTL:
        return _bm_retail_cache[1]
    try:
        from app.services.binmanager_client import BinManagerClient
        bm = BinManagerClient()
        if not await bm.login():
            return {}
        items = await bm.get_bulk_stock()
        price_map: dict = {}
        for item in items:
            sku = (item.get("SKU") or "").strip()
            if sku:
                price = float(item.get("LastRetailPricePurchaseHistory") or 0)
                if price > 0:
                    price_map[sku] = price
        _bm_retail_cache = (_t2.time(), price_map)
        return price_map
    except Exception as _e:
        logger.warning(f"[BM-RETAIL] Error al obtener precios: {_e}")
        return {}


def _get_retail_ph_map() -> dict:
    """Retorna {bm_sku: last_retail_price_ph_usd} desde _bm_retail_ph_cache (SQLite catalog).
    CERO hits a BM — el catalog se sincroniza 1x/semana y se carga en memoria al arrancar.
    Usado como precio de referencia para calcular márgenes y valor de retornos.
    """
    return {sku: v[1] for sku, v in _bm_retail_ph_cache.items() if v[1] > 0}


