@app.get("/partials/returns-summary", response_class=HTMLResponse)
async def returns_summary_partial(
    request: Request,
    date_from: str = Query("", description="YYYY-MM-DD"),
    date_to: str = Query("", description="YYYY-MM-DD"),
    account_id: str = Query("", description="ML user_id de la cuenta a consultar"),
):
    client = await get_meli_client(user_id=account_id or None)
    if not client:
        return HTMLResponse("<p>Error: No autenticado</p>")
    try:
        df = date_from or None
        dt = date_to or None

        # Fetch en paralelo: todos los reclamos + user info para tasa oficial ML
        all_claims, _user_info = await asyncio.gather(
            _fetch_all_claims_cached(client, df, dt),
            client.get_user_info()
        )
        ml_claims_rate = (_user_info.get("seller_reputation", {})
                          .get("metrics", {}).get("claims", {}).get("rate", None))

        total = len(all_claims)
        opened = sum(1 for c in all_claims if c.get("status") == "opened")
        closed = total - opened

        # Count urgent (opened con due_date < 24h)
        from datetime import datetime, timezone
        urgent = 0
        for c in all_claims:
            if c.get("status") != "opened":
                continue
            for player in c.get("players", []):
                if player.get("role") == "respondent":
                    for a in player.get("available_actions", []):
                        if a.get("mandatory") and a.get("due_date"):
                            try:
                                due_dt = datetime.fromisoformat(
                                    a["due_date"].replace("Z", "+00:00"))
                                remaining_h = (due_dt - datetime.now(timezone.utc)).total_seconds() / 3600
                                if remaining_h < 24:
                                    urgent += 1
                            except Exception:
                                pass
                    break

        # Total orders para tasa de retorno
        total_orders = 0
        try:
            orders_data = await client.get(
                "/orders/search",
                params={"seller": _user_info.get("id", ""),
                        "sort": "date_asc", "offset": 0, "limit": 1,
                        **({"date_from": df} if df else {}),
                        **({"date_to": dt} if dt else {})}
            )
            total_orders = orders_data.get("paging", {}).get("total", 0)
        except Exception:
            pass

        return_rate = (total / total_orders * 100) if total_orders > 0 else 0.0

        # ── Valor monetario y costo real (AvgCostQTY) ──────────────────────
        valor_mxn = 0.0
        costo_usd = 0.0
        try:
            oids = list({str(c.get("resource_id", "")) for c in all_claims
                         if c.get("resource") == "order" and c.get("resource_id")})
            if oids:
                sem_v = asyncio.Semaphore(5)
                async def _fetch_order_val(oid):
                    async with sem_v:
                        try:
                            order = await client.get(f"/orders/{oid}")
                            items_o = order.get("order_items", [])
                            sku = ""
                            if items_o:
                                item_d = items_o[0].get("item", {})
                                sku = item_d.get("seller_custom_field") or item_d.get("seller_sku") or ""
                            return float(order.get("total_amount") or 0), sku
                        except Exception:
                            return 0.0, ""
                vals = await asyncio.gather(*[_fetch_order_val(o) for o in oids],
                                            return_exceptions=True)
                skus_returned = []
                for v in vals:
                    if isinstance(v, tuple):
                        valor_mxn += v[0]
                        if v[1]:
                            skus_returned.append(normalize_to_bm_sku(v[1]))
                # Costo real = AvgCostQTY de BM (no RetailPrice)
                retail_ph_map = _get_retail_ph_map()
                costo_usd = sum(retail_ph_map.get(s, 0.0) for s in skus_returned if s)
        except Exception as _ev:
            logger.warning(f"[RETURNS-SUMMARY] valor error: {_ev}")

        # Breakdown por categoría y stage
        by_category = {"pdd": 0, "pntr": 0, "other": 0}
        by_stage = {"claim": 0, "dispute": 0, "other": 0}
        for c in all_claims:
            cat = _claim_category(c.get("reason_id", ""))
            by_category[cat] = by_category.get(cat, 0) + 1
            stg = (c.get("stage") or "other").lower()
            stage_key = stg if stg in ("claim", "dispute") else "other"
            by_stage[stage_key] = by_stage.get(stage_key, 0) + 1

        summary = SimpleNamespace(
            total=total,
            opened=opened,
            closed=closed,
            urgent=urgent,
            total_orders=total_orders,
            return_rate=round(return_rate, 2),
            valor_mxn=round(valor_mxn, 2),
            costo_usd=round(costo_usd, 2),
            ml_claims_rate=ml_claims_rate,
            by_category=by_category,
            by_stage=by_stage,
        )

        return templates.TemplateResponse(request, "partials/returns_summary.html", {            "summary": summary,
            "date_from": date_from,
            "date_to": date_to,
        })
    except Exception as e:
        return HTMLResponse(f'<p class="text-center py-4 text-red-500">Error cargando resumen de retornos: {e}</p>')
    finally:
        await client.close()


@app.get("/partials/returns-table", response_class=HTMLResponse)
async def returns_table_partial(
    request: Request,
    offset: int = Query(0, ge=0),
    limit: int = Query(20, ge=1, le=50),
    status: str = Query(""),
    date_from: str = Query("", description="YYYY-MM-DD"),
    date_to: str = Query("", description="YYYY-MM-DD"),
    account_id: str = Query("", description="ML user_id de la cuenta a consultar"),
    claim_type: str = Query("", description="pdd | pntr | other — vacío = todos"),
):
    client = await get_meli_client(user_id=account_id or None)
    if not client:
        return HTMLResponse("<p>Error: No autenticado</p>")
    try:
        df = date_from or None
        dt = date_to or None
        params_status = status if status else None

        # Todos los reclamos del período — sin filtrar solo PDD
        all_claims = await _fetch_all_claims_cached(client, df, dt)
        # Filtrar por status si se pidió
        if params_status:
            all_claims = [c for c in all_claims if c.get("status") == params_status]
        # Filtrar por tipo de reclamo (categoría) si se pidió
        if claim_type:
            all_claims = [c for c in all_claims if _claim_category(c.get("reason_id", "")) == claim_type]

        total_all = len(all_claims)
        paging = {"total": total_all, "offset": offset, "limit": limit}
        raw_claims = all_claims[offset:offset + limit]

        # Refresh status de reclamos abiertos via detail endpoint
        opened_ids = [c for c in raw_claims if c.get("status") == "opened"]
        if opened_ids:
            sem_refresh = asyncio.Semaphore(5)

            async def _refresh_status(claim):
                async with sem_refresh:
                    try:
                        detail = await client.get_claim_detail(str(claim.get("id", "")))
                        if isinstance(detail, dict) and detail.get("status"):
                            claim["status"] = detail["status"]
                            if detail.get("stage"):
                                claim["stage"] = detail["stage"]
                            if detail.get("players"):
                                claim["players"] = detail["players"]
                            if detail.get("type"):
                                claim["claim_type"] = detail["type"]
                            if "affects_reputation" in detail:
                                claim["affects_reputation"] = detail["affects_reputation"]
                            if "has_incentive" in detail:
                                claim["has_incentive"] = detail["has_incentive"]
                    except Exception:
                        pass

            await asyncio.gather(*[_refresh_status(c) for c in opened_ids[:30]],
                                 return_exceptions=True)

        # Batch fetch info de órdenes — incluye SKU BM
        order_ids = list({str(c.get("resource_id", "")) for c in raw_claims
                          if c.get("resource") == "order" and c.get("resource_id")})
        orders_map = {}
        if order_ids:
            sem_ord = asyncio.Semaphore(5)
            async def _fetch_order_info_tbl(oid):
                async with sem_ord:
                    try:
                        order = await client.get(f"/orders/{oid}")
                        oi = order.get("order_items", [])
                        if oi:
                            item = oi[0].get("item", {})
                            # seller_custom_field a veces viene vacío en /orders aunque el
                            # listing sí tenga SKU — ML también expone seller_sku (mismo dato,
                            # nombre de campo distinto). Ver DEVLOG 2026-07-16.
                            raw_sku = item.get("seller_custom_field") or item.get("seller_sku") or ""
                            return oid, {
                                "title":   item.get("title", ""),
                                "price":   order.get("total_amount", 0),
                                "item_id": item.get("id", ""),
                                "bm_sku":  normalize_to_bm_sku(raw_sku) if raw_sku else "",
                            }
                    except Exception:
                        pass
                    return oid, {}
            ord_results = await asyncio.gather(
                *[_fetch_order_info_tbl(oid) for oid in order_ids[:20]],
                return_exceptions=True
            )
            for r in ord_results:
                if isinstance(r, tuple):
                    orders_map[r[0]] = r[1]

        # Mensajes del reclamo
        sem = asyncio.Semaphore(5)
        claim_messages_map = {}

        async def _fetch_msgs(claim_id):
            async with sem:
                try:
                    msgs = await client.get_claim_messages(str(claim_id))
                    if isinstance(msgs, list):
                        return str(claim_id), msgs
                    return str(claim_id), msgs.get("results", msgs.get("messages", []))
                except Exception:
                    return str(claim_id), []

        msg_results = await asyncio.gather(
            *[_fetch_msgs(c.get("id", "")) for c in raw_claims[:20]],
            return_exceptions=True
        )
        for r in msg_results:
            if isinstance(r, tuple):
                claim_messages_map[r[0]] = r[1]

        from datetime import datetime, timezone

        enriched = []
        for c in raw_claims:
            date_created = c.get("date_created", "")
            elapsed_str, elapsed_secs = _elapsed_str(date_created)
            days_open = elapsed_secs // 86400 if elapsed_secs else 0

            c_status = c.get("status", "")
            stage = c.get("stage", "")

            # Due date
            due_date_raw = ""
            due_date = ""
            for player in c.get("players", []):
                if player.get("role") == "respondent":
                    for a in player.get("available_actions", []):
                        if a.get("mandatory") and a.get("due_date"):
                            due_date_raw = a["due_date"]
                            due_date = due_date_raw[:10]
                            break
                    break

            # Countdown hours
            countdown_hours = None
            if due_date_raw and c_status == "opened":
                try:
                    due_dt = datetime.fromisoformat(due_date_raw.replace("Z", "+00:00"))
                    remaining = due_dt - datetime.now(timezone.utc)
                    countdown_hours = max(0, round(remaining.total_seconds() / 3600, 1))
                except Exception:
                    pass

            # Urgency
            if c_status == "opened":
                if countdown_hours is not None:
                    urgency = "red" if countdown_hours < 8 else ("yellow" if countdown_hours < 24 else "green")
                else:
                    urgency = "red" if days_open > 7 else ("yellow" if days_open > 3 else "green")
            else:
                urgency = "gray"

            reason_id = c.get("reason_id", "")
            reason_desc = _claim_reason_label(reason_id)
            category   = _claim_category(reason_id)

            resource_id = str(c.get("resource_id", ""))
            order_info = orders_map.get(resource_id, {})

            # Mensajes de conversación
            claim_id_str = str(c.get("id", ""))
            raw_msgs = claim_messages_map.get(claim_id_str, [])
            conversation = []
            buyer_complaint = ""
            for msg in raw_msgs:
                sender = msg.get("sender_role", msg.get("role", ""))
                text = msg.get("text", msg.get("message", ""))
                msg_date = msg.get("date_created", "")
                if sender == "complainant" and text and not buyer_complaint:
                    buyer_complaint = text
                conversation.append({
                    "sender": sender,
                    "text": text,
                    "date": msg_date[:16].replace("T", " ") if msg_date else "",
                })

            # Sugerencias contextuales por tipo de reclamo
            suggestions = []
            if c_status == "opened":
                if countdown_hours is not None and countdown_hours < 24:
                    suggestions.append("URGENTE: Responde antes de " + due_date + " para evitar penalizacion")
                if category == "pdd":
                    suggestions.append("Solicita fotos del defecto o diferencia al comprador")
                    suggestions.append("Ofrece solucion: reemplazo, devolucion o descuento")
                elif category == "pntr":
                    suggestions.append("Verifica el tracking del envio y comparte la guia al comprador")
                    suggestions.append("Si el paquete esta entregado, solicita foto de quien recibio")
                else:
                    suggestions.append("Revisa el detalle del reclamo y responde con evidencia")
                if stage == "dispute":
                    suggestions.append("Responde al mediador de MeLi con evidencia clara")
            else:
                suggestions.append("Retorno resuelto — revisa si el producto tiene un problema recurrente")

            _affects_rep = c.get("affects_reputation", "")
            _has_incentive = c.get("has_incentive", False)
            _claim_type = c.get("claim_type", "")

            enriched.append(SimpleNamespace(
                id=c.get("id", ""),
                order_id=resource_id,
                status=c_status,
                stage=stage,
                claim_type=_claim_type,
                affects_reputation=_affects_rep,
                has_incentive=_has_incentive,
                date_created=date_created[:10] if date_created else "-",
                _sort_date=date_created or "",
                elapsed=elapsed_str,
                days_open=days_open,
                urgency=urgency,
                countdown_hours=countdown_hours,
                reason_desc=reason_desc,
                reason_id=reason_id,
                category=category,
                product_title=order_info.get("title", ""),
                product_price=order_info.get("price", 0),
                item_id=str(order_info.get("item_id", "")),
                bm_sku=order_info.get("bm_sku", ""),
                due_date=due_date,
                buyer_complaint=buyer_complaint,
                conversation=conversation,
                suggestions=suggestions,
                tracking={},
            ))

        # Sort: urgency first, then by date desc
        _urgency_order = {"red": 0, "yellow": 1, "green": 2, "gray": 3}
        enriched.sort(key=lambda c: (_urgency_order.get(c.urgency, 3), not c._sort_date, c._sort_date))

        return templates.TemplateResponse(request, "partials/returns_table.html", {            "returns": enriched,
            "paging": paging,
            "offset": offset,
            "limit": limit,
            "status": status,
        })
    except Exception as e:
        return HTMLResponse(f'<p class="text-center py-4 text-red-500">Error cargando retornos: {e}</p>')
    finally:
        await client.close()


@app.get("/api/returns/analysis")
async def returns_analysis(
    date_from: str = Query("", description="YYYY-MM-DD"),
    date_to: str = Query("", description="YYYY-MM-DD"),
    limit: int = Query(5, ge=1, le=20),
    account_id: str = Query("", description="ML user_id de la cuenta a consultar"),
):
    client = await get_meli_client(user_id=account_id or None)
    if not client:
        return {"error": "No autenticado"}
    try:
        df = date_from or None
        dt = date_to or None

        all_claims = await _fetch_all_claims_cached(client, df, dt)

        total = len(all_claims)
        opened = sum(1 for c in all_claims if c.get("status") == "opened")
        closed = total - opened

        order_ids = list({str(c.get("resource_id", "")) for c in all_claims
                          if c.get("resource") == "order" and c.get("resource_id")})
        sem = asyncio.Semaphore(5)

        async def _fetch_order_info(oid):
            async with sem:
                try:
                    order = await client.get(f"/orders/{oid}")
                    oi = order.get("order_items", [])
                    if oi:
                        item = oi[0].get("item", {})
                        return oid, {"title": item.get("title", ""), "item_id": str(item.get("id", ""))}
                except Exception:
                    pass
                return oid, {"title": "", "item_id": ""}

        info_results = await asyncio.gather(
            *[_fetch_order_info(oid) for oid in order_ids[:40]],
            return_exceptions=True
        )
        order_info_map = {}
        for r in info_results:
            if isinstance(r, tuple):
                order_info_map[r[0]] = r[1]

        product_counts: dict = {}
        for c in all_claims:
            oid = str(c.get("resource_id", ""))
            info = order_info_map.get(oid, {})
            title = info.get("title") or "Producto desconocido"
            item_id = info.get("item_id", "")
            if title not in product_counts:
                product_counts[title] = {"title": title, "item_id": item_id, "count": 0}
            product_counts[title]["count"] += 1

        top_products = sorted(product_counts.values(), key=lambda x: x["count"], reverse=True)[:limit]

        return {
            "total": total,
            "by_status": {"opened": opened, "closed": closed},
            "top_products": top_products,
        }
    except Exception as e:
        return {"error": str(e)}
    finally:
        await client.close()


@app.get("/api/returns/top-products")
async def returns_top_products(
    date_from: str = Query("", description="Period A start YYYY-MM-DD"),
    date_to: str = Query("", description="Period A end YYYY-MM-DD"),
    compare_from: str = Query("", description="Period B start YYYY-MM-DD"),
    compare_to: str = Query("", description="Period B end YYYY-MM-DD"),
    limit: int = Query(10, ge=1, le=20),
    account_id: str = Query("", description="ML user_id de la cuenta a consultar"),
):
    """Top N returned products with period comparison, reason breakdown, and action recommendations."""
    client = await get_meli_client(user_id=account_id or None)
    if not client:
        return {"error": "No autenticado"}
    try:
        df_a = date_from or None
        dt_a = date_to or None
        df_b = compare_from or None
        dt_b = compare_to or None

        async def _fetch_all(df, dt):
            return await _fetch_all_claims_cached(client, df, dt)

        if df_b or dt_b:
            pdd_a, pdd_b = await asyncio.gather(_fetch_all(df_a, dt_a), _fetch_all(df_b, dt_b))
        else:
            pdd_a = await _fetch_all(df_a, dt_a)
            pdd_b = []

        oids_a = {str(c.get("resource_id", "")) for c in pdd_a
                  if c.get("resource") == "order" and c.get("resource_id")}
        oids_b = {str(c.get("resource_id", "")) for c in pdd_b
                  if c.get("resource") == "order" and c.get("resource_id")}
        max_orders = max(limit * 6, 120)
        all_oids = list(oids_a | oids_b)[:max_orders]

        sem = asyncio.Semaphore(3)

        async def _fetch_order_info(oid):
            async with sem:
                try:
                    order = await asyncio.wait_for(client.get(f"/orders/{oid}"), timeout=8.0)
                    oi = order.get("order_items", [])
                    if oi:
                        item = oi[0].get("item", {})
                        item_id_str = str(item.get("id", ""))
                        # seller_custom_field a veces viene vacío aunque el listing sí tenga
                        # SKU — ML también expone seller_sku (mismo dato, campo distinto).
                        sku = item.get("seller_custom_field") or item.get("seller_sku") or ""
                        if not sku and item_id_str:
                            try:
                                det = await asyncio.wait_for(
                                    client.get(f"/items/{item_id_str}", params={"attributes": "seller_custom_field,seller_sku,title"}),
                                    timeout=5.0
                                )
                                sku = det.get("seller_custom_field") or det.get("seller_sku") or ""
                            except Exception:
                                pass
                        return oid, {
                            "title": item.get("title", "") or "Producto desconocido",
                            "item_id": item_id_str,
                            "sku": sku,
                            "sale_amount": float(order.get("total_amount") or 0),
                        }
                except Exception:
                    pass
                return oid, {"title": "Producto desconocido", "item_id": "", "sku": "", "sale_amount": 0.0}

        results = await asyncio.gather(*[_fetch_order_info(oid) for oid in all_oids], return_exceptions=True)
        order_map = {r[0]: r[1] for r in results if isinstance(r, tuple)}

        # Precio de referencia = LastRetailPricePurchaseHistory desde catálogo local (sin hit BM)
        bm_avg_costs_tp = _get_retail_ph_map()

        def _count_by_product(claims):
            counts = {}
            for c in claims:
                oid = str(c.get("resource_id", ""))
                claim_id = str(c.get("id", ""))
                info = order_map.get(oid, {"title": "", "item_id": "", "sku": "", "sale_amount": 0.0})
                # Fallback: usar claim_id para que cada reclamo sin producto sea único (no se agrupen)
                title = info.get("title") or f"Sin título (Reclamo #{claim_id})"
                reason_id = c.get("reason_id", "")
                status = c.get("status", "")
                if title not in counts:
                    counts[title] = {
                        "title": title, "item_id": info["item_id"],
                        "sku": normalize_to_bm_sku(info.get("sku", "")),
                        "count": 0, "opened": 0, "closed": 0, "reasons": {},
                        "sale_amount_mxn": 0.0,
                    }
                counts[title]["count"] += 1
                counts[title]["sale_amount_mxn"] += info.get("sale_amount", 0.0)
                if status == "opened":
                    counts[title]["opened"] += 1
                else:
                    counts[title]["closed"] += 1
                label = _claim_reason_label(reason_id)
                counts[title]["reasons"][label] = counts[title]["reasons"].get(label, 0) + 1
            return counts

        def _recommendation(reasons: dict, opened: int, total: int) -> dict:
            if not reasons:
                return {"text": "Analizar manualmente", "color": "gray",
                        "actions": ["Revisar historial de mensajes de compradores"]}
            top_reason = max(reasons, key=reasons.get)
            top_pct = round(reasons[top_reason] / total * 100) if total > 0 else 0
            urgency = "high" if opened > 0 else "medium"
            r = top_reason.lower()
            if "descripción" in r or "coincide" in r:
                return {"text": "Actualizar fotos y descripción",
                        "detail": f"{top_pct}% no coincide con descripción",
                        "color": "orange", "urgency": urgency,
                        "actions": ["Verificar fotos vs producto real",
                                    "Actualizar especificaciones exactas",
                                    "Agregar tabla de medidas si aplica"]}
            elif "incorrecto" in r or "diferente" in r:
                return {"text": "Revisar proceso de picking",
                        "detail": f"{top_pct}% producto incorrecto enviado",
                        "color": "red", "urgency": urgency,
                        "actions": ["Verificar SKUs en almacén",
                                    "Auditar últimos envíos de este producto",
                                    "Separar variantes similares"]}
            elif "defecto" in r or "fábrica" in r or "funciona" in r:
                return {"text": "Revisar calidad con proveedor",
                        "detail": f"{top_pct}% defectos de producto",
                        "color": "red", "urgency": urgency,
                        "actions": ["Contactar proveedor con evidencia",
                                    "Revisar lote actual en almacén",
                                    "Implementar control de calidad pre-envío"]}
            elif "tránsito" in r or "dañado" in r:
                return {"text": "Mejorar empaque para envío",
                        "detail": f"{top_pct}% daños en tránsito",
                        "color": "yellow", "urgency": "medium",
                        "actions": ["Usar caja más resistente",
                                    "Agregar protección interna (burbuja/foam)",
                                    "Verificar peso y dimensiones declarados"]}
            elif "faltante" in r:
                return {"text": "Verificar contenido del paquete",
                        "detail": f"{top_pct}% partes faltantes",
                        "color": "orange", "urgency": urgency,
                        "actions": ["Crear checklist de contenido por producto",
                                    "Verificar accesorios listados en descripción",
                                    "Revisar proceso de empaque con proveedor"]}
            else:
                return {"text": "Analizar patrón de retornos",
                        "detail": f"Razón principal: {top_reason}",
                        "color": "gray", "urgency": "medium",
                        "actions": ["Revisar mensajes de compradores",
                                    "Comparar con descripción actual del producto"]}

        counts_a = _count_by_product(pdd_a)
        counts_b = _count_by_product(pdd_b)
        total_a = len(pdd_a)
        total_b = len(pdd_b)

        top_a = sorted(counts_a.values(), key=lambda x: x["count"], reverse=True)[:limit]

        products = []
        # FX para convertir MXN → USD en cálculo de margen
        _fx = _manual_fx_rate if _manual_fx_rate > 0 else 18.0
        try:
            _fx_cached = await _get_usd_to_mxn(client)
            if _fx_cached > 0:
                _fx = _fx_cached
        except Exception:
            pass

        for p in top_a:
            count_a = p["count"]
            b_entry = counts_b.get(p["title"])
            count_b = b_entry["count"] if b_entry else (0 if pdd_b else None)
            delta_pct = None
            if count_b is not None and count_b > 0:
                delta_pct = round((count_a - count_b) / count_b * 100, 1)
            rec = _recommendation(p["reasons"], p["opened"], count_a)
            sku = p.get("sku", "")
            # Precio de referencia = LastRetailPricePurchaseHistory (catálogo local, sin BM)
            retail_ph_unit = bm_avg_costs_tp.get(sku, 0.0) if sku else 0.0
            retail_ph_total = retail_ph_unit * count_a

            # Margen de recuperación:
            # sale_amount_mxn = lo que cobró el vendedor (bruto)
            # sale_usd = convertido a USD con FX
            # profit_usd = sale_usd - retail_ph_total (pérdida si negativo)
            # profit_pct = profit_usd / retail_ph_total * 100
            sale_mxn = p.get("sale_amount_mxn", 0.0)
            sale_usd = round(sale_mxn / _fx, 2) if _fx > 0 else 0.0
            profit_usd = round(sale_usd - retail_ph_total, 2) if retail_ph_total > 0 else None
            profit_pct = round(profit_usd / retail_ph_total * 100, 1) if (profit_usd is not None and retail_ph_total > 0) else None

            products.append({
                "title": p["title"],
                "item_id": p["item_id"],
                "sku": sku,
                "count_a": count_a,
                "count_b": count_b,
                "delta_pct": delta_pct,
                "pct_of_total": round(count_a / total_a * 100, 1) if total_a > 0 else 0,
                "opened": p["opened"],
                "closed": p["closed"],
                "reasons": p["reasons"],
                "recommendation": rec,
                "sale_amount_mxn": round(sale_mxn, 2),
                "sale_usd": sale_usd,
                "retail_ph_unit": round(retail_ph_unit, 2),
                "retail_ph_total": round(retail_ph_total, 2),
                "profit_usd": profit_usd,
                "profit_pct": profit_pct,
            })

        def _label(df, dt):
            if df and dt: return f"{df} al {dt}"
            elif df: return f"Desde {df}"
            elif dt: return f"Hasta {dt}"
            return "Todo el historial"

        return {
            "period_a": {"label": _label(df_a, dt_a), "total": total_a, "products": products},
            "period_b": {"label": _label(df_b, dt_b), "total": total_b} if (df_b or dt_b) else None,
        }
    except Exception as e:
        return {"error": str(e)}
    finally:
        await client.close()


@app.get("/api/returns/timeline")
async def returns_timeline(
    date_from: str = Query("", description="YYYY-MM-DD"),
    date_to: str = Query("", description="YYYY-MM-DD"),
    granularity: str = Query("auto", description="day | week | auto"),
    account_id: str = Query("", description="ML user_id de la cuenta a consultar"),
):
    """Timeline de retornos agrupados por día o semana para gráfica de tendencia."""
    client = await get_meli_client(user_id=account_id or None)
    if not client:
        return {"error": "No autenticado"}
    try:
        from datetime import datetime, timedelta, timezone
        df = date_from or None
        dt = date_to or None

        all_claims = await _fetch_all_claims_cached(client, df, dt)

        # Auto-granularity
        gran = granularity
        if gran == "auto":
            if date_from and date_to:
                try:
                    days_range = (datetime.fromisoformat(date_to) - datetime.fromisoformat(date_from)).days
                    gran = "week" if days_range > 90 else "day"
                except Exception:
                    gran = "day"
            else:
                gran = "day"

        buckets: dict = {}
        for c in all_claims:
            dc = c.get("date_created", "")
            if not dc:
                continue
            try:
                dt_obj = datetime.fromisoformat(dc.replace("Z", "+00:00"))
            except Exception:
                continue
            if gran == "week":
                week_start = dt_obj - timedelta(days=dt_obj.weekday())
                key = week_start.strftime("%Y-%m-%d")
            else:
                key = dc[:10]
            reason_label = _claim_reason_label(c.get("reason_id", ""))
            if key not in buckets:
                buckets[key] = {"date": key, "count": 0, "reasons": {}}
            buckets[key]["count"] += 1
            buckets[key]["reasons"][reason_label] = buckets[key]["reasons"].get(reason_label, 0) + 1

        timeline = sorted(buckets.values(), key=lambda x: x["date"])
        return {"timeline": timeline, "granularity": gran, "total": len(all_claims)}
    except Exception as e:
        return {"error": str(e)}
    finally:
        await client.close()


@app.get("/api/returns/global-top")
async def returns_global_top(
    days: int = Query(30, ge=1, le=365, description="Ventana de días hacia atrás"),
    limit: int = Query(10, ge=1, le=20),
):
    """Top N SKUs más retornados sumando TODAS las cuentas ML."""
    from datetime import datetime as _dt2, timedelta as _td2
    accounts = await token_store.get_all_tokens()
    if not accounts:
        return {"error": "No hay cuentas ML configuradas", "total": 0, "products": []}

    _now = _dt2.utcnow()
    df = (_now - _td2(days=days)).strftime("%Y-%m-%d")
    dt = _now.strftime("%Y-%m-%d")

    sem_acc = asyncio.Semaphore(2)

    async def _fetch_for_account(account):
        async with sem_acc:
            uid = account.get("user_id", "")
            nickname = account.get("nickname") or uid
            try:
                client = await get_meli_client(user_id=uid)
                if not client:
                    return []
                try:
                    claims = await _fetch_all_claims_cached(client, df, dt)
                    for c in claims:
                        c["_account_id"] = uid
                        c["_account_nickname"] = nickname
                    return claims
                finally:
                    await client.close()
            except Exception as _exc:
                logger.warning(f"[GLOBAL-TOP] cuenta {uid}: {_exc}")
                return []

    nested = await asyncio.gather(*[_fetch_for_account(a) for a in accounts], return_exceptions=True)
    all_claims: list = []
    for r in nested:
        if isinstance(r, list):
            all_claims.extend(r)

    if not all_claims:
        return {"total": 0, "days": days, "accounts_count": len(accounts), "products": []}

    # oid → acc_id (primer claim visto para esa orden)
    oids_acc: dict[str, str] = {}
    for c in all_claims:
        if c.get("resource") != "order" or not c.get("resource_id"):
            continue
        oid = str(c["resource_id"])
        if oid not in oids_acc:
            oids_acc[oid] = c.get("_account_id", "")

    max_ords = max(limit * 6, 120)
    oids_to_fetch = list(oids_acc.items())[:max_ords]

    sem_ord = asyncio.Semaphore(3)
    order_map: dict = {}

    async def _fetch_ord_global(oid: str, acc_id: str):
        async with sem_ord:
            try:
                client = await get_meli_client(user_id=acc_id)
                if not client:
                    return oid, {}
                try:
                    order = await asyncio.wait_for(client.get(f"/orders/{oid}"), timeout=8.0)
                    oi = order.get("order_items", [])
                    if oi:
                        item = oi[0].get("item", {})
                        item_id_str = str(item.get("id", ""))
                        # seller_custom_field a veces viene vacío aunque el listing sí tenga
                        # SKU — ML también expone seller_sku (mismo dato, campo distinto).
                        sku = item.get("seller_custom_field") or item.get("seller_sku") or ""
                        if not sku and item_id_str:
                            try:
                                det = await asyncio.wait_for(
                                    client.get(f"/items/{item_id_str}", params={"attributes": "seller_custom_field,seller_sku,title"}),
                                    timeout=5.0
                                )
                                sku = det.get("seller_custom_field") or det.get("seller_sku") or ""
                            except Exception:
                                pass
                        return oid, {
                            "title": item.get("title", "") or "Producto desconocido",
                            "item_id": item_id_str,
                            "sku": sku,
                            "sale_amount": float(order.get("total_amount") or 0),
                        }
                finally:
                    await client.close()
            except Exception:
                pass
            return oid, {"title": "Producto desconocido", "item_id": "", "sku": "", "sale_amount": 0.0}

    ord_results = await asyncio.gather(*[_fetch_ord_global(oid, acc) for oid, acc in oids_to_fetch], return_exceptions=True)
    for r in ord_results:
        if isinstance(r, tuple):
            order_map[r[0]] = r[1]

    retail_map = _get_retail_ph_map()

    counts: dict = {}
    total_claims = len(all_claims)
    for c in all_claims:
        oid = str(c.get("resource_id", ""))
        info = order_map.get(oid, {"title": "", "item_id": "", "sku": "", "sale_amount": 0.0})
        raw_sku = info.get("sku", "")
        sku = normalize_to_bm_sku(raw_sku) if raw_sku else ""
        title = info.get("title") or f"Sin título (Reclamo #{c.get('id', '')})"
        key = sku if sku else title
        acc_nick = c.get("_account_nickname", "")

        if key not in counts:
            counts[key] = {
                "title": title, "sku": sku,
                "item_id": info.get("item_id", ""),
                "count": 0, "opened": 0, "closed": 0,
                "reasons": {}, "accounts": {},
                "sale_amount_mxn": 0.0,
            }
        counts[key]["count"] += 1
        counts[key]["sale_amount_mxn"] += info.get("sale_amount", 0.0)
        if c.get("status") == "opened":
            counts[key]["opened"] += 1
        else:
            counts[key]["closed"] += 1
        label = _claim_reason_label(c.get("reason_id", ""))
        counts[key]["reasons"][label] = counts[key]["reasons"].get(label, 0) + 1
        if acc_nick:
            counts[key]["accounts"][acc_nick] = counts[key]["accounts"].get(acc_nick, 0) + 1

    top = sorted(counts.values(), key=lambda x: x["count"], reverse=True)[:limit]
    for p in top:
        sku = p.get("sku", "")
        p["retail_ph_unit"] = retail_map.get(sku, 0.0) if sku else 0.0
        p["pct_of_total"] = round(p["count"] / total_claims * 100, 1) if total_claims > 0 else 0

    return {
        "total": total_claims,
        "days": days,
        "accounts_count": len(accounts),
        "products": top,
    }


# ── Amazon refunds cache ──────────────────────────────────────────────────────
_amz_refunds_cache: dict = {}   # {(seller_id, days): (ts, [refunds])}
_AMZ_REFUNDS_TTL = 3600 * 3    # 3 horas — refund data no cambia en tiempo real

async def _fetch_amazon_refunds_cached(seller_id: str, days: int) -> list:
    """get_refunds_detail() con cache de 3h para no martillar la Financial Events API."""
    import time as _ta
    key = (seller_id, days)
    entry = _amz_refunds_cache.get(key)
    if entry and (_ta.time() - entry[0]) < _AMZ_REFUNDS_TTL:
        return entry[1]
    try:
        from app.services.amazon_client import get_amazon_client as _get_amz
        client = await _get_amz(seller_id)
        if not client:
            return []
        refunds = await client.get_refunds_detail(days=days)
        _amz_refunds_cache[key] = (_ta.time(), refunds)
        return refunds
    except Exception as _exc:
        logger.warning(f"[AMZ-REFUNDS] Error {seller_id}: {_exc}")
        return []


# Amazon return reason codes → etiquetas en español
_AMZ_REASON_MAP: dict = {
    "CUSTOMER_RETURN":      "Arrepentimiento de compra",
    "DEFECTIVE":            "Producto defectuoso",
    "NOT_AS_DESCRIBED":     "No coincide con descripción",
    "DAMAGED_BY_CARRIER":   "Dañado en tránsito",
    "DAMAGED_BY_FC":        "Dañado en centro de distribución Amazon",
    "QUALITY_UNACCEPTABLE": "Calidad inaceptable",
    "WRONG_ITEM_SENT":      "Producto incorrecto enviado",
    "ORDERED_WRONG_ITEM":   "Cliente ordenó producto equivocado",
    "MISSING_PARTS":        "Piezas/accesorios faltantes",
    "NOT_COMPATIBLE":       "Incompatible con dispositivo",
    "EXPIRED":              "Producto vencido",
    "SWITCHEROO":           "Fraude (switcheroo)",
    "UNDELIVERABLE":        "No entregado",
    "UNDELIVERABLE_UNKNOWN": "No entregado (motivo desconocido)",
    "REFUSED":              "Rechazado por comprador",
    "UNWANTED_ITEM":        "Ya no lo quiere/necesita",
    "UNAUTHORIZED_PURCHASE": "Compra no autorizada",
    "ACCIDENTAL_ORDER":     "Orden accidental",
    "FOUND_BETTER_PRICE":   "Encontró mejor precio",
    "NO_LONGER_NEEDED":     "Ya no lo necesita",
    "NO_REASON_GIVEN":      "Sin motivo especificado",
    "APPAREL_TOO_SMALL":    "Talla chica (ropa/accesorios)",
    "APPAREL_TOO_LARGE":    "Talla grande (ropa/accesorios)",
    "APPAREL_STYLE":        "No le gustó el estilo (ropa/accesorios)",
    "EXTRA_ITEM":           "Recibió producto extra/duplicado",
    "MISORDERED":           "Ordenado por error",
    "PERFORMANCE_UNACCEPTABLE": "Rendimiento no aceptable",
}

def _amz_reason_label(reason: str) -> str:
    return _AMZ_REASON_MAP.get((reason or "").upper().strip(), reason or "Devolución Amazon")


# ── Amazon returns report (razón real, solo FBA) ───────────────────────────────
# get_refunds_detail() (Finances API) nunca trae razón real — el campo llega vacío.
# La razón real (y el comentario del cliente) solo existe en el reporte
# GET_FBA_FULFILLMENT_CUSTOMER_RETURNS_DATA (Reports API, solo FBA). Ese método
# pedía el reporte equivocado hasta 2026-07-21 (GET_FLAT_FILE_RETURNS_DATA_BY_RETURN_DATE,
# columnas distintas, siempre devolvía 0 filas) — ver amazon_client.py get_returns_report()
# para el detalle del bug y su fix. Cache largo porque generar el reporte es caro (polling).
_amz_returns_report_cache: dict = {}   # {(seller_id, days): (ts, [returns])}
_AMZ_RETURNS_REPORT_TTL = 3600 * 6    # 6 horas

async def _fetch_amazon_returns_report_cached(seller_id: str, days: int) -> list:
    """get_returns_report() con cache de 6h. Amazon limita el reporte a 60 días —
    si days > 60 se acota (el reporte cubre solo la ventana más reciente)."""
    import time as _trr
    from datetime import datetime as _dtr, timedelta as _tdr
    key = (seller_id, days)
    entry = _amz_returns_report_cache.get(key)
    if entry and (_trr.time() - entry[0]) < _AMZ_RETURNS_REPORT_TTL:
        return entry[1]
    try:
        from app.services.amazon_client import get_amazon_client as _get_amz_rr
        client = await _get_amz_rr(seller_id)
        if not client:
            return []
        capped_days = min(days, 60)
        _now = _dtr.utcnow()
        date_from = (_now - _tdr(days=capped_days)).strftime("%Y-%m-%d")
        date_to = _now.strftime("%Y-%m-%d")
        items = await client.get_returns_report(date_from, date_to)
        _amz_returns_report_cache[key] = (_trr.time(), items)
        return items
    except Exception as _exc:
        logger.warning(f"[AMZ-RETURNS-REPORT] Error {seller_id}: {_exc}")
        return []


# ── Reembolsos FBA ya aprobados (idea tomada de Helium10 Managed Refund
# Service — lo detectamos gratis con el reporte que Amazon ya expone, sin
# pagarle comisión a un tercero por presentar el reclamo). Mismo patrón de
# cache que el reporte de devoluciones (generar el reporte es caro/lento).
_amz_reimbursements_cache: dict = {}
_AMZ_REIMBURSEMENTS_TTL = 3600 * 6

async def _fetch_amazon_reimbursements_cached(seller_id: str, days: int) -> list:
    import time as _tri
    from datetime import datetime as _dtri, timedelta as _tdri
    key = (seller_id, days)
    entry = _amz_reimbursements_cache.get(key)
    if entry and (_tri.time() - entry[0]) < _AMZ_REIMBURSEMENTS_TTL:
        return entry[1]
    try:
        from app.services.amazon_client import get_amazon_client as _get_amz_reimb
        client = await _get_amz_reimb(seller_id)
        if not client:
            return []
        capped_days = min(days, 60)
        _now = _dtri.utcnow()
        date_from = (_now - _tdri(days=capped_days)).strftime("%Y-%m-%d")
        date_to = _now.strftime("%Y-%m-%d")
        items = await client.get_reimbursements_report(date_from, date_to)
        _amz_reimbursements_cache[key] = (_tri.time(), items)
        return items
    except Exception as _exc:
        logger.warning(f"[AMZ-REIMBURSEMENTS] Error {seller_id}: {_exc}")
        return []


# ── Ventas por SKU Amazon (Fase 2.5 del nav unificado) ─────────────────────────
# get_sku_sales() es N+1 (1 request de items por orden) — igual que
# get_sales_summary_30d(), nunca en vivo por request. Stale-while-revalidate
# igual que _fetch_unified_returns_cached / Finanzas ML. getOrderItems tiene un
# rate limit propio bastante estricto en SP-API (confirmado: 429/QuotaExceeded
# incluso con Semaphore(2)) — con el retry-con-backoff ya existente en _request()
# esto se resuelve solo pero puede tardar; TTL largo (6h, igual que el reporte de
# devoluciones) para no relanzar el cómputo caro seguido.
_amz_sku_sales_cache: dict = {}     # {(seller_id, days): (ts, {sku: {...}})}
_AMZ_SKU_SALES_TTL = 3600 * 6      # 6 horas
_amz_sku_sales_inflight: set = set()

async def _compute_amz_sku_sales(seller_id: str, days: int) -> dict:
    from datetime import datetime as _dts, timedelta as _tds
    from app.services.amazon_client import get_amazon_client as _get_amz_sk
    client = await _get_amz_sk(seller_id)
    if not client:
        return {}
    try:
        _now = _dts.utcnow()
        date_from = (_now - _tds(days=days)).strftime("%Y-%m-%d")
        date_to = _now.strftime("%Y-%m-%d")
        return await client.get_sku_sales(date_from, date_to)
    finally:
        await client.close()


async def _refresh_amz_sku_sales(key: tuple) -> None:
    import time as _tsk
    try:
        seller_id, days = key
        data = await _compute_amz_sku_sales(seller_id, days)
        _amz_sku_sales_cache[key] = (_tsk.time(), data)
    except Exception as _e:
        logger.warning(f"[AMZ-SKU-SALES] Error refrescando {key}: {_e}")
    finally:
        _amz_sku_sales_inflight.discard(key)


async def _fetch_amz_sku_sales_cached(seller_id: str, days: int) -> dict:
    import time as _tsk
    key = (seller_id, days)
    entry = _amz_sku_sales_cache.get(key)
    fresh = entry and (_tsk.time() - entry[0]) < _AMZ_SKU_SALES_TTL
    if fresh:
        return entry[1]
    if key not in _amz_sku_sales_inflight:
        _amz_sku_sales_inflight.add(key)
        asyncio.create_task(_refresh_amz_sku_sales(key))
    if entry:
        return entry[1]
    return {}


@app.get("/partials/amazon-sku-sales-table")
async def amazon_sku_sales_table(
    days: int = Query(30, ge=1, le=365),
    seller_id: str = Query(""),
):
    """Ventas por SKU Amazon — columnas calcadas de sku_sales_table.html (ML):
    SKU, Producto, Cantidad, Ingreso, Stock BM, Retail PH, %Recuperado."""
    sid = seller_id.strip()
    if not sid:
        return {"error": "No hay cuenta Amazon activa", "computing": False, "rows": []}
    sales = await _fetch_amz_sku_sales_cached(sid, days)
    is_computing = not sales and (sid, days) in _amz_sku_sales_inflight
    if is_computing:
        return {"computing": True, "rows": []}

    try:
        listings = await token_store.get_amazon_listings_for_account(sid)
        title_map = {l["sku"]: l["title"] for l in listings if l.get("title")}
    except Exception:
        title_map = {}
    retail_map = _get_retail_ph_map()

    rows = []
    for sku, d in sales.items():
        bm_sku = normalize_to_bm_sku(sku)
        retail_ph = retail_map.get(bm_sku, 0.0)
        revenue_usd = d["revenue"] / (_manual_fx_rate if _manual_fx_rate > 0 else 18.0)
        pct_recuperado = round(revenue_usd / (retail_ph * d["units"]) * 100, 1) if retail_ph > 0 and d["units"] > 0 else None
        _bm_entry = _bm_stock_cache.get(bm_sku)
        bm_stock = _bm_entry[1].get("avail_total") if _bm_entry else None
        rows.append({
            "sku": sku, "title": title_map.get(sku, sku),
            "units": d["units"], "revenue_mxn": d["revenue"], "orders": d["orders"],
            "bm_stock": bm_stock, "retail_ph_usd": retail_ph,
            "pct_recuperado": pct_recuperado,
        })
    rows.sort(key=lambda r: r["units"], reverse=True)
    return {"computing": False, "days": days, "rows": rows, "total_skus": len(rows)}


@app.get("/amazon/sku-sales")
async def amazon_sku_sales_page(request: Request):
    """Alias legacy — Ventas por SKU Amazon ahora vive dentro de #amz-tab-ventas."""
    return RedirectResponse("/amazon?tab=ventas", status_code=302)


# Severidad por código de razón Amazon (mismo formato que _REASON_SEVERITY de ML,
# ver /api/returns/quality-scores). Pesos altos = problema real de calidad del
# producto; bajos = arrepentimiento/logística, no calidad.
_AMZ_REASON_SEVERITY: dict = {
    "DEFECTIVE": 25, "QUALITY_UNACCEPTABLE": 22, "DAMAGED_BY_CARRIER": 18,
    "WRONG_ITEM_SENT": 18, "NOT_AS_DESCRIBED": 15, "MISSING_PARTS": 12,
    "NOT_COMPATIBLE": 10, "SWITCHEROO": 10,
    "CUSTOMER_RETURN": 5, "UNDELIVERABLE": 5, "REFUSED": 5, "EXPIRED": 5,
}
_AMZ_REASON_SEVERITY_DEFAULT = 10  # código no mapeado pero SÍ conocido


async def _aggregate_amazon_returns_by_sku(seller_id: str, days: int, nickname: str = "") -> dict:
    """Agrega refunds Amazon por SKU para UNA cuenta — combina _fetch_amazon_refunds_cached
    (todas las órdenes, sin razón) + _fetch_amazon_returns_report_cached (razón real,
    solo FBA) por order_id. Refund sin match en el reporte (típicamente FBM) cae al
    fallback "Devolución Amazon", igual que antes — no se inventa una razón.

    Usado tanto por el endpoint de una sola cuenta (/amazon/returns) como por
    _compute_unified_returns (cross-cuenta) — antes esa función duplicaba esta misma
    lógica inline por cuenta.
    """
    refunds = await _fetch_amazon_refunds_cached(seller_id, days)
    try:
        reasons_report = await _fetch_amazon_returns_report_cached(seller_id, days)
    except Exception:
        reasons_report = []
    reason_by_order = {
        r["order_id"]: r["reason"] for r in reasons_report
        if r.get("order_id") and r.get("reason")
    }
    # product_name viene directo del reporte de devoluciones (más preciso que
    # cruzar por SKU, porque es el título exacto de ESE listing/orden). Como
    # respaldo para refunds sin match en el reporte (típicamente FBM), se usa
    # el catálogo de listings de la cuenta — antes ninguna de las dos existía
    # y el título caía siempre al SKU crudo (Jovan lo reportó como "una jalada"
    # tras ver Quality Score/Top SKUs sin nombre de producto).
    title_by_order = {
        r["order_id"]: r["product_name"] for r in reasons_report
        if r.get("order_id") and r.get("product_name")
    }
    try:
        _listings = await token_store.get_amazon_listings_for_account(seller_id)
        title_by_sku = {l["sku"]: l["title"] for l in _listings if l.get("title")}
    except Exception:
        title_by_sku = {}

    counts: dict = {}
    for ref in refunds:
        sku_raw = (ref.get("sku") or "").strip()
        sku = normalize_to_bm_sku(sku_raw) if sku_raw else sku_raw
        key = sku if sku else f"amz_{ref.get('order_id', '')}"
        order_id = ref.get("order_id", "")
        reason_code = reason_by_order.get(order_id, "")
        reason_lbl = _amz_reason_label(reason_code) if reason_code else "Devolución Amazon"
        refund_amt = float(ref.get("amount", 0) or 0)
        currency = ref.get("currency", "USD")
        refund_usd = refund_amt if currency == "USD" else refund_amt / 18.0
        real_title = title_by_order.get(order_id) or title_by_sku.get(sku_raw) or title_by_sku.get(sku)

        if key not in counts:
            counts[key] = {
                "title": real_title or sku or sku_raw or key, "sku": sku,
                "item_id": "",
                "count": 0, "opened": 0, "closed": 0,
                "reasons": {}, "accounts": {},
                "platforms": {"ml": 0, "amazon": 0},
                "sale_amount_mxn": 0.0, "refund_usd": 0.0,
                "severity_sum": 0,
            }
        elif sku and not counts[key]["sku"]:
            counts[key]["sku"] = sku
        if real_title and (not counts[key]["title"] or counts[key]["title"] == counts[key]["sku"]):
            counts[key]["title"] = real_title
        counts[key]["count"] += 1
        counts[key]["platforms"]["amazon"] += 1
        counts[key]["refund_usd"] = round(counts[key]["refund_usd"] + refund_usd, 2)
        counts[key]["closed"] += 1  # un refund es un evento financiero ya completado
        counts[key]["reasons"][reason_lbl] = counts[key]["reasons"].get(reason_lbl, 0) + 1
        if reason_code:  # solo se penaliza cuando la razón real SÍ se conoce (FBA)
            counts[key]["severity_sum"] += _AMZ_REASON_SEVERITY.get(
                reason_code.upper().strip(), _AMZ_REASON_SEVERITY_DEFAULT
            )
        if nickname:
            counts[key]["accounts"][nickname] = counts[key]["accounts"].get(nickname, 0) + 1
    return counts


# ── Unified returns cache (ML + Amazon combinado por SKU) ──────────────────────
# Antes esto se calculaba en vivo en cada carga del widget, y para resolver el SKU
# real de un reclamo ML hay que pedir el detalle de LA orden (1 request por reclamo)
# — carísimo con cientos de reclamos, así que se truncaba a ~30 órdenes/cuenta. Con
# 4 cuentas ML y cientos de reclamos, eso dejaba sin resolver a la gran mayoría, que
# caían en buckets de 1 (`orden_X`) y nunca se agregaban a ningún SKU — el ranking
# quedaba sesgado a favor de Amazon (que sí trae el SKU directo en el refund, sin
# request extra) aunque ML tuviera muchos más reclamos en total. Fix: cachear 3h
# (igual que _fetch_amazon_refunds_cached) y resolver TODAS las órdenes sin cap —
# caro pero solo corre una vez cada 3h, no en cada carga de página.
_unified_returns_cache: dict = {}   # {days: (ts, {"ml_counts":.., "amz_counts":.., "ml_total":N, "amz_total":N})}
_UNIFIED_RETURNS_TTL = 3600 * 3

async def _compute_unified_returns(days: int) -> dict:
    from datetime import datetime as _dt3, timedelta as _td3
    import aiosqlite as _aio_ur

    _now = _dt3.utcnow()
    df = (_now - _td3(days=days)).strftime("%Y-%m-%d")
    dt = _now.strftime("%Y-%m-%d")

    ml_counts: dict = {}
    amz_counts: dict = {}

    # ── ML claims ────────────────────────────────────────────────────────────
    ml_accounts = await token_store.get_all_tokens()
    sem_ml = asyncio.Semaphore(3)

    async def _ml_for_account(acc):
        async with sem_ml:
            uid = acc.get("user_id", "")
            nick = acc.get("nickname") or uid
            try:
                cli = await get_meli_client(user_id=uid)
                if not cli:
                    return []
                try:
                    claims = await _fetch_all_claims_cached(cli, df, dt)
                    # copy dicts to avoid mutating the shared cache
                    return [dict(c, _account_id=uid, _account_nickname=nick) for c in claims]
                finally:
                    await cli.close()
            except Exception:
                return []

    ml_nested = await asyncio.gather(
        *[_ml_for_account(a) for a in ml_accounts], return_exceptions=True
    )
    ml_claims: list = []
    for r in ml_nested:
        if isinstance(r, list):
            ml_claims.extend(r)

    # Group order IDs by account so we reuse ONE client per account
    oids_by_acc: dict = {}
    for c in ml_claims:
        if not c.get("resource_id"):
            continue
        oid = str(c["resource_id"])
        acc_id = c.get("_account_id", "")
        if acc_id not in oids_by_acc:
            oids_by_acc[acc_id] = []
        if oid not in oids_by_acc[acc_id]:
            oids_by_acc[acc_id].append(oid)

    order_map_u: dict = {}
    sem_acc_ord = asyncio.Semaphore(3)

    async def _fetch_acc_orders(acc_id: str, oids: list):
        async with sem_acc_ord:
            cli = await get_meli_client(user_id=acc_id)
            if not cli:
                return
            try:
                sem3 = asyncio.Semaphore(6)

                async def _one_order(oid):
                    async with sem3:
                        try:
                            order = await asyncio.wait_for(cli.get(f"/orders/{oid}"), timeout=8.0)
                            oi = order.get("order_items") or []
                            if oi:
                                item = oi[0].get("item", {})
                                iid = str(item.get("id", ""))
                                # seller_custom_field a veces viene vacío en /orders aunque el
                                # listing sí tenga SKU puesto — ML también expone seller_sku
                                # (mismo dato, campo distinto). Bug real encontrado 2026-07-16:
                                # un reclamo de un TV Onn 70" no se podía buscar por SKU porque
                                # solo se revisaba seller_custom_field (vacío), aunque
                                # seller_sku sí traía "SNTV002237" correctamente.
                                sku = item.get("seller_custom_field") or item.get("seller_sku") or ""
                                if not sku and iid:
                                    try:
                                        det = await asyncio.wait_for(
                                            cli.get(f"/items/{iid}", params={"attributes": "seller_custom_field,seller_sku,title"}),
                                            timeout=5.0
                                        )
                                        sku = det.get("seller_custom_field") or det.get("seller_sku") or ""
                                    except Exception:
                                        pass
                                return oid, {
                                    "title": item.get("title", "") or "",
                                    "item_id": iid,
                                    "sku": sku,
                                    "sale_amount": float(order.get("total_amount") or 0),
                                }
                        except Exception:
                            pass
                        return oid, {}

                # Sin cap — se resuelven TODAS las órdenes de la muestra (cacheado 3h).
                results = await asyncio.gather(
                    *[_one_order(o) for o in oids], return_exceptions=True
                )
                for r in results:
                    if isinstance(r, tuple) and r[1]:
                        order_map_u[r[0]] = r[1]
            finally:
                await cli.close()

    await asyncio.gather(
        *[_fetch_acc_orders(aid, oids) for aid, oids in oids_by_acc.items()],
        return_exceptions=True
    )

    # Filas para persistir en claims_history como efecto secundario — el detalle
    # (comentarios/fotos) de /returns dependía de que alguien corriera "Actualizar
    # reclamos" manualmente en otra página, completamente desconectado de este
    # cálculo que YA resuelve cada reclamo. Ahora cualquier refresh de este cache
    # (cada 3h) también deja el registro base en claims_history — sin buyer_comment
    # todavía (eso requiere una llamada extra por reclamo, se resuelve on-demand en
    # sku-claims-detail solo para los reclamos que el usuario realmente abre).
    _ch_rows: list = []

    for c in ml_claims:
        oid = str(c.get("resource_id", ""))
        info = order_map_u.get(oid, {})
        raw_sku = info.get("sku", "")
        sku = normalize_to_bm_sku(raw_sku) if raw_sku else ""
        title = info.get("title") or ""
        # sku > title > orden_X (same order groups) > reclamo_X (last resort)
        key = sku if sku else (title if title else (f"orden_{oid}" if oid else f"reclamo_{c.get('id', '')}"))
        acc_nick = c.get("_account_nickname", "")
        reason_lbl = _claim_reason_label(c.get("reason_id", ""))

        _claim_id = str(c.get("id", ""))
        if _claim_id:
            _ch_rows.append({
                "claim_id": _claim_id, "platform": "ml", "account_id": c.get("_account_id", ""),
                "order_id": oid, "item_id": info.get("item_id", ""), "sku": sku,
                "reason_id": c.get("reason_id", ""), "stage": c.get("stage", ""),
                "status": c.get("status", ""), "quantity": 1,
                "amount_mxn": info.get("sale_amount", 0.0), "buyer_comment": "",
                "date_created": (c.get("date_created") or "")[:10],
            })

        if key not in ml_counts:
            ml_counts[key] = {
                "title": title or sku or key, "sku": sku,
                "item_id": info.get("item_id", ""),
                "count": 0, "opened": 0, "closed": 0,
                "reasons": {}, "accounts": {},
                "platforms": {"ml": 0, "amazon": 0},
                "sale_amount_mxn": 0.0, "refund_usd": 0.0,
            }
        if title and not ml_counts[key]["title"]:
            ml_counts[key]["title"] = title
        if sku and not ml_counts[key]["sku"]:
            ml_counts[key]["sku"] = sku
        if info.get("item_id") and not ml_counts[key]["item_id"]:
            ml_counts[key]["item_id"] = info["item_id"]

        ml_counts[key]["count"] += 1
        ml_counts[key]["platforms"]["ml"] += 1
        ml_counts[key]["sale_amount_mxn"] += info.get("sale_amount", 0.0)
        if c.get("status") == "opened":
            ml_counts[key]["opened"] += 1
        else:
            ml_counts[key]["closed"] += 1
        ml_counts[key]["reasons"][reason_lbl] = ml_counts[key]["reasons"].get(reason_lbl, 0) + 1
        if acc_nick:
            ml_counts[key]["accounts"][acc_nick] = ml_counts[key]["accounts"].get(acc_nick, 0) + 1

    if _ch_rows:
        try:
            await token_store.upsert_claims_history(_ch_rows)
        except Exception as _e:
            logger.warning(f"[UNIFIED-RETURNS] Error persistiendo claims_history: {_e}")

    # ── Amazon refunds ────────────────────────────────────────────────────────
    try:
        amz_accounts = await token_store.get_all_amazon_accounts()
    except Exception:
        amz_accounts = []
    sem_amz = asyncio.Semaphore(2)

    async def _amz_for_account(acc):
        async with sem_amz:
            seller_id = acc.get("seller_id", "")
            nick = acc.get("nickname") or seller_id
            try:
                return await _aggregate_amazon_returns_by_sku(seller_id, days, nickname=nick)
            except Exception:
                return {}

    amz_nested = await asyncio.gather(
        *[_amz_for_account(a) for a in amz_accounts], return_exceptions=True
    )
    amz_total_refunds = 0
    for per_account in amz_nested:
        if not isinstance(per_account, dict):
            continue
        for key, v in per_account.items():
            amz_total_refunds += v["count"]
            if key not in amz_counts:
                amz_counts[key] = {**v, "reasons": dict(v["reasons"]), "accounts": dict(v["accounts"]),
                                    "platforms": dict(v["platforms"])}
                continue
            m = amz_counts[key]
            m["count"] += v["count"]
            m["closed"] += v["closed"]
            m["refund_usd"] = round(m["refund_usd"] + v["refund_usd"], 2)
            m["severity_sum"] = m.get("severity_sum", 0) + v.get("severity_sum", 0)
            m["platforms"]["amazon"] += v["platforms"]["amazon"]
            if v.get("sku") and not m.get("sku"):
                m["sku"] = v["sku"]
            for r2, c2 in v["reasons"].items():
                m["reasons"][r2] = m["reasons"].get(r2, 0) + c2
            for a2, c2 in v["accounts"].items():
                m["accounts"][a2] = m["accounts"].get(a2, 0) + c2

    # ── Fallback de título vía catálogo BM cuando no se pudo resolver por orden/refund ──
    try:
        async with _aio_ur.connect(token_store.DATABASE_PATH) as _db_t:
            _db_t.row_factory = _aio_ur.Row
            _cur_t = await _db_t.execute("SELECT sku, title FROM bm_sku_master")
            titles_map = {r["sku"]: r["title"] for r in await _cur_t.fetchall()}
    except Exception:
        titles_map = {}
    for _cdict in (ml_counts, amz_counts):
        for p in _cdict.values():
            sku = p.get("sku", "")
            if sku and titles_map.get(sku) and (not p["title"] or p["title"] == sku):
                p["title"] = titles_map[sku]

    return {
        "ml_counts": ml_counts, "amz_counts": amz_counts,
        "ml_total": len(ml_claims), "amz_total": amz_total_refunds,
    }


_unified_returns_inflight: set = set()   # days actualmente calculándose en background

async def _refresh_unified_returns(days: int) -> None:
    import time as _tu
    try:
        data = await _compute_unified_returns(days)
        _unified_returns_cache[days] = (_tu.time(), data)
    except Exception as _e:
        logger.warning(f"[UNIFIED-RETURNS] Error refrescando days={days}: {_e}")
    finally:
        _unified_returns_inflight.discard(days)


async def _fetch_unified_returns_cached(days: int) -> dict:
    """Nunca calcula en línea con el request — _compute_unified_returns puede tardar
    30s+ (resuelve TODAS las órdenes ML sin cap) y Railway mata requests a los ~30s
    (ver DEVLOG). Si el cache está fresco lo devuelve; si está viejo o no existe,
    dispara un refresh en background y sirve lo que haya (stale-while-revalidate),
    o un placeholder 'computing' si es la primera vez que se pide esta ventana."""
    import time as _tu
    entry = _unified_returns_cache.get(days)
    fresh = entry and (_tu.time() - entry[0]) < _UNIFIED_RETURNS_TTL
    if fresh:
        return entry[1]
    if days not in _unified_returns_inflight:
        _unified_returns_inflight.add(days)
        asyncio.create_task(_refresh_unified_returns(days))
    if entry:
        return entry[1]
    return {"ml_counts": {}, "amz_counts": {}, "ml_total": 0, "amz_total": 0, "computing": True}


