@app.get("/partials/amazon-returns-summary", response_class=HTMLResponse)
async def amazon_returns_summary_partial(
    request: Request,
    days: int = Query(30, ge=1, le=365),
    seller_id: str = Query(""),
):
    """KPIs de Retornos para UNA cuenta Amazon. Sin Abiertos/Resueltos (un refund
    Amazon es un evento financiero ya completado, no hay estado 'abierto')."""
    sid = seller_id.strip()
    if not sid:
        return HTMLResponse("<p class='text-center py-4 text-red-500'>No hay cuenta Amazon activa.</p>")
    try:
        agg = await _aggregate_amazon_returns_by_sku(sid, days)
        total = sum(v["count"] for v in agg.values())
        refund_usd_total = sum(v["refund_usd"] for v in agg.values())

        retail_map = _get_retail_ph_map()
        costo_usd = sum(retail_map.get(v["sku"], 0.0) * v["count"] for v in agg.values() if v.get("sku"))

        # Denominador de tasa de retorno — total de órdenes del período (Sales API)
        total_orders = 0
        try:
            from app.services.amazon_client import get_amazon_client as _get_amz_rt
            from datetime import datetime as _dtrt, timedelta as _tdrt
            client = await _get_amz_rt(sid)
            if client:
                _now = _dtrt.utcnow()
                date_to_excl = (_now + _tdrt(days=1)).strftime("%Y-%m-%d")
                date_from = (_now - _tdrt(days=days)).strftime("%Y-%m-%d")
                metrics = await client.get_order_metrics(
                    date_from=date_from, date_to_exclusive=date_to_excl, granularity="Total"
                )
                # get_order_metrics(granularity="Total") retorna una LISTA de 1 elemento
                metrics_row = metrics[0] if isinstance(metrics, list) and metrics else (metrics if isinstance(metrics, dict) else {})
                total_orders = int(metrics_row.get("orderCount", 0))
        except Exception as _e:
            logger.warning(f"[AMZ-RETURNS-SUMMARY] order_metrics error {sid}: {_e}")

        return_rate = (total / total_orders * 100) if total_orders > 0 else 0.0
        _fx = _manual_fx_rate if _manual_fx_rate > 0 else 18.0
        valor_mxn = refund_usd_total * _fx

        reasons_agg: dict = {}
        for v in agg.values():
            for r, c in v.get("reasons", {}).items():
                reasons_agg[r] = reasons_agg.get(r, 0) + c

        summary = SimpleNamespace(
            total=total,
            return_rate=round(return_rate, 2),
            total_orders=total_orders,
            valor_mxn=round(valor_mxn, 2),
            valor_usd=round(refund_usd_total, 2),
            costo_usd=round(costo_usd, 2),
            reasons=reasons_agg,
        )
        return templates.TemplateResponse(request, "partials/amazon_returns_summary.html", {
            "summary": summary, "days": days,
        })
    except Exception as e:
        logger.warning(f"[AMZ-RETURNS-SUMMARY] Error {sid}: {e}")
        return HTMLResponse(f"<p class='text-center py-4 text-red-500'>Error cargando resumen: {e}</p>")


@app.get("/api/amazon/returns/timeline")
async def amazon_returns_timeline(
    days: int = Query(30, ge=1, le=365),
    seller_id: str = Query(""),
):
    """Timeline de refunds Amazon por día o semana (mismo shape que /api/returns/timeline)."""
    sid = seller_id.strip()
    if not sid:
        return {"error": "No hay cuenta Amazon activa", "timeline": [], "total": 0}
    try:
        from datetime import datetime as _dttl, timedelta as _tdtl
        refunds = await _fetch_amazon_refunds_cached(sid, days)
        gran = "week" if days > 90 else "day"
        buckets: dict = {}
        for r in refunds:
            dc = (r.get("posted_date") or "")[:10]
            if not dc:
                continue
            key = dc
            if gran == "week":
                try:
                    d_obj = _dttl.fromisoformat(dc)
                    key = (d_obj - _tdtl(days=d_obj.weekday())).strftime("%Y-%m-%d")
                except Exception:
                    pass
            if key not in buckets:
                buckets[key] = {"date": key, "count": 0}
            buckets[key]["count"] += 1
        timeline = sorted(buckets.values(), key=lambda x: x["date"])
        return {"timeline": timeline, "granularity": gran, "total": len(refunds)}
    except Exception as e:
        return {"error": str(e), "timeline": [], "total": 0}


@app.get("/api/amazon/returns/quality-scores")
async def amazon_returns_quality_scores(
    days: int = Query(30, ge=1, le=365),
    seller_id: str = Query(""),
):
    """Quality Score 0-100 por SKU Amazon — mismo criterio que ML (deducción por
    volumen + severidad de razón), sin penalidad por 'abiertos' (no aplica)."""
    sid = seller_id.strip()
    if not sid:
        return {"ok": False, "error": "No hay cuenta Amazon activa", "scores": []}
    try:
        agg = await _aggregate_amazon_returns_by_sku(sid, days)
        scores = []
        for d in agg.values():
            n = d["count"]
            if n == 0:
                continue
            count_deduct = min(n * 8, 60)
            sev_deduct = min(d.get("severity_sum", 0) / max(n, 1), 30)
            score = max(0, round(100 - count_deduct - sev_deduct))
            grade = ("A" if score >= 80 else "B" if score >= 60 else
                     "C" if score >= 40 else "D" if score >= 20 else "F")
            main_reason = max(d["reasons"], key=d["reasons"].get) if d["reasons"] else ""
            scores.append({
                "sku": d.get("sku", ""), "title": d.get("title", "") or d.get("sku", ""),
                "score": score, "grade": grade,
                "return_count": n, "main_reason": main_reason,
            })
        scores.sort(key=lambda s: s["score"])
        return {"ok": True, "scores": scores}
    except Exception as e:
        return {"ok": False, "error": str(e), "scores": []}


@app.get("/api/amazon/returns/top-skus")
async def amazon_returns_top_skus(
    days: int = Query(30, ge=1, le=365),
    limit: int = Query(10, ge=1, le=50),
    seller_id: str = Query(""),
):
    """Top SKUs por retornos Amazon de UNA cuenta — mismo shape que
    /api/returns/unified-top?platform=amazon pero scoped a un solo seller_id."""
    sid = seller_id.strip()
    if not sid:
        return {"error": "No hay cuenta Amazon activa", "products": [], "total": 0}
    try:
        agg = await _aggregate_amazon_returns_by_sku(sid, days)
        total = sum(v["count"] for v in agg.values())
        retail_map = _get_retail_ph_map()
        top = sorted(agg.values(), key=lambda x: x["count"], reverse=True)[:limit]
        products = []
        for p in top:
            sku = p.get("sku", "")
            products.append({
                "sku": sku, "title": p.get("title", "") or sku,
                "count": p["count"], "refund_usd": p["refund_usd"],
                "reasons": p["reasons"],
                "retail_ph_unit": retail_map.get(sku, 0.0) if sku else 0.0,
                "pct_of_total": round(p["count"] / total * 100, 1) if total > 0 else 0,
            })
        return {"total": total, "days": days, "products": products}
    except Exception as e:
        return {"error": str(e), "products": [], "total": 0}


@app.get("/api/amazon/returns/customer-comments")
async def amazon_returns_customer_comments(
    days: int = Query(30, ge=1, le=365),
    seller_id: str = Query(""),
):
    """Comentarios reales de clientes en devoluciones — solo FBA (Amazon no
    expone este campo para MFN). Reusa el mismo reporte cacheado que ya pide
    _aggregate_amazon_returns_by_sku (customer-comments se descartaba ahí,
    aquí se expone directo). Jovan pidió esto para Salud/Retornos Amazon
    después de confirmar que Buyer Messages no es accesible por API."""
    sid = seller_id.strip()
    if not sid:
        return {"error": "No hay cuenta Amazon activa", "rows": [], "total_returns": 0}
    try:
        items = await _fetch_amazon_returns_report_cached(sid, days)
        total_returns = len(items)
        try:
            listings = await token_store.get_amazon_listings_for_account(sid)
            title_map = {l["sku"]: l["title"] for l in listings if l.get("title")}
        except Exception:
            title_map = {}

        rows = []
        for it in items:
            comment = (it.get("customer_comments") or "").strip()
            if not comment:
                continue
            sku = it.get("sku", "")
            rows.append({
                "order_id": it.get("order_id", ""),
                "sku": sku,
                "title": it.get("product_name") or title_map.get(sku, sku),
                "asin": it.get("asin", ""),
                "return_date": it.get("return_date", ""),
                "reason": it.get("reason", ""),
                "reason_label": _amz_reason_label(it.get("reason", "")),
                "customer_comments": comment,
                "quantity": it.get("quantity", 1),
            })
        rows.sort(key=lambda r: r["return_date"], reverse=True)
        return {
            "days": days, "rows": rows,
            "total_returns": total_returns, "total_with_comments": len(rows),
        }
    except Exception as e:
        return {"error": str(e), "rows": [], "total_returns": 0}


@app.get("/api/amazon/returns/reimbursements")
async def amazon_reimbursements_api(
    days: int = Query(30, ge=1, le=365),
    seller_id: str = Query(""),
):
    """Reembolsos FBA ya aprobados por Amazon (inventario perdido/dañado en
    almacén, etc — idea tomada de Helium10 Managed Refund Service, aquí se
    detecta gratis con el reporte que Amazon ya expone). V1: solo muestra lo
    ya aprobado — no cruza contra Inventory Ledger para detectar pérdidas
    aún no reembolsadas (pendiente, ver amazon_client.get_reimbursements_report)."""
    sid = seller_id.strip()
    if not sid:
        return {"error": "No hay cuenta Amazon activa", "rows": [], "summary": {}}
    try:
        items = await _fetch_amazon_reimbursements_cached(sid, days)
        rows = sorted(items, key=lambda r: r.get("approval_date", ""), reverse=True)
        for r in rows:
            r["reason_label"] = _amz_reason_label(r.get("reason", ""))
        total_amount = sum(r.get("amount_total", 0) for r in rows)
        by_reason: dict = {}
        for r in rows:
            reason = r.get("reason", "")
            by_reason[reason] = by_reason.get(reason, 0) + r.get("amount_total", 0)
        summary = {
            "total_count": len(rows),
            "total_amount": round(total_amount, 2),
            "by_reason": {k: round(v, 2) for k, v in by_reason.items()},
        }
        return {"days": days, "rows": rows, "summary": summary}
    except Exception as e:
        return {"error": str(e), "rows": [], "summary": {}}


def _amz_thread_key(reply_to_addr: str) -> str:
    """Prefijo reusando ml_message_views (pack_id/account_id genéricos) —
    mismo truco que ya usan los reclamos ('claim:'), evita crear una tabla
    nueva solo para llevar quién está atendiendo un hilo."""
    return f"amz:{reply_to_addr}"


def _amz_response_deltas(messages: list) -> list:
    """Para cada tramo de mensajes inbound seguido de una respuesta outbound,
    devuelve el delta en segundos entre el último inbound del tramo y esa
    respuesta — insumo para el KPI de tiempo promedio de respuesta."""
    deltas = []
    pending_inbound_ts = None
    for m in messages:
        if m["direction"] == "inbound":
            pending_inbound_ts = m["ts"] or 0
        elif pending_inbound_ts is not None:
            deltas.append((m["ts"] or 0) - pending_inbound_ts)
            pending_inbound_ts = None
    return deltas


@app.get("/api/amazon/buyer-messages")
async def amazon_buyer_messages_list(
    request: Request,
    days: int = Query(30, ge=1, le=365),
    seller_id: str = Query(""),
    order_id: str = Query(""),
    only_pending: bool = Query(True),
):
    """Hilos de mensajes reales de compradores (Buyer-Seller Messaging)
    capturados vía el buzón Gmail dedicado — NO es SP-API (no existe endpoint
    de lectura, ver reference_amazon_sp_api_docs). Agrupa por reply_to_addr
    (la dirección tokenizada de Amazon = identificador estable de "esta
    conversación con este comprador") en vez de devolver mensajes sueltos,
    para que Tomar/Atendiendo/IA-con-historial tengan sentido, igual que
    Mensajes ML.

    order_id: si se da, busca el histórico completo de ESA orden (ignora days
    y only_pending — Jovan quiere poder ver todo lo que se habló con ese
    cliente, ya esté resuelto o no).
    only_pending (default True): oculta los hilos donde el último mensaje ya
    es nuestro (ya se respondió) — Jovan no quiere ver de nuevo lo que ya se
    contestó, solo lo que sigue esperando respuesta."""
    _require_subtab(request, "amz", "salud", "mensajes")
    sid = seller_id.strip()
    oid = order_id.strip()
    if not sid:
        return {"error": "No hay cuenta Amazon activa", "threads": [], "total": 0, "unread": 0}
    try:
        effective_days = 3650 if oid else days
        rows = await token_store.get_buyer_messages(sid, effective_days, limit=(1000 if oid else 50))
        if oid:
            rows = [r for r in rows if r["order_id"] == oid]
        unread = sum(1 for r in rows if r["direction"] == "inbound" and not r.get("read_at"))

        by_thread: dict = {}
        for r in rows:
            key = r["reply_to_addr"] or r["order_id"] or str(r["id"])
            th = by_thread.setdefault(key, {
                "reply_to_addr": r["reply_to_addr"], "buyer_name": r["buyer_name"],
                "order_id": r["order_id"], "asin": r["asin"], "product_title": r["product_title"],
                "messages": [], "last_ts": 0,
            })
            th["messages"].append(r)
            th["last_ts"] = max(th["last_ts"], r["ts"] or 0)
            # el nombre/orden/producto más reciente disponible gana (algunos
            # inbound viejos pueden no traerlos si Amazon no los incluyó)
            if r["direction"] == "inbound":
                th["buyer_name"] = r["buyer_name"] or th["buyer_name"]
                th["order_id"] = r["order_id"] or th["order_id"]
                th["asin"] = r["asin"] or th["asin"]
                th["product_title"] = r["product_title"] or th["product_title"]

        threads = sorted(by_thread.values(), key=lambda t: t["last_ts"], reverse=True)
        for th in threads:
            th["messages"].sort(key=lambda m: m["ts"] or 0)
            th["unread"] = sum(1 for m in th["messages"] if m["direction"] == "inbound" and not m.get("read_at"))

        # view_info ANTES de filtrar — "pendiente" depende tanto de si el
        # último mensaje es del comprador COMO de si alguien ya lo marcó
        # resuelto a mano (ej. "Marcar todo como atendido" para limpiar
        # historial de antes de esta feature, que Amazon no comparte por
        # ningún canal). Sin esto, un hilo marcado resuelto seguía apareciendo
        # como pendiente para siempre si nunca se le contestó DESDE AQUÍ.
        pack_ids = [_amz_thread_key(t["reply_to_addr"]) for t in threads if t["reply_to_addr"]]
        views = await token_store.get_message_views(pack_ids, sid) if pack_ids else {}
        for th in threads:
            th["view_info"] = views.get(_amz_thread_key(th["reply_to_addr"]))
            last_is_inbound = th["messages"][-1]["direction"] == "inbound" if th["messages"] else False
            already_resolved = th["view_info"] and th["view_info"].get("status") == "resolved"
            th["needs_response"] = last_is_inbound and not already_resolved

        # stats se calcula sobre TODOS los hilos (antes del filtro only_pending)
        # para que los KPIs no dependan del toggle de "solo pendientes".
        now_ts = _time_module.time()
        pending_threads = [t for t in threads if t["needs_response"]]
        urgency = {"under24": 0, "h24_72": 0, "over72": 0}
        oldest_pending = None
        for t in pending_threads:
            age_hours = (now_ts - (t["last_ts"] or now_ts)) / 3600
            if age_hours < 24:
                urgency["under24"] += 1
            elif age_hours < 72:
                urgency["h24_72"] += 1
            else:
                urgency["over72"] += 1
            if oldest_pending is None or (t["last_ts"] or 0) < oldest_pending["ts"]:
                oldest_pending = {"buyer_name": t["buyer_name"], "ts": t["last_ts"], "hours": age_hours}

        response_deltas = []
        for t in threads:
            response_deltas.extend(_amz_response_deltas(t["messages"]))
        avg_response_hours = (sum(response_deltas) / len(response_deltas) / 3600) if response_deltas else None

        resolved_cutoff = now_ts - 86400
        resolved_today = sum(
            1 for t in threads
            if t["view_info"] and t["view_info"].get("status") == "resolved"
            and (t["view_info"].get("viewed_at") or 0) >= resolved_cutoff
        )

        stats = {
            "pending_count": len(pending_threads),
            "urgency": urgency,
            "oldest_pending": oldest_pending,
            "avg_response_hours": avg_response_hours,
            "avg_response_sample": len(response_deltas),
            "resolved_today": resolved_today,
        }

        if only_pending and not oid:
            threads = [t for t in threads if t["needs_response"]]

        return {"days": days, "threads": threads, "total": len(rows), "unread": unread, "stats": stats}
    except Exception as e:
        return {"error": str(e), "threads": [], "total": 0, "unread": 0}


@app.post("/api/amazon/buyer-messages/mark-read")
async def amazon_buyer_messages_mark_read(request: Request):
    """Marca varios mensajes como leídos de una sola vez — el frontend llama
    esto UNA vez con todos los IDs visibles, no uno por mensaje (evita
    contención en SQLite si hay muchos sin leer)."""
    du = getattr(request.state, "dashboard_user", None) or {}
    if not du:
        return JSONResponse({"error": "forbidden"}, status_code=403)
    try:
        body = await request.json()
        ids = [int(x) for x in (body.get("ids") or [])]
    except Exception:
        return JSONResponse({"detail": "JSON inválido"}, status_code=400)
    await token_store.mark_buyer_messages_read(ids)
    return JSONResponse({"ok": True})


@app.post("/api/amazon/buyer-messages/take")
async def amazon_buyer_messages_take(request: Request):
    """Asigna explícitamente un hilo de comprador al usuario actual — mismo
    patrón que /api/health/messages/{pack_id}/take (ML)."""
    du = getattr(request.state, "dashboard_user", None) or {}
    if not du:
        return JSONResponse({"error": "forbidden"}, status_code=403)
    try:
        body = await request.json()
        seller_id = (body.get("seller_id") or "").strip()
        reply_to_addr = (body.get("reply_to_addr") or "").strip()
    except Exception:
        return JSONResponse({"detail": "JSON inválido"}, status_code=400)
    if not seller_id or not reply_to_addr:
        return JSONResponse({"detail": "seller_id y reply_to_addr son requeridos"}, status_code=400)
    username = du["username"]
    await token_store.take_message(_amz_thread_key(reply_to_addr), seller_id, username)
    return JSONResponse({"ok": True, "taken_by": username})


