@app.post("/api/amazon/buyer-messages/mark-all-resolved")
async def amazon_buyer_messages_mark_all_resolved(request: Request):
    """'Borrón y cuenta nueva' del historial acumulado — Jovan lo pidió tras
    confirmar que Amazon no comparte respuestas dadas directo en Seller
    Central, así que no hay forma de saber con certeza qué del historial
    viejo ya se atendió. Marca TODOS los hilos actuales de la cuenta como
    resueltos de un jalón; de ahí en adelante Tomar/Marcar resuelto se usa
    normal para lo nuevo que vaya llegando."""
    du = getattr(request.state, "dashboard_user", None) or {}
    if not du:
        return JSONResponse({"error": "forbidden"}, status_code=403)
    try:
        body = await request.json()
        seller_id = (body.get("seller_id") or "").strip()
    except Exception:
        return JSONResponse({"detail": "JSON inválido"}, status_code=400)
    if not seller_id:
        return JSONResponse({"detail": "seller_id es requerido"}, status_code=400)

    rows = await token_store.get_buyer_messages(seller_id, days=3650, limit=5000)
    reply_addrs = {r["reply_to_addr"] for r in rows if r.get("reply_to_addr")}
    pack_ids = [_amz_thread_key(addr) for addr in reply_addrs]
    count = await token_store.bulk_mark_resolved(pack_ids, seller_id, du["username"])

    try:
        ip = request.headers.get("X-Forwarded-For", request.client.host if request.client else None)
        await user_store.log_action(
            username=du["username"], user_id=du.get("id"),
            action="amazon_buyer_messages_mark_all_resolved", item_id=seller_id,
            detail={"threads_marked": count}, ip=ip, section="Salud",
        )
    except Exception:
        pass

    return JSONResponse({"ok": True, "threads_marked": count})


@app.post("/api/amazon/buyer-messages/{message_id}/reply")
async def amazon_buyer_message_reply(
    message_id: int, request: Request,
    text: str = Form(...),
    attachment: UploadFile = File(None),
):
    """Responde un mensaje de comprador desde el dashboard — envía un correo
    real desde el buzón dedicado de la cuenta hacia la dirección tokenizada
    de Amazon (reply_to_addr), que la relanza al comprador de forma anónima.
    El adjunto (si viene) se lee en memoria y se descarta tras enviarlo — no
    se persiste en disco (ver riesgo de disco lleno documentado en memoria
    del proyecto)."""
    du = getattr(request.state, "dashboard_user", None) or {}
    if not du:
        return JSONResponse({"error": "forbidden"}, status_code=403)
    text = (text or "").strip()
    if not text:
        return JSONResponse({"detail": "El texto de la respuesta es requerido"}, status_code=400)

    original = await token_store.get_buyer_message(message_id)
    if not original:
        return JSONResponse({"detail": "Mensaje no encontrado"}, status_code=404)

    attachment_tuple = None
    if attachment is not None and attachment.filename:
        data = await attachment.read()
        if data:
            attachment_tuple = (attachment.filename, data, attachment.content_type or "application/octet-stream")

    # Firma con el nombre real de quien responde — nunca "admin" (Jovan pidió
    # explícitamente no usarlo, no identifica a una persona real).
    signer = (du.get("display_name") or du.get("username") or "").strip()
    body_with_signature = f"{text}\n\n{signer}" if signer and signer.lower() != "admin" else text

    from app.services import buyer_messages_client as _bmc
    try:
        sent_message_id = await _bmc.send_reply(
            seller_id=original["seller_id"],
            to_addr=original["reply_to_addr"],
            subject=original["subject"],
            body=body_with_signature,
            in_reply_to=original["message_id"],
            attachment=attachment_tuple,
        )
    except Exception as e:
        return JSONResponse({"detail": f"No se pudo enviar: {e}"}, status_code=502)

    import time as _t_bmr
    await token_store.insert_buyer_message({
        "seller_id": original["seller_id"], "direction": "outbound",
        "order_id": original["order_id"], "asin": original["asin"],
        "product_title": original["product_title"], "buyer_name": original["buyer_name"],
        "subject": original["subject"], "body_text": body_with_signature,
        "reply_to_addr": original["reply_to_addr"], "message_id": sent_message_id,
        "in_reply_to": original["message_id"], "ts": _t_bmr.time(),
    })
    await token_store.mark_buyer_messages_read([message_id])
    await token_store.take_message(_amz_thread_key(original["reply_to_addr"]), original["seller_id"], du["username"])

    try:
        ip = request.headers.get("X-Forwarded-For", request.client.host if request.client else None)
        await user_store.log_action(
            username=du["username"], user_id=du.get("id"),
            action="amazon_buyer_message_reply", item_id=original.get("order_id", ""),
            detail={"seller_id": original["seller_id"], "text": text, "had_attachment": bool(attachment_tuple)},
            ip=ip, section="Salud",
        )
    except Exception:
        pass

    return JSONResponse({"ok": True})


def _merge_return_counts(ml_counts: dict, amz_counts: dict) -> dict:
    """Combina los conteos por-plataforma en un solo dict por SKU para la vista 'Todas'."""
    merged: dict = {}
    for src in (ml_counts, amz_counts):
        for key, v in src.items():
            if key not in merged:
                merged[key] = {
                    "title": v["title"], "sku": v["sku"], "item_id": v.get("item_id", ""),
                    "count": 0, "opened": 0, "closed": 0,
                    "reasons": {}, "accounts": {},
                    "platforms": {"ml": 0, "amazon": 0},
                    "sale_amount_mxn": 0.0, "refund_usd": 0.0,
                }
            m = merged[key]
            if v.get("title") and (not m["title"] or m["title"] == m.get("sku")):
                m["title"] = v["title"]
            if v.get("sku") and not m["sku"]:
                m["sku"] = v["sku"]
            if v.get("item_id") and not m["item_id"]:
                m["item_id"] = v["item_id"]
            m["count"] += v["count"]
            m["opened"] += v["opened"]
            m["closed"] += v["closed"]
            m["sale_amount_mxn"] += v.get("sale_amount_mxn", 0.0)
            m["refund_usd"] = round(m["refund_usd"] + v.get("refund_usd", 0.0), 2)
            m["platforms"]["ml"] += v["platforms"]["ml"]
            m["platforms"]["amazon"] += v["platforms"]["amazon"]
            for r, c in v.get("reasons", {}).items():
                m["reasons"][r] = m["reasons"].get(r, 0) + c
            for a, c in v.get("accounts", {}).items():
                m["accounts"][a] = m["accounts"].get(a, 0) + c
    return merged


@app.get("/api/returns/unified-top")
async def returns_unified_top(
    days: int = Query(30, ge=1, le=365),
    limit: int = Query(10, ge=1, le=20),
    platform: str = Query("all", description="all | ml | amazon"),
):
    """Top N SKUs más retornados/reembolsados sumando ML + Amazon. Lee de
    _fetch_unified_returns_cached (3h TTL) — ver comentario ahí."""
    data = await _fetch_unified_returns_cached(days)
    retail_map = _get_retail_ph_map()

    if platform == "ml":
        counts = data["ml_counts"]
        total_all = data["ml_total"]
    elif platform == "amazon":
        counts = data["amz_counts"]
        total_all = data["amz_total"]
    else:
        counts = _merge_return_counts(data["ml_counts"], data["amz_counts"])
        total_all = data["ml_total"] + data["amz_total"]

    top = [dict(p) for p in sorted(counts.values(), key=lambda x: x["count"], reverse=True)[:limit]]
    for p in top:
        sku = p.get("sku", "")
        p["retail_ph_unit"] = retail_map.get(sku, 0.0) if sku else 0.0
        p["pct_of_total"] = round(p["count"] / total_all * 100, 1) if total_all > 0 else 0

    ml_accs = len(await token_store.get_all_tokens()) if platform in ("all", "ml") else 0
    try:
        amz_accs_list = await token_store.get_all_amazon_accounts() if platform in ("all", "amazon") else []
        amz_accs = len(amz_accs_list)
    except Exception:
        amz_accs = 0

    return {
        "total": total_all,
        "ml_total": data["ml_total"],
        "amz_total": data["amz_total"],
        "days": days,
        "ml_accounts": ml_accs,
        "amazon_accounts": amz_accs,
        "platform": platform,
        "computing": data.get("computing", False),
        "products": top,
    }


@app.post("/api/returns/flag-item")
async def returns_flag_item(request: Request):
    """Marca un listing desde análisis de retornos. flag_type: 'review' | 'qty_zero'."""
    body = await request.json()
    item_id = str(body.get("item_id", "")).strip()
    flag_type = str(body.get("flag_type", "review"))
    note = str(body.get("note", ""))

    if not item_id:
        return {"ok": False, "error": "item_id requerido"}

    from app.services.meli_client import _active_user_id as _ctx
    _uid = str(_ctx.get() or "")
    from app.services import token_store as _ts
    await _ts.save_return_flag(_uid, item_id, flag_type, note)
    result: dict = {"ok": True, "flagged": item_id, "type": flag_type}

    if flag_type == "qty_zero":
        client = await get_meli_client()
        if client:
            try:
                await client.update_item_stock(item_id, 0)
                result["stock_updated"] = True
                result["message"] = f"Stock del listing {item_id} puesto a 0"
            except Exception as _e2:
                result["stock_error"] = str(_e2)
            finally:
                await client.close()

    return result


