@app.get("/api/returns/claim-photos/{claim_id}")
async def returns_claim_photos(claim_id: str, account_id: str = Query("")):
    """Fotos de un reclamo ML. Prioriza el mirror local ya sincronizado por
    _save_ml_claims_bg (claim_photos); si no hay nada guardado, cae a fetch en
    vivo de los mensajes del reclamo (attachments v2 no traen url — se arma la
    ruta de descarga y se sirve vía proxy con auth, que además cachea a disco)."""
    import os as _os
    from urllib.parse import quote
    from app.services import token_store as _ts_ph

    local_photos = await _ts_ph.get_claim_photos(claim_id)
    if local_photos:
        return {
            "ok": True, "claim_id": claim_id, "total": len(local_photos),
            "photos": [{
                "url": f"/api/returns/claim-photo-file?path={quote(p['local_path'])}",
                "filename": _os.path.basename(p["local_path"]),
                "from_role": p.get("from_role", ""),
            } for p in local_photos],
        }

    from app.services.meli_client import _active_user_id as _ctx
    _uid = account_id or str(_ctx.get() or "")
    client = await get_meli_client(user_id=_uid or None)
    if not client:
        return {"ok": False, "error": "No autenticado", "photos": []}
    try:
        msgs = await client.get_claim_messages(claim_id)
        photos = []
        if isinstance(msgs, list):
            for msg in msgs:
                sender = msg.get("sender_role", "")
                for att in (msg.get("attachments") or []):
                    fname = att.get("filename") or att.get("name") or ""
                    mime = att.get("type") or att.get("mime_type") or ""
                    is_img = (
                        mime.startswith("image/") or
                        any(fname.lower().endswith(ext) for ext in (".jpg", ".jpeg", ".png", ".webp", ".gif"))
                    )
                    if is_img and fname:
                        proxy_url = (
                            f"/api/returns/claim-photo-proxy?claim_id={claim_id}"
                            f"&filename={quote(fname)}&account_id={_uid}"
                        )
                        photos.append({
                            "url": proxy_url,
                            "filename": fname,
                            "mime": mime,
                            "from_role": sender,
                        })
        return {"ok": True, "claim_id": claim_id, "photos": photos, "total": len(photos)}
    except Exception as _e:
        return {"ok": False, "error": str(_e), "photos": []}
    finally:
        await client.close()


@app.get("/api/returns/claim-photo-file")
async def returns_claim_photo_file(path: str = Query(...)):
    """Sirve una foto ya persistida en /app/data/claim_photos/. `path` es relativo
    a la carpeta de datos (Railway Volume) — se valida que no escape el directorio."""
    import mimetypes
    photos_root = Path(DATABASE_PATH).resolve().parent / "claim_photos"
    full_path = (photos_root.parent / path).resolve()
    if photos_root not in full_path.parents or not full_path.is_file():
        return Response(status_code=404)
    mime, _ = mimetypes.guess_type(str(full_path))
    return Response(content=full_path.read_bytes(), media_type=mime or "application/octet-stream")


# Presupuesto duro de disco para claim_photos/ — el Railway Volume es 500MB TOTAL,
# compartido con la DB (~310MB). Sin un tope acumulado, las fotos de reclamos crecen sin
# límite entre requests (cada request individual ya tenía un cap propio — 30 fotos aquí,
# 1 en claim-photo-proxy — pero eso solo acota CADA llamada, no el total acumulado con el
# tiempo). Causa raíz confirmada de los incidentes "database or disk is full" del
# 2026-07-15 (835 fotos = 1.5GB, sync masivo) y 2026-07-17 (113MB acumulados por el
# backfill on-demand del buscador de SKU, sin relación con el sync). Ver DEVLOG.
# Bajado de 120 a 40 el 2026-07-18: con la DB en ~309MB, 120MB de fotos dejaba
# muy poco margen antes de los 500MB del volumen — el disco se volvió a llenar
# el mismo día. 40MB deja un colchón mucho más cómodo.
_CLAIM_PHOTOS_BUDGET_MB = 40.0
# Regla adicional (2026-07-18, a petición de Jovan): ninguna foto vive más de 30
# días SIN IMPORTAR el tamaño acumulado — se aplica ANTES del tope de tamaño, no
# en vez de él. Un tope solo por antigüedad no protege contra ráfagas (ej. el
# incidente del 2026-07-15: 835 fotos/1.5GB de golpe, todas con <30 días) — por
# eso el tope de tamaño sigue siendo la red de seguridad real; esto es una regla
# de higiene encima, para que nada se quede oxidado aunque sí haya espacio.
_CLAIM_PHOTOS_MAX_AGE_DAYS = 30


async def _enforce_claim_photos_budget() -> dict:
    """Mantiene claim_photos/ bajo control con dos reglas, en este orden:
    1. Borra cualquier archivo con más de _CLAIM_PHOTOS_MAX_AGE_DAYS días,
       sin importar el tamaño total acumulado.
    2. Si aún se pasa de _CLAIM_PHOTOS_BUDGET_MB, borra los más viejos que
       queden (LRU por mtime) hasta bajar al 80% del presupuesto.
    Se llama después de cualquier descarga de fotos, sin importar el endpoint."""
    import os as _os_budget
    import time as _time_budget

    photos_dir = Path(DATABASE_PATH).resolve().parent / "claim_photos"
    if not photos_dir.is_dir():
        return {"evicted": 0, "freed_mb": 0.0}

    entries = []
    total_bytes = 0
    for root, _dirs, fnames in _os_budget.walk(photos_dir):
        for f in fnames:
            fp = _os_budget.path.join(root, f)
            try:
                st = _os_budget.stat(fp)
                entries.append((fp, st.st_size, st.st_mtime))
                total_bytes += st.st_size
            except Exception:
                pass

    evicted, freed = 0, 0
    deleted_rel_paths = []

    def _evict(fp, sz):
        nonlocal total_bytes, evicted, freed
        try:
            _os_budget.remove(fp)
            total_bytes -= sz
            freed += sz
            evicted += 1
            deleted_rel_paths.append(str(Path(fp).relative_to(photos_dir.parent)))
            return True
        except Exception:
            return False

    # Regla 1 — antigüedad, incondicional
    age_cutoff = _time_budget.time() - (_CLAIM_PHOTOS_MAX_AGE_DAYS * 86400)
    remaining = []
    for fp, sz, mt in entries:
        if mt < age_cutoff:
            _evict(fp, sz)
        else:
            remaining.append((fp, sz, mt))

    # Regla 2 — tope de tamaño sobre lo que sobrevivió a la regla 1
    budget_bytes = _CLAIM_PHOTOS_BUDGET_MB * 1024 * 1024
    if total_bytes > budget_bytes:
        remaining.sort(key=lambda e: e[2])  # más viejo primero
        target_bytes = budget_bytes * 0.8
        for fp, sz, _mt in remaining:
            if total_bytes <= target_bytes:
                break
            _evict(fp, sz)

    if deleted_rel_paths:
        try:
            from app.services import token_store as _ts_evict
            await _ts_evict.delete_claim_photos_by_path(deleted_rel_paths)
        except Exception:
            pass

    if evicted:
        logger.warning(
            f"[CLAIM-PHOTOS-BUDGET] Evictados {evicted} archivos, "
            f"{freed / 1024 / 1024:.1f}MB liberados "
            f"(máx {_CLAIM_PHOTOS_MAX_AGE_DAYS}d, presupuesto {_CLAIM_PHOTOS_BUDGET_MB}MB)"
        )
    return {"evicted": evicted, "freed_mb": round(freed / 1024 / 1024, 2)}


@app.get("/api/returns/claim-photo-proxy")
async def returns_claim_photo_proxy(claim_id: str = Query(...), filename: str = Query(...), account_id: str = Query("")):
    """Descarga en vivo una foto de reclamo (con auth) y la sirve al navegador —
    además la cachea a disco + DB para que la próxima carga sea local (fast path)."""
    import os as _os
    import mimetypes
    from app.services import token_store as _ts_ph

    client = await get_meli_client(user_id=account_id or None)
    if not client:
        return Response(status_code=401)
    try:
        dl_path = f"/marketplace/v2/claims/{claim_id}/attachments/{filename}/download"
        content = await client.download_binary(dl_path)
        if not content:
            return Response(status_code=404)

        photos_dir = Path(DATABASE_PATH).resolve().parent / "claim_photos"
        claim_dir = photos_dir / claim_id
        claim_dir.mkdir(parents=True, exist_ok=True)
        local_path = claim_dir / f"0_{_os.path.basename(filename)}"
        if not local_path.exists():
            local_path.write_bytes(content)
            await _ts_ph.save_claim_photos(claim_id, "ml", [{
                "local_path": str(local_path.relative_to(photos_dir.parent)),
                "original_url": dl_path,
                "from_role": "",
            }])
            asyncio.create_task(_enforce_claim_photos_budget())

        mime, _ = mimetypes.guess_type(filename)
        return Response(content=content, media_type=mime or "image/jpeg")
    except Exception:
        return Response(status_code=502)
    finally:
        await client.close()


