@app.get("/api/diag/ml-search")
async def diag_ml_search(q: str = "", token: str = "", limit: int = 20):
    """Diagnóstico: busca competencia en ML por número de parte/modelo usando la API de catálogo.
    Flujo: product_identifier → catalog_product_id → /products/{id}/items (todos los vendedores)."""
    if token != _DIAG_TOKEN:
        return JSONResponse({"error": "token inválido"}, status_code=403)
    if not q:
        return JSONResponse({"error": "q requerido"}, status_code=400)
    limit = max(1, min(50, limit))
    try:
        client = await get_meli_client()
        if not client:
            return JSONResponse({"error": "Sin cliente ML activo"}, status_code=503)

        import urllib.parse as _up

        # Paso 1: buscar el product en el catálogo por número de parte
        from app.services.meli_client import MeliApiError as _MeliErr
        try:
            catalog_results = await client.get(
                f"/marketplace/products/search?product_identifier={_up.quote(q)}&status=active&limit=5"
            )
            products = catalog_results.get("results", []) if isinstance(catalog_results, dict) else []
        except _MeliErr as _me:
            return JSONResponse({"error": f"catalog_search HTTP {_me.status_code}", "body": str(_me.body)[:400], "endpoint": f"/marketplace/products/search?product_identifier={q}"}, status_code=502)

        if not products:
            # Fallback: búsqueda textual
            try:
                catalog_results = await client.get(
                    f"/marketplace/products/search?q={_up.quote(q)}&status=active&limit=5"
                )
                products = catalog_results.get("results", []) if isinstance(catalog_results, dict) else []
            except _MeliErr as _me2:
                return JSONResponse({"error": f"catalog_search_text HTTP {_me2.status_code}", "body": str(_me2.body)[:400]}, status_code=502)

        if not products:
            return JSONResponse({"query": q, "catalog_products": [], "sellers": [], "msg": "No encontrado en catálogo ML"})

        # Paso 2: para cada catalog_product encontrado, obtener sus sellers
        all_sellers = []
        catalog_info = []
        for prod in products[:3]:
            prod_id = prod.get("id") or prod.get("catalog_product_id")
            if not prod_id:
                continue
            catalog_info.append({"id": prod_id, "name": prod.get("name", ""), "domain": prod.get("domain_id", "")})
            try:
                items_data = await client.get(f"/products/{prod_id}/items?limit={limit}")
                items = items_data.get("results", []) if isinstance(items_data, dict) else []
                for it in items:
                    seller = it.get("seller", {})
                    shipping = it.get("shipping", {})
                    all_sellers.append({
                        "catalog_product_id": prod_id,
                        "item_id": it.get("item_id") or it.get("id"),
                        "price": it.get("price"),
                        "currency": it.get("currency_id", "MXN"),
                        "condition": it.get("condition"),
                        "buy_box_winner": it.get("buy_box_winner", False),
                        "full": shipping.get("logistic_type") == "fulfillment",
                        "free_shipping": shipping.get("free_shipping"),
                        "seller_id": seller.get("id"),
                        "seller_nickname": seller.get("nickname"),
                        "available_quantity": it.get("available_quantity"),
                    })
            except Exception:
                pass

        # Ordenar por precio
        all_sellers.sort(key=lambda x: x.get("price") or 999999)

        return JSONResponse({
            "query": q,
            "catalog_products_found": len(catalog_info),
            "catalog_products": catalog_info,
            "sellers_count": len(all_sellers),
            "sellers": all_sellers,
        })
    except Exception as e:
        return JSONResponse({"error": str(e)}, status_code=500)


@app.get("/api/diag/claims-raw")
async def diag_claims_raw(
    token: str = "",
    account_id: str = Query(""),
    date_from: str = Query(""),
    date_to: str = Query(""),
    limit: int = Query(5),
    no_players: bool = Query(False),
    raw_status: str = Query(""),
):
    """Diagnóstico: llama marketplace/v2/claims/search y devuelve respuesta raw.
    Útil para verificar que el endpoint funciona y devuelve claims para la cuenta.
    """
    if token != _DIAG_TOKEN:
        return JSONResponse({"error": "token inválido"}, status_code=403)
    client = await get_meli_client(user_id=account_id or None)
    if not client:
        return JSONResponse({"error": "No autenticado / cuenta no encontrada"}, status_code=401)
    try:
        # Prueba fetch_all_claims completo con date filter client-side
        status_req = raw_status if raw_status and raw_status not in ("fmt2","fmt3","fmt4") else None
        claims_all = await client.fetch_all_claims(
            status=status_req,
            date_from=date_from or None,
            date_to=date_to or None,
        )
        return JSONResponse({
            "ok": True,
            "user_id": client.user_id,
            "endpoint": "/marketplace/v2/claims/search",
            "params": {
                "status": status_req,
                "date_from": date_from or None,
                "date_to": date_to or None,
                "limit": limit,
            },
            "total_found": len(claims_all),
            "sample": claims_all[:limit],
        })
    except Exception as e:
        from app.services.meli_client import MeliApiError as _MAE
        err_body = getattr(e, "body", None)
        err_status = getattr(e, "status_code", None)
        return JSONResponse({
            "ok": False,
            "error": str(e),
            "error_body": err_body,
            "error_status": err_status,
            "user_id": client.user_id,
        }, status_code=500)
    finally:
        await client.close()


@app.get("/api/diag/mlmu")
async def diag_mlmu(
    token: str = Query(""),
    mlmu_id: str = Query("MLMU3559888403"),
):
    """Diagnóstico: probar endpoints para resolver un MLMU Universal Product ID."""
    _dk = _os_diag.environ.get("DIAG_TOKEN", "dk_b55c96a82a49f04908e0079bda6bee41ce2748be2c11f3b5")
    if token != _dk:
        return JSONResponse({"error": "unauthorized"}, status_code=403)
    client = await get_meli_client()
    if not client:
        return JSONResponse({"error": "no_auth"}, status_code=401)
    results = {}
    try:
        # 1. /sites/MLM/search?catalog_product_id
        try:
            r1 = await client.get("/sites/MLM/search", params={"catalog_product_id": mlmu_id, "limit": 3})
            results["search_catalog_product_id"] = {"count": len(r1.get("results") or []), "first": (r1.get("results") or [{}])[0].get("id") if r1.get("results") else None, "raw_keys": list(r1.keys())}
        except Exception as e:
            results["search_catalog_product_id"] = {"error": str(e)[:200]}
        # 2. /products/{mlmu_id}
        try:
            r2 = await client.get(f"/products/{mlmu_id}")
            results["products_endpoint"] = {"name": r2.get("name",""), "error": r2.get("error",""), "status": r2.get("status",""), "keys": list(r2.keys())[:10]}
        except Exception as e:
            results["products_endpoint"] = {"error": str(e)[:200]}
        # 3. /catalog/search?query
        try:
            r3 = await client.get("/catalog/search", params={"site_id": "MLM", "q": mlmu_id})
            results["catalog_search"] = {"count": len(r3.get("results") or []), "keys": list(r3.keys())}
        except Exception as e:
            results["catalog_search"] = {"error": str(e)[:200]}
        # 4. /products/{mlmu_id}/items
        try:
            r4 = await client.get(f"/products/{mlmu_id}/items", params={"limit": 10})
            _r4res = r4.get("results") or []
            results["products_items"] = {"count": len(_r4res), "all_ids": [x.get("item_id") for x in _r4res], "raw_keys": list(r4.keys()), "first_raw": _r4res[0] if _r4res else None}
        except Exception as e:
            results["products_items"] = {"error": str(e)[:200]}
        # 5. Try resolving each returned item via auth client
        if results.get("products_items", {}).get("all_ids"):
            _item_tests = {}
            import httpx as _hx_diag
            for _tid in (results["products_items"]["all_ids"] or [])[:5]:
                try:
                    _ti = await client.get_item(_tid)
                    _item_tests[_tid] = {"ok": not _ti.get("error"), "title": _ti.get("title","")[:60], "error": _ti.get("error",""), "status": _ti.get("status","")}
                except Exception as _te:
                    _item_tests[_tid] = {"exception": str(_te)[:100]}
            # Also try public API for first item
            try:
                _first_id = results["products_items"]["all_ids"][0]
                async with _hx_diag.AsyncClient(timeout=8.0) as _hxc:
                    _hr = await _hxc.get(f"https://api.mercadolibre.com/items/{_first_id}", headers={"Accept":"application/json"})
                    _item_tests[f"{_first_id}_public"] = {"status_code": _hr.status_code, "body": str(_hr.text)[:200]}
            except Exception as _hxe:
                _item_tests["public_error"] = str(_hxe)[:100]
            results["item_resolution_tests"] = _item_tests
        # 6. Try /sites/MLM/search?user_product_id to find listings by MLMU
        try:
            r6 = await client.get("/sites/MLM/search", params={"user_product_id": mlmu_id, "limit": 3})
            _r6res = r6.get("results") or []
            results["search_user_product_id"] = {"count": len(_r6res), "ids": [x.get("id") for x in _r6res], "first_title": _r6res[0].get("title","") if _r6res else ""}
        except Exception as e:
            results["search_user_product_id"] = {"error": str(e)[:200]}
        # 7. Try /products/{mlmu_id} with explicit Bearer auth
        try:
            import httpx as _hx7
            _tok7 = getattr(client, 'access_token', '')
            async with _hx7.AsyncClient(timeout=8.0) as _hxc7:
                _hr7 = await _hxc7.get(f"https://api.mercadolibre.com/products/{mlmu_id}", headers={"Accept":"application/json", "Authorization": f"Bearer {_tok7}"})
                results["products_direct_auth"] = {"status": _hr7.status_code, "keys": list(_hr7.json().keys())[:10] if _hr7.status_code == 200 else [], "name": _hr7.json().get("name","") if _hr7.status_code == 200 else "", "error": str(_hr7.text)[:150] if _hr7.status_code != 200 else ""}
        except Exception as e:
            results["products_direct_auth"] = {"error": str(e)[:200]}
        # 8. Scrape ML product page HTML for OG title
        try:
            import httpx as _hx8, re as _re8
            _page_url = f"https://www.mercadolibre.com.mx/p/{mlmu_id}"
            async with _hx8.AsyncClient(timeout=10.0, follow_redirects=True) as _hxc8:
                _hr8 = await _hxc8.get(_page_url, headers={"Accept": "text/html", "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36"})
                _og = _re8.search(r'<meta property="og:title" content="([^"]+)"', _hr8.text or "")
                _h1 = _re8.search(r'<h1[^>]*>([^<]+)</h1>', _hr8.text or "")
                results["page_scrape"] = {"status": _hr8.status_code, "og_title": _og.group(1) if _og else "", "h1": _h1.group(1).strip() if _h1 else "", "url": _page_url}
        except Exception as e:
            results["page_scrape"] = {"error": str(e)[:200]}
    finally:
        await client.close()
    return JSONResponse(results)


@app.get("/api/diag/bulk-raw-fields")
async def diag_bulk_raw_fields(token: str = "", sku: str = ""):
    """Diagnóstico: muestra los campos RAW del bulk BM antes de slimming.
    Permite identificar qué campo contiene el desglose por warehouse (MTY/CDMX).
    """
    if token != _DIAG_TOKEN:
        return JSONResponse({"error": "token inválido"}, status_code=403)
    if _bm_bulk_raw_sample is None:
        return JSONResponse({"status": "no_sample", "msg": "Esperando primer bulk fetch (prewarm)"})
    result = {"raw_fields": _bm_bulk_raw_sample}
    # Si se pasa un SKU, buscar en el bulk cache actual el row crudo (ya slimmed)
    if sku:
        _sk = sku.upper().strip()
        gr_rows = _bm_bulk_gr_cache[1] if _bm_bulk_gr_cache else []
        all_rows = _bm_bulk_all_cache[1] if _bm_bulk_all_cache else []
        _found_gr  = [r for r in gr_rows  if (r.get("SKU") or "").upper() == _sk or _extract_base_sku((r.get("SKU") or "").upper()) == _sk]
        _found_all = [r for r in all_rows if (r.get("SKU") or "").upper() == _sk or _extract_base_sku((r.get("SKU") or "").upper()) == _sk]
        result["sku_in_slimmed_gr"]  = _found_gr[:5]
        result["sku_in_slimmed_all"] = _found_all[:5]
    return JSONResponse(result)


